-- Poems batch 127
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('007a47bf-84dc-4c09-89e0-4cc5d022ae72','龍學尚書新安侯羅公輓詞二首  其二','范成大','宋','宋诗','song-poetry','','[]','一昨更調瑟，如聞欲賜環。',48,'全唐诗/poet.song.137000.json','["一昨更調瑟，如聞欲賜環。", "途殫泣西狩，望絕起東山。", "華屋林霏慘，新阡草露班。", "春風埋玉淚，重爲庾公潸。"]'),
('a296c373-a26f-470c-ad2c-b16a15704bef','龍學侍郎清河侯張公輓詞二首  其一','范成大','宋','宋诗','song-poetry','','[]','白水名多士，清河最有聲。',48,'全唐诗/poet.song.137000.json','["白水名多士，清河最有聲。", "人危孔北海，帝識柳宜城。", "蜀險談間固，蠻訌檄到平。", "凌煙何處在，風雨上銘旌。"]'),
('a4f08242-d9bf-4275-adab-474fb420bb2a','龍學侍郎清河侯張公輓詞二首  其二','范成大','宋','宋诗','song-poetry','','[]','太息逢萋錦，平生付薄冰。',48,'全唐诗/poet.song.137000.json','["太息逢萋錦，平生付薄冰。", "滄溟淙赤舌，白日照青蠅。", "嶽麓身猶健，星維馭已升。", "天如遺一老，人亦望三登。"]'),
('fef3db40-3904-4e41-8572-5314342902b7','新安侯夫人俞氏輓詞','范成大','宋','宋诗','song-poetry','','[]','蚤兆于凰卜，來嬪駟馬車。',48,'全唐诗/poet.song.137000.json','["蚤兆于凰卜，來嬪駟馬車。", "夫君宜竹帛，子舍各詩書。", "露薤丹旌舉，風楊組帳虛。", "空餘彤管訓，他日照鄉閭。"]'),
('749037bb-0d90-424f-a77a-7635c8f2bde2','次韻甄雲卿晚登浮丘亭','范成大','宋','宋诗','song-poetry','','[]','賓筵舊壓三千客，燕榭新高十二城。',64,'全唐诗/poet.song.137000.json','["賓筵舊壓三千客，燕榭新高十二城。", "潑墨雲頭連樹暗，垂絲雨脚過溪生。", "葛巾羽扇吾身健，雪椀冰甌子句清。", "從此相從須痛飲，故應此事勝公榮。"]'),
('751d72c1-848a-4eda-aad5-89dd6f768e17','古風上知府秘書二首  其一','范成大','宋','宋诗','song-poetry','','[]','神仙絕世立，功行聞清都。',96,'全唐诗/poet.song.137000.json','["神仙絕世立，功行聞清都。", "玉符賜長生，籋雲遊紫虛。", "雞犬爾何知，偶舐藥鼎餘。", "身輕亦仙去，罡風與之俱。", "俯視舊籬落，眇莽如積蘇。", "非無鳳與麟，終然侶蟲魚。", "微物豈有命，政爾謝泥塗。", "時哉適丁是，邂逅真良圖。"]'),
('7ddbe84e-8c3b-456a-aad6-753a9cbacbae','古風上知府秘書二首  其二','范成大','宋','宋诗','song-poetry','','[]','大鵬上扶搖，南溟聒天沸。',96,'全唐诗/poet.song.137000.json','["大鵬上扶搖，南溟聒天沸。", "斥鷃有羽翼，意滿蓬蒿裏。", "不如附驥蠅，掣電抹荆薊。", "誰云極么麽，俛仰且萬里。", "向來庭戶間，決起不踰咫。", "飄颻托方便，意氣乃如此。", "物生未可料，旦暮倘逢世。", "君看功名場，得失一交臂。"]'),
('31a9e5f3-de1a-4692-80ac-d4923983e584','拄笏亭晚望','范成大','宋','宋诗','song-poetry','','[]','林泉隨處有清凉，山繞闌干客自忙。',32,'全唐诗/poet.song.137000.json','["林泉隨處有清凉，山繞闌干客自忙。", "溪雨不飛虹尚飲，亂蟬高柳滿斜陽。"]'),
('715651c2-36cd-4c3b-aaed-989bde199beb','乳灘','范成大','宋','宋诗','song-poetry','','[]','清溪可怖亦可喜，造化於人真虐戲。',64,'全唐诗/poet.song.137000.json','["清溪可怖亦可喜，造化於人真虐戲。", "轟雷捲雪鬢成絲，一擲平生來此試。", "險絕無雙是乳灘，舟如滾石下高山。", "畫樓正倚黄昏雨，豈識江間行路難。"]'),
('2dd20abe-b684-4599-8e7e-79a1e9a79597','浮丘亭','范成大','宋','宋诗','song-poetry','','[]','黟山鬰律神仙宅，三十六峰雷雨隔。',128,'全唐诗/poet.song.137000.json','["黟山鬰律神仙宅，三十六峰雷雨隔。", "碧城欄檻偃雙旌，笑挹浮丘爲坐客。", "巖扉無鎖晝長開，紫雲明滅多樓臺。", "雲中仙馭參差是，肯爲使君乘興來。", "西崑巉絕不可至，東望蓬萊愁弱水。", "誰知芳草徧天涯，玉京只在珠簾底。", "他年麟閣上清空，却訪舊遊尋赤松。", "我亦從公負丹鼎，來斸砂牀汲湯井。"]'),
('0789511e-d0d8-4060-b33a-d6f648f02cf1','風月堂','范成大','宋','宋诗','song-poetry','','[]','天風無邊吹海月，景入溪山更奇絕。',64,'全唐诗/poet.song.137000.json','["天風無邊吹海月，景入溪山更奇絕。", "太守文章別乘賢，平生付與金杯滑。", "門闌我亦似彭宣，想聞橫玉叫蒼煙。", "讀碑索句仍投轄，誰是揚州控鶴仙。"]'),
('311fc23e-1908-4218-8862-4b867a40c935','寄贈泉石使李元直入覲','范成大','宋','宋诗','song-poetry','','[]','漢圖昔中天，百六啟真主。',156,'全唐诗/poet.song.137000.json','["漢圖昔中天，百六啟真主。", "當時鄧高密，徒步赴光武。", "諸公上雲臺，一葉渺湘浦。", "聲名三十年，玉氣貫晴宇。", "向來宣室問，天語道舊故。", "不圖太平日，復見起兵簿。", "雙旌奠侯服，三節臨江滸。", "垂欲大用公，少駐議圜府。", "人言山澤官，底用廟廊具。", "果聞一乘傳，已踵追鋒去。", "翔鳳覽輝來，風采照鴛鷺。", "平生經濟心，十不一二吐。", "茲行公勿遜，安國如鼎呂。"]'),
('ce6afc4e-aff7-40e0-a7c0-055301a7cdb9','休寧','范成大','宋','宋诗','song-poetry','','[]','南街豪郡城，東圃壓州宅。',72,'全唐诗/poet.song.137000.json','["南街豪郡城，東圃壓州宅。", "誰云沸鑊地，氣象不偪仄。", "林園富瓜筍，堂密美杉柏。", "山醪極可人，溪女能醉客。", "吳子邑中彥，毫端萬人敵。", "傳杯相勞苦，不覺東方白。"]'),
('6c3c1de0-4673-400b-81a3-c8c1339f00ee','祁門','范成大','宋','宋诗','song-poetry','','[]','石梁平波心，金剎駕巖腹。',72,'全唐诗/poet.song.137000.json','["石梁平波心，金剎駕巖腹。", "溪藤卷霜繒，山骨琢紫玉。", "東堂有嘉名，窈窕窗紗綠。", "落花掃無迹，蕉葉森似束。", "主人甚愛客，挽袖語陸續。", "衝雨出門去，役役媿童僕。"]'),
('fd04b698-7b38-47bb-be7f-3f4ce3aaa4b8','靈山口','范成大','宋','宋诗','song-poetry','','[]','陵高類登天，斗下劇窺井。',72,'全唐诗/poet.song.137000.json','["陵高類登天，斗下劇窺井。", "衡從十里近，底用許多嶺。", "秋雨釀春泥，掀淖力扛鼎。", "僕夫負隅哭，邂逅憂性命。", "舊嗤子猷狂，夜半槳歸艇。", "方知興盡處，頃步令人癭。"]'),
('f6b6e480-49a4-4d5a-bff7-2d130d9a62c8','浮梁','范成大','宋','宋诗','song-poetry','','[]','大灘石如林，小灘石如枿。',72,'全唐诗/poet.song.137000.json','["大灘石如林，小灘石如枿。", "微生拋擲過，兩槳砉將割。", "一灘復一灘，食頃經七八。", "崎嶇幸脫免，已足凋鬢髮。", "我家五湖船，鏡面貼天闊。", "行迷勿浪遠，歸歟泛花月。"]'),
('d89d55e6-bda1-4e89-a84e-23615324e967','鄱陽湖','范成大','宋','宋诗','song-poetry','','[]','淒悲鴻雁來，泱漭魚龍蟄。',72,'全唐诗/poet.song.137000.json','["淒悲鴻雁來，泱漭魚龍蟄。", "雷霆一鼓罷，星斗萬里濕。", "波翻漁火碎，月落村舂急。", "折葦已紛披，衰楊尚僵立。", "長年畏簡書，今夕念簑笠。", "江湖有佳思，逆旅百憂集。"]'),
('f994e624-f401-410e-a7cc-29399265fa27','回黄坦','范成大','宋','宋诗','song-poetry','','[]','渥丹楓凋零，濃黛柏幽獨。',72,'全唐诗/poet.song.137000.json','["渥丹楓凋零，濃黛柏幽獨。", "畦稻晚已黄，陂草秋重綠。", "平遠一橫看，浩蕩供醉目。", "落帆金碧溪，嘶馬錦繡谷。", "世界真莊嚴，造物極不俗。", "向非來遠遊，那有此奇矚。"]'),
('e4541f87-e465-4724-9b8a-2348ee0e8d2f','桑嶺','范成大','宋','宋诗','song-poetry','','[]','回腸山百盤，揮手天一握。',72,'全唐诗/poet.song.137000.json','["回腸山百盤，揮手天一握。", "俯驚危棧穿，仰詫飛石落。", "挽輿如挽舟，絕叫斷雙筰。", "怪蔓纏枯槎，瘠草被幽壑。", "此豈車馬路，誰云强刊鑿。", "人言遠遊好，呼來試著脚。"]'),
('92f2d4db-6b70-4ef7-8777-0ddc0f4598c8','天都峰','范成大','宋','宋诗','song-poetry','','[]','維帝有下都，作鎮此南國。',72,'全唐诗/poet.song.137000.json','["維帝有下都，作鎮此南國。", "孤撐紫玉樓，橫絕太霄碧。", "晶熒砂竇紅，夭矯泉紳白。", "晴雲無盡藏，竟日裊幽石。", "諸峰三十五，離立侍傍側。", "會稽眇小哉，請議職方籍。"]'),
('4336006f-e947-4289-a54a-aa1f0847cbe1','溫泉','范成大','宋','宋诗','song-poetry','','[]','砂牀毓靈源，石液漱和氣。',72,'全唐诗/poet.song.137000.json','["砂牀毓靈源，石液漱和氣。", "鬰攸甑常蒸，觱沸鼎百沸。", "人生本無垢，安用滌腸胃。", "一瓢灧清肥，回首謝羅罻。", "山深人跡罕，政以遠爲貴。", "君看華清池，談者至今諱。"]'),
('4327f62c-72a8-4e17-a625-70f80d19527e','伏聞知府祕書欲取小杜桐廬詩語以見花名堂成大記東坡送鄭戶曹詩云蕩蕩清河壖黄樓我所開遲君爲坐客新詩出瓊瑰樓成君已去人事固多乖此段大類今日成大行且受代計梅開堂成歸舟已下南浦欲爲坐客不可得懷不能已請先爲公賦之','范成大','宋','宋诗','song-poetry','','[]','使君來暖東堂席，又見堂前花信息。',64,'全唐诗/poet.song.137000.json','["使君來暖東堂席，又見堂前花信息。", "小白猶封竹外枝，微黄已點眉間色。", "山城十月如春臺，聞有細書天上來。", "說與橫斜應早計，不須更待雪花催。"]'),
('ae923b1d-b004-4596-94e2-3d5cdd664e5c','知府祕書遣帳下持新詩追路贈行輒次韻寄上','范成大','宋','宋诗','song-poetry','','[]','冷雲去仍來，凍雨落還歇。',84,'全唐诗/poet.song.137000.json','["冷雲去仍來，凍雨落還歇。", "平明一篙漲，珍重送船發。", "端成南溪泛，寧復東堂謁。", "何時公三日，請澤看山笏。", "恩勤一未報，終古銘肌骨。", "幡幡跡雖遠，耿耿心不沒。", "門闌如水波，永印此孤月。"]'),
('885305d2-447e-4b16-a080-599564726fed','寄上鄙句之明日舟次梅口南枝已有春意復次知府祕書贈行高韻','范成大','宋','宋诗','song-poetry','','[]','晏溫解船去，暮夜檥船歇。',84,'全唐诗/poet.song.137000.json','["晏溫解船去，暮夜檥船歇。", "橫斜隘梅村，玉蓓粲將發。", "城中三輔豪，指日承明謁。", "高懷妙康濟，未試君前笏。", "周南又小春，微溫入花骨。", "我瞻浮丘亭，山高璿柄沒。", "飛鳥正飄蕩，空繞南枝月。"]'),
('23bc2da6-ee0d-476d-8d0d-a91b1cf03293','晞真閣留別方道士賓實','范成大','宋','宋诗','song-poetry','','[]','東山西山雙袖舞，中有清宮蟠萬礎。',128,'全唐诗/poet.song.137000.json','["東山西山雙袖舞，中有清宮蟠萬礎。", "雲橫朱閣碧梧寒，風掃石壇蒼檜古。", "道人賓實其姓方，來從何許今幾霜。", "誅蒿仆蓬殿突兀，玉華紫氣騰真香。", "胸奇腹憤無人識，我獨相從似疇昔。", "時時苦語見鍼砭，邂逅天涯得三益。", "明朝歸客上歸艎，重到晞真計渺茫。", "只有雙魚相問訊，歙江之水通吳江。"]'),
('2cea1e31-5d51-43dd-ae38-f0dbd3d2f2a6','程助教遠餞求詩','范成大','宋','宋诗','song-poetry','','[]','殘山剩水带離亭，送客煩君遠作程。',32,'全唐诗/poet.song.137000.json','["殘山剩水带離亭，送客煩君遠作程。", "直欲明年擊吳榜，白沙翠竹是柴荆。"]'),
('3dce433e-d19c-4190-9773-bb02d7c20a2e','次伯安推官贈別韻','范成大','宋','宋诗','song-poetry','','[]','交情彌歲竟匆匆，短棹歸尋一畝宮。',64,'全唐诗/poet.song.137000.json','["交情彌歲竟匆匆，短棹歸尋一畝宮。", "塞責文書容我懶，及時盃酒頼君同。", "披雲峰頂城頭月，攬秀堂前扇裏風。", "千里音書慰離索，莫言天遠費鱗鴻。"]'),
('c561cd32-276d-4d51-b95d-1e6aad627c89','次景琳錄事贈別韻','范成大','宋','宋诗','song-poetry','','[]','放船鳴櫓便秦吳，送別空煩長者車。',64,'全唐诗/poet.song.137000.json','["放船鳴櫓便秦吳，送別空煩長者車。", "宿霧鎖山常羃羃，斷雲將雨忽疎疎。", "高城五嶺花深處，短棹三江木落初。", "頼得溪流通尺素，蒲根仍有一雙魚。"]'),
('3f1704de-e280-4991-98bd-550980e9f8cf','次黄必先主簿同年贈別韻二首  其一','范成大','宋','宋诗','song-poetry','','[]','當年仗外揖高標，繡䪌蘆鞭寶馬驕。',64,'全唐诗/poet.song.137000.json','["當年仗外揖高標，繡䪌蘆鞭寶馬驕。", "瓊苑天香飄合坐，碧城山色照同僚。", "思歸意決吾張翰，贈別情深子繞朝。", "蟹籪魚梁從此去，他年書札墮煙霄。"]'),
('a238dc8c-9e31-459f-a569-9bdc41bbcd77','次黄必先主簿同年贈別韻二首  其二','范成大','宋','宋诗','song-poetry','','[]','山郭官閒得爛遊，彌年還往話綢繆。',64,'全唐诗/poet.song.137000.json','["山郭官閒得爛遊，彌年還往話綢繆。", "西園剝栗催奴課，東院尋梅勸客留。", "筆下修鋒千首富，談間和氣兩眉浮。", "別來悵望何時見，謾上重城謾上樓。"]'),
('95f77877-3624-4e0b-bf33-ad99bb527d0f','次胡經仲知丞贈別韻','范成大','宋','宋诗','song-poetry','','[]','先生有道抗浮雲，拄頰看山意最真。',64,'全唐诗/poet.song.137000.json','["先生有道抗浮雲，拄頰看山意最真。", "霜鬢不堪痟首疾，翠蛾常作捧心顰。", "官如斯立藍田小，家似淵明栗里貧。", "俯仰別來蓂莢換，衹今誰與話情親。"]'),
('7258df26-7ce7-4ff9-a7b6-91da47752057','次諸葛伯山贍軍贈別韻','范成大','宋','宋诗','song-poetry','','[]','歙維羣山囿，漫仕富英傑。',144,'全唐诗/poet.song.137000.json','["歙維羣山囿，漫仕富英傑。", "清標照人寒，玉筍森積雪。", "嗟余獨委瑣，無用等木屑。", "又如道傍李，味苦不堪折。", "歸舟坐成泛，去馬亦已刷。", "三年風波險，盡付一笑閲。", "惟君同懷抱，各坐天機拙。", "我家鴟夷子，竹帛照吳越。", "雲仍無肖似，頫首媿前哲。", "若家卧龍公，事業管蕭埒。", "期君踵祖武，勿惜兒女別。", "言狂舉白浮，醉倒霜松折。"]'),
('287353c0-10fe-4565-bf14-e179f7f04496','次韻樂先生除夜三絕  其一','范成大','宋','宋诗','song-poetry','','[]','團蒲曲几坐成癡，北看南觀恍是非。',32,'全唐诗/poet.song.137000.json','["團蒲曲几坐成癡，北看南觀恍是非。", "道眼已空詩眼在，梅花欲動雪花稀。"]'),
('3f5b4fc0-3fd5-4d82-9057-6035039b33b4','次韻樂先生除夜三絕  其二','范成大','宋','宋诗','song-poetry','','[]','天邊客裏五迎冬，爭信還鄉似寓公。',32,'全唐诗/poet.song.137000.json','["天邊客裏五迎冬，爭信還鄉似寓公。", "人事都非城郭是，獨憐雞犬識新豐。"]'),
('070c3218-9e88-40a4-9c7b-f39756970edf','次韻樂先生除夜三絕  其三','范成大','宋','宋诗','song-poetry','','[]','牀頭曆日鬢絲絲，懶倦慵吟守歲詩。',32,'全唐诗/poet.song.137000.json','["牀頭曆日鬢絲絲，懶倦慵吟守歲詩。", "宜入新年須吉利，明朝把筆寫門楣。"]'),
('d3e2e12d-3f39-4a63-9baa-9c6427ee0c16','次韻唐幼度客中幼度相別數年復會於錢塘湖上','范成大','宋','宋诗','song-poetry','','["\u897f\u6e56"]','西湖冰泮綠生鱗，料峭東風欲中人。',64,'全唐诗/poet.song.137000.json','["西湖冰泮綠生鱗，料峭東風欲中人。", "花片不禁寒食雨，鬢絲猶那湧金春。", "江山契闊詩情在，京洛追隨客夢新。", "喚取歌聲不愁思，爲君吹水引盃頻。"]'),
('dd89d467-7e8c-479e-8fdf-9a1735b8ffba','客中呈幼度','范成大','宋','宋诗','song-poetry','','[]','手板頭銜意已慵，墨池書枕興無窮。',64,'全唐诗/poet.song.137000.json','["手板頭銜意已慵，墨池書枕興無窮。", "釀泥深巷五更雨，吹酒小樓三面風。", "草色有無春最好，客心去住水長東。", "今朝合有家書到，昨夜燈花綴玉蟲。"]'),
('00551326-32c1-4a33-8cd3-dd18c115383e','奠唐少梁晉仲兄弟墓下','范成大','宋','宋诗','song-poetry','','[]','當年連璧氣如蜺，人許躋攀九列齊。',64,'全唐诗/poet.song.137000.json','["當年連璧氣如蜺，人許躋攀九列齊。", "黄壤一時埋玉樹，青雲何處用丹梯。", "生平書札頻雙鯉，歲晚交情但隻雞。", "眼底傷心難制淚，寧論宿草已萋萋。"]'),
('99d461bc-08b8-4a75-9d6b-e8388cd015b3','鎮東行送湯丞相帥紹興','范成大','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','吳波鱗鱗越山紫，鎮東旌旆東風裏。',128,'全唐诗/poet.song.137000.json','["吳波鱗鱗越山紫，鎮東旌旆東風裏。", "前驅傳道相君來，一夜鑑湖春漲起。", "鑑湖如鑑涵空明，相君出處如湖清。", "十年勳業泰山重，五鼎富貴浮雲輕。", "人言公如裴相國，綠野堂高貯風月。", "我獨願公如子牟，身在江湖心魏闕。", "浯溪有石高嵯峨，公方東征如此何。", "丁寧湖水莫斷渡，早晚歸來絕江去。"]'),
('5f1940f4-5126-4c57-a9a1-6f1553cc6185','水月菴謁現老不值','范成大','宋','宋诗','song-poetry','','[]','有客叩巖扃，無人管送迎。',24,'全唐诗/poet.song.137000.json','["有客叩巖扃，無人管送迎。", "片雲閒出岫，水月自空明。"]'),
('3440fa70-6b00-4f80-8b2e-cbdd33acab24','次韻邊公辨','范成大','宋','宋诗','song-poetry','','[]','錯落參旗罥竹梢，柴荆臨水閉蓬蒿。',64,'全唐诗/poet.song.137000.json','["錯落參旗罥竹梢，柴荆臨水閉蓬蒿。", "春風吹曉玉蟾墮，穠露洗空銀漢高。", "雙鵲繞枝應也倦，一蛩吟壁已能豪。", "新秋只合添詩興，莫學潘郎歎二毛。"]'),
('8bf3ff33-670e-47cc-b09d-a0a6e59181af','中秋無月復次韻','范成大','宋','宋诗','song-poetry','','[]','屋山從捲杜陵茅，門徑慵芟仲蔚蒿。',64,'全唐诗/poet.song.137000.json','["屋山從捲杜陵茅，門徑慵芟仲蔚蒿。", "澹澹白虹風暈壯，紛紛蒼狗雨雲高。", "凌空累筯仙無術，半夜撞鐘句謾豪。", "枵腹題詩將底用，真成兔角與龜毛。"]'),
('fc5b67f7-122f-4b94-ba58-df08aea4ad7a','公辨用前韻見贈復次韻','范成大','宋','宋诗','song-poetry','','[]','先生筆力玉山鼇，氣壓明堂一柱蒿。',64,'全唐诗/poet.song.137000.json','["先生筆力玉山鼇，氣壓明堂一柱蒿。", "雪椀滌毫詞絕妙，朱絃縮瑟調彌高。", "心兵不起無三粲，坐客常多似四豪。", "喜有過從南北巷，蘇蘭薪桂瀹溪毛。"]'),
('4ef8a839-e05e-4903-b87b-c4ab92f49dd7','公辨再贈復次韻','范成大','宋','宋诗','song-poetry','','[]','書生活計極蕭騷，爝火微明似束蒿。',64,'全唐诗/poet.song.137000.json','["書生活計極蕭騷，爝火微明似束蒿。", "犬子地寒徒壁立，元龍身懶謾樓高。", "筆端未辦誇三絕，酒裏猶能掃二豪。", "又向詩壇蘄借一，强磨鉛鈍齒吹毛。"]'),
('1568ad2c-fb1a-4c85-a397-309d2afdec5d','送施元光赴江西幕府','范成大','宋','宋诗','song-poetry','','[]','鎮南旌旆照江臯，入幕如今客最高。',64,'全唐诗/poet.song.137000.json','["鎮南旌旆照江臯，入幕如今客最高。", "月暗秋城稀擊柝，雲飛朝棟賸揮毫。", "長亭酒盡歌三疊，半夜溪深雨一篙。", "莫戀陽關更西路，九關歸路踏金鼇。"]'),
('85c45c93-d6b1-4a0a-b400-24d7964a087b','次韻林子章阻淺留滯','范成大','宋','宋诗','song-poetry','','[]','客行端似未歸雲，指點璿杓幾易辰。',64,'全唐诗/poet.song.137000.json','["客行端似未歸雲，指點璿杓幾易辰。", "喜有風花黄作暈，似聞溪漲綠生鱗。", "我從走俗言無味，君已鳴文筆有神。", "繡段炳然空辱贈，急繙緹襲掃蛛塵。"]'),
('81aba9cf-ffbc-4824-bc97-345db1efbab5','次韻馬少伊木犀  其一','范成大','宋','宋诗','song-poetry','','[]','月窟飛來露已涼，斷無塵格惹蜂黄。',32,'全唐诗/poet.song.137000.json','["月窟飛來露已涼，斷無塵格惹蜂黄。", "纖纖綠裹排金粟，何處能容九里香。"]'),
('52892e87-0c48-44ce-9ba2-e50ac746811c','次韻馬少伊木犀  其二','范成大','宋','宋诗','song-poetry','','[]','水尾山腰樹影蒼，一天風露不供香。',32,'全唐诗/poet.song.137000.json','["水尾山腰樹影蒼，一天風露不供香。", "誰家鏡裏能消得，付與詩人古錦囊。"]'),
('ba2df1b7-823c-4304-85e9-572a7525f634','次韻馬少伊木犀  其三','范成大','宋','宋诗','song-poetry','','[]','密密嬌黄侍翠輿，避風遮日小扶疎。',32,'全唐诗/poet.song.137000.json','["密密嬌黄侍翠輿，避風遮日小扶疎。", "畫闌想見懸秋晚，無限宮香總不如。"]'),
('a7c79b96-a211-4d4d-b1dc-eb405140ad03','林夫人輓詞','范成大','宋','宋诗','song-poetry','','[]','翰墨門闌正巋然，故應婉娩亦儒先。',64,'全唐诗/poet.song.137000.json','["翰墨門闌正巋然，故應婉娩亦儒先。", "與聞古學三千禮，能誦家書四百篇。", "卜協媯姜占永世，夢呼辰巳讖凋年。", "班姬合有遺文在，後日從容訪孟堅。"]'),
('57c70759-d85a-48d7-83d9-c94418138e6c','李仲鎮懶窩','范成大','宋','宋诗','song-poetry','','["\u8861\u5c71"]','求名當著鞭，訪道亦重趼。',96,'全唐诗/poet.song.137000.json','["求名當著鞭，訪道亦重趼。", "二邊俱不住，三昧不如懶。", "向來南嶽師，自謂極蕭散。", "收涕且無緒，客至那可款。", "爭如懶窩高，門外轍常滿。", "殊不妨嘯歌，秉燭苦夜短。", "天寒雪欲花，屋角黄雲晚。", "徑須煩二妙，對洗玻瓈盞。"]'),
('e4c48ebc-9e7f-4bc7-94da-e41f44ca1d25','次韻陳季陵寺丞求歙石眉子硯','范成大','宋','宋诗','song-poetry','','[]','金星熒熒眉子綠，婺源琢石如琢玉。',96,'全唐诗/poet.song.137000.json','["金星熒熒眉子綠，婺源琢石如琢玉。", "寶玩何曾捄枵腹，但愛文君遠山蹙。", "文人筆陣森五兵，書品入妙仍詩名。", "我有陂陀天海樣，與公文字俱金聲。", "梟盧一擲不須呼，況敢定價論車渠。", "只煩將到粧臺下，試比何如京兆畫。"]'),
('de54ef0c-ffc2-405f-a833-5db640a856d3','次韻季陵貢院新晴','范成大','宋','宋诗','song-poetry','','[]','鎖闈令嚴深復深，五星簾幕晴若陰。',80,'全唐诗/poet.song.137000.json','["鎖闈令嚴深復深，五星簾幕晴若陰。", "澹雲微月謾清夜，短檠政自關人心。", "看燈作暈生睡色，江南行處夢不隔。", "覺來快讀新晴篇，怳然寘我鶑花前。", "徑欲觴公後堂酒，倘煩春衫小垂手。"]'),
('aed6d995-e5cd-4e7e-b50d-d5aa845ebec7','次韻周子充正字館中緋碧兩桃花','范成大','宋','宋诗','song-poetry','','[]','碧城香霧赤城霞，深出劉郎未見花。',32,'全唐诗/poet.song.137000.json','["碧城香霧赤城霞，深出劉郎未見花。", "憑仗天風扶絳節，爲招萼綠過羊家。"]'),
('94b56b91-fcb3-47f2-9ae8-97edc9aa3e66','明日子充折贈次韻謝之','范成大','宋','宋诗','song-poetry','','[]','海上三山冠綵霞，六時高會雨天花。',32,'全唐诗/poet.song.137000.json','["海上三山冠綵霞，六時高會雨天花。", "步虛聲裏隨風下，吹落尋常百姓家。"]'),
('c9f9f5c9-0c48-4705-886b-9edf8e3cfb43','明日大雨復折贈再次韻','范成大','宋','宋诗','song-poetry','','[]','一天雲葉翳朝霞，風卷泥沾不惜花。',32,'全唐诗/poet.song.137000.json','["一天雲葉翳朝霞，風卷泥沾不惜花。", "羣玉山高春好在，人間煙雨暗千家。"]'),
('e1909376-685a-430a-be46-930847fb6a11','張恭甫正字折贈館中碧桃因次子充韻','范成大','宋','宋诗','song-poetry','','[]','滿枝晴雪照青霞，舊識桃源暈碧花。',32,'全唐诗/poet.song.137000.json','["滿枝晴雪照青霞，舊識桃源暈碧花。", "俯仰京塵隔年夢，東風猶認故人家。"]'),
('50fb9ff0-4b46-4e1c-b378-1e96c3676cf1','雨中報謁呈劉韶美侍郎','范成大','宋','宋诗','song-poetry','','[]','花落滿城雨，雨餘雲重陰。',72,'全唐诗/poet.song.137000.json','["花落滿城雨，雨餘雲重陰。", "驅車有底急，巷泥三尺深。", "平生黄篾舫，漁榔有清音。", "斗升得苦相，懷刺衝愁霖。", "歸來掩關卧，一枕直兼金。", "作詩詫比鄰，幸勿譏褊心。"]'),
('fad17a34-3fc6-4845-af5e-05a648d42f04','雨中集水月','范成大','宋','宋诗','song-poetry','','[]','獻之今年不堪暑，天亦相憐病良苦。',96,'全唐诗/poet.song.137000.json','["獻之今年不堪暑，天亦相憐病良苦。", "明便中秋法合凉，夜半行雲曉行雨。", "蘄州竹簟清如冰，饑蚊倔强猶鳴聲。", "下牀蚤喜衣裳健，出門更覺山川明。", "曳屐扶藜尋水月，不惜垂垂巾角折。", "竹間松下已淒然，却要芳樽生暖熱。"]'),
('3420902d-7ec3-4f0e-8aae-09bf48fa31fc','送洪景盧內翰使虜二首  其一','范成大','宋','宋诗','song-poetry','','[]','金章玉色照離亭，戰伐和親決此行。',64,'全唐诗/poet.song.137000.json','["金章玉色照離亭，戰伐和親決此行。", "國有威靈雙節重，家傳忠義一身輕。", "平生海內文場伯，今日胸中武庫兵。", "萬里往來公有相，淮濆陰德貫神明。"]'),
('5c996900-a2c4-482a-bec8-0db83659a305','送洪景盧內翰使虜二首  其二','范成大','宋','宋诗','song-poetry','','[]','檄到中原殺氣銷，穹廬那敢說天驕。',64,'全唐诗/poet.song.137000.json','["檄到中原殺氣銷，穹廬那敢說天驕。", "今年蕃始來和漢，即日燕當遠徙遼。", "北土未乾遺老淚，西陵應望孝孫朝。", "著鞭往矣功名會，麟閣丹青上九霄。"]'),
('e11aa4ce-91ae-4f5f-bbb6-5d395ba52e49','次韻嚴子文旅中見贈','范成大','宋','宋诗','song-poetry','','[]','杯中疇昔共江天，傾座新詩報警聯。',64,'全唐诗/poet.song.137000.json','["杯中疇昔共江天，傾座新詩報警聯。", "海浦寸心空共月，京華雙鬢各凋年。", "交情敢說同方友，句法甘從弟子員。", "有意數從文字飲，何須爭著祖生鞭。"]'),
('e5df254e-e0f4-4c9c-8508-6dbeaf5d2e84','次韻子文客舍小樓','范成大','宋','宋诗','song-poetry','','["\u897f\u6e56"]','客裏仍携一束書，閉門虹氣自凌虛。',64,'全唐诗/poet.song.137000.json','["客裏仍携一束書，閉門虹氣自凌虛。", "未聞光範延珠履，誰向甘泉從玉車。", "散盡生涯千答布，收將文價百車渠。", "淹留且結西湖夏，同到秋風賦遂初。"]'),
('dd53e233-a572-440f-93b0-d59294c4da5a','次韻劉韶美大風雨壞門屋','范成大','宋','宋诗','song-poetry','','[]','雲煙揮翰墨池翻，緗縹如山晝掩關。',32,'全唐诗/poet.song.137000.json','["雲煙揮翰墨池翻，緗縹如山晝掩關。", "已許六丁收散落，只愁雷電費牆藩。"]'),
('55567fcd-d58b-424e-8a9d-562f00c60d2b','洪景盧內翰使還入境以詩迓之','范成大','宋','宋诗','song-poetry','','[]','玉帛干戈汹並馳，孤臣叱馭觸危機。',64,'全唐诗/poet.song.137000.json','["玉帛干戈汹並馳，孤臣叱馭觸危機。", "關山無極申舟去，天地有情蘇武歸。", "漢月凌秋隨使節，胡塵捲暑避征衣。", "國人渴望公顔色，爲報褰帷入帝畿。"]'),
('c358993e-8a9c-4244-adf7-0177ef87c546','寄題向撫州采菊亭','范成大','宋','宋诗','song-poetry','','[]','一葉起秋色，衆綠凋歲華。',96,'全唐诗/poet.song.137000.json','["一葉起秋色，衆綠凋歲華。", "耿耿霜露側，餘此黄金葩。", "西風滿天地，孤芳照塵沙。", "殷勤開小築，花氣日夕嘉。", "落英楚纍手，東籬陶令家。", "兩窮偶寓意，豈必真愛花。", "不如亭中人，一笑了天涯。", "采采勿虛度，門前欲高牙。"]'),
('b16cac67-abad-4200-85a2-4e9baf42197e','古風二首上湯丞相  其一','范成大','宋','宋诗','song-poetry','','[]','抱瑟游孔門，豈識宮與商。',84,'全唐诗/poet.song.137000.json','["抱瑟游孔門，豈識宮與商。", "古曲一再行，乃雜巴人倡。", "知音顧之笑，解絃爲更張。", "歸來掩關卧，冰炭交愁腸。", "平生桑濮手，未省歌虞唐。", "明發理朱絲，復登君子堂。", "遺音入三歎，山高水湯湯。"]'),
('7c75c524-fcbc-470d-85b9-1e0b98d6a320','古風二首上湯丞相  其二','范成大','宋','宋诗','song-poetry','','[]','空山學仙子，窮年卧巖扃。',84,'全唐诗/poet.song.137000.json','["空山學仙子，窮年卧巖扃。", "煮石不得飽，秋鬢蒼已星。", "道逢紫霄翁，示我餐霞經。", "采采晨之華，滌濯腐與腥。", "向來役薪水，終然槁柴荆。", "跪謝起再拜，飄颻蛻蟬輕。", "飛升那敢學，倘許學長生。"]'),
('3adb0fb2-9833-4ffc-898b-e4f63c98c019','冷泉亭放水','范成大','宋','宋诗','song-poetry','','[]','古苔危磴著枯藜，脚底翻濤洶欲飛。',32,'全唐诗/poet.song.137000.json','["古苔危磴著枯藜，脚底翻濤洶欲飛。", "九陌倦遊那有此，從教驚雪濺塵衣。"]'),
('4cea1015-6622-4e7e-8267-a25c2a746a0f','九月十日南山見梅','范成大','宋','宋诗','song-poetry','','[]','五斗留連首屢迴，來尋南澗濯塵埃。',32,'全唐诗/poet.song.137000.json','["五斗留連首屢迴，來尋南澗濯塵埃。", "春風直恐淵明去，借與橫斜對菊開。"]'),
('447cce5e-3d66-48df-8d12-6361bc9755c7','送汪聖錫侍郎帥福唐','范成大','宋','宋诗','song-poetry','','[]','承明纔入又南州，重見旌旗照柁樓。',64,'全唐诗/poet.song.137000.json','["承明纔入又南州，重見旌旗照柁樓。", "道義平生無捷徑，風波隨處有虛舟。", "如公未可違文石，稽古何妨欠碧油。", "我亦登門煩著錄，此行無力爲王留。"]'),
('6ee161d9-3425-4d62-8bda-3550a90658d8','送王純白郎中赴閩漕','范成大','宋','宋诗','song-poetry','','[]','聲利場中百戰鏖，今誰勇退似公豪。',64,'全唐诗/poet.song.137000.json','["聲利場中百戰鏖，今誰勇退似公豪。", "緩尋南粵千山路，先破西興百尺濤。", "平日曼容嫌祿厚，他年文本歎官高。", "才名政爾歸安往，富貴追蹤未可逃。"]'),
('8b2dcc2d-8953-4317-a0c3-0d75cf1ca0f6','長至日與同舍遊北山','范成大','宋','宋诗','song-poetry','','[]','歲晚山同色，湖平霧不收。',48,'全唐诗/poet.song.137000.json','["歲晚山同色，湖平霧不收。", "寒雲低閣雪，佳節靜供愁。", "竹柏森嚴立，蒲荷索莫休。", "瘦笻知脚力，政爾耐清遊。"]'),
('d028822d-24eb-47b9-bc0d-fdeb849ca449','次韻尹少稷察院九宮壇齋宿','范成大','宋','宋诗','song-poetry','','[]','草草馳三里，蕭蕭共一餐。',48,'全唐诗/poet.song.137000.json','["草草馳三里，蕭蕭共一餐。", "吏方綿禮蕝，公自將詩壇。", "隙月窺牀近，窗風刮坐寒。", "鴉鳴未忍散，端爲四并難。"]'),
('67f70081-3540-4555-81e2-891913f1f3a9','冬祠太乙六言四首  其一','范成大','宋','宋诗','song-poetry','','[]','三一舊傳神呪，十神今濟時艱。',28,'全唐诗/poet.song.137000.json','["三一舊傳神呪，十神今濟時艱。", "願挽靈旗北指，爲君直擣陰山。"]'),
('f0cd0403-17d4-48b2-8802-45a1d4a0ebde','冬祠太乙六言四首  其二','范成大','宋','宋诗','song-poetry','','[]','月色朧明碧瓦，蠟煙浮動黄簾。',28,'全唐诗/poet.song.137000.json','["月色朧明碧瓦，蠟煙浮動黄簾。", "罡騎飈輪欲下，一天飛霰纖纖。"]'),
('5045073a-7e67-4f47-a37a-a51ecdcd90a2','冬祠太乙六言四首  其三','范成大','宋','宋诗','song-poetry','','[]','雲木栖烏未動，風庭警鶴先鳴。',28,'全唐诗/poet.song.137000.json','["雲木栖烏未動，風庭警鶴先鳴。", "殘夜百靈夙駕，人間鼻息雷驚。"]'),
('1c7df211-3dce-43a8-bc0c-5472814ad729','冬祠太乙六言四首  其四','范成大','宋','宋诗','song-poetry','','[]','行道羽衣縹緲，捲班玉珮冬瓏。',28,'全唐诗/poet.song.137000.json','["行道羽衣縹緲，捲班玉珮冬瓏。", "回首金鋪獸面，步虛聲在天風。"]'),
('01651e57-d7e9-49b6-aee8-8fdbf49af28b','次韻李子永雪中長句','范成大','宋','宋诗','song-poetry','','[]','黄昏苦寒烏鳥稀，吹沙走石交橫飛。',160,'全唐诗/poet.song.137000.json','["黄昏苦寒烏鳥稀，吹沙走石交橫飛。", "布衾如鐵復似水，夢想東風來解圍。", "豈知天地有奇事，夜半窗紙生光輝。", "兜羅寶界佛所現，冥凌不敢專璿璣。", "開門倚杖眩一色，迥立此世空無依。", "少年行樂怳尚記，瑶林珠樹中成蹊。", "犬驕鷹俊馬蹄快，狡穴未盡須窮追。", "湖海粗豪今豈在，但憶鳴哮如餓鴟。", "北鄰亦復淡生活，要我忍寒吟此詩。", "手龜筆退不可捉，墨泓齟齬冰生衣。"]'),
('89800a14-46f7-4c0e-aa6c-86e6510b028e','次韻子永見贈建除體','范成大','宋','宋诗','song-poetry','','[]','建子玉杓直，黄昏月如霜。',144,'全唐诗/poet.song.137000.json','["建子玉杓直，黄昏月如霜。", "除道啟柴扃，客來巾履忙。", "滿炷寒缸油，共此書檠光。", "平生卜鄰願，何意登我堂。", "定交吾豈敢，南榮慚伯陽。", "執手道古作，遺篇記河梁。", "破窗風鳴悲，孤客多慨傷。", "危腸不捄饑，我詩安得昌。", "成章類村歌，但可侶牛羊。", "收功翰墨藪，微子誰能良。", "開卷得雅音，玉鑾導旂常。", "閉戶坐相念，雪深梅暗香。"]'),
('ee240493-e819-4d14-99ec-4b79237abf15','與胡經仲陳朋元遊照山堂梅數百株盛開','范成大','宋','宋诗','song-poetry','','[]','九陌緇塵滿客襟，錢塘門外有園林。',64,'全唐诗/poet.song.137000.json','["九陌緇塵滿客襟，錢塘門外有園林。", "胡牀住處梅無限，酒旆垂邊柳未深。", "晴日暖風千里目，殘山剩水一人心。", "元方伯始皆吾黨，解后清遊直萬金。"]'),
('f655e1dc-eea5-4a9d-8ead-343568607d7b','次韻胡邦衡祕監','范成大','宋','宋诗','song-poetry','','[]','斯言向來立，千古敢疵瑕。',48,'全唐诗/poet.song.137000.json','["斯言向來立，千古敢疵瑕。", "有命孤蓬轉，何心勁箭加。", "人窮名滿世，天定客還家。", "回首冥恩怨，虛空不著花。"]'),
('a7452b6d-60a4-4176-8533-8c598880979f','三月四日驟煖','范成大','宋','宋诗','song-poetry','','[]','日脚融晴晚氣暄，睡餘初覺薄羅便。',32,'全唐诗/poet.song.137000.json','["日脚融晴晚氣暄，睡餘初覺薄羅便。", "如何柳絮沾泥處，煖似槐陰轉午天。"]'),
('a8c89120-cc0e-42b4-9294-ecf5248fc1f6','久雨地濕','范成大','宋','宋诗','song-poetry','','[]','汗礎經旬未肯乾，破窗隨處有蝸涎。',32,'全唐诗/poet.song.137000.json','["汗礎經旬未肯乾，破窗隨處有蝸涎。", "衹今不耐春陰得，想見黄梅細雨天。"]'),
('5cdd20a4-e6e3-4916-8672-750f33d6e221','晝錦行送陳福公判信州','范成大','宋','宋诗','song-poetry','','[]','漢家麟閣多王侯，冠佩相望經幾秋。',115,'全唐诗/poet.song.137000.json','["漢家麟閣多王侯，冠佩相望經幾秋。", "晝錦聲名兩榮耀，惟有信州如相州。", "國南門頭折楊柳，借問江津垂白叟。", "住在行都四十年，曾見歸舟似公否。", "人言公與赤松期，飈車羽輪來何時。", "雲出雲歸俱是道，苦學赤松還未妙。", "君不見補陀大士海復山，隨喜却來觀世間。"]'),
('a2621dd1-f4b0-4ffd-b979-0f42f4554860','送張真甫中書奉祠歸蜀','范成大','宋','宋诗','song-poetry','','[]','種成桃李恰新陰，忽憶家山叢桂林。',64,'全唐诗/poet.song.137000.json','["種成桃李恰新陰，忽憶家山叢桂林。", "客路莫嫌歸計拙，春江爭似駭機深。", "一封朝奏鈞天夢，萬里江行魏闕心。", "後日還朝飽風露，黑頭應有雪絲侵。"]'),
('a89a9bf8-51a4-4dff-9384-a295c47fcb28','送周子充左史奉祠歸廬陵','范成大','宋','宋诗','song-poetry','','[]','黄鵠飄然下九關，江船載月客俱還。',64,'全唐诗/poet.song.137000.json','["黄鵠飄然下九關，江船載月客俱還。", "名高豈是孤臣願，身退聊開壯士顔。", "傾蓋當年真旦暮，沾巾明日有河山。", "後期淹速都難料，相對猶憐鬢未斑。"]'),
('0ec7d479-e44d-40bc-adad-1c83a4b17f49','送陳天予大監同年使閩','范成大','宋','宋诗','song-poetry','','[]','春關十載記英遊，蚤喜時才近采旒。',64,'全唐诗/poet.song.137000.json','["春關十載記英遊，蚤喜時才近采旒。", "夷路著鞭方逸駕，急流回首忽扁舟。", "雲霄正穩君猶去，塵土無邊我合休。", "問訊後車容客否，茶山荔浦看南州。"]'),
('52fee84f-2872-4acd-8d01-5f97a364539f','送陸務觀編修監鎮江郡歸會稽待闕  其一','范成大','宋','宋诗','song-poetry','','[]','寶馬天街路，煙篷海浦心。',48,'全唐诗/poet.song.137000.json','["寶馬天街路，煙篷海浦心。", "非關愛京口，自是憶山陰。", "高興餘飛動，孤忠有照臨。", "浮雲付舒卷，知子道根深。"]'),
('02d9d5e1-1d5e-4717-8d9e-1d41fc66bb54','送陸務觀編修監鎮江郡歸會稽待闕  其二','范成大','宋','宋诗','song-poetry','','[]','見說雲門好，全家住翠微。',48,'全唐诗/poet.song.137000.json','["見說雲門好，全家住翠微。", "京塵成歲晚，江雨送人歸。", "邊鎖風雷動，軍書日夜飛。", "功名袖中手，世事巧相違。"]'),
('bc010220-458e-4a6c-8a65-88ec2461452f','送李仲鎮宰溧陽','范成大','宋','宋诗','song-poetry','','[]','相逢已歎十年遲，冷淡貧交又語離。',64,'全唐诗/poet.song.137000.json','["相逢已歎十年遲，冷淡貧交又語離。", "玉筍換班通籍後，黄梅催雨送帆時。", "月巖家世猶爲縣，金瀨溪山好賦詩。", "喚起酸寒孟東野，倒流三峽洗餘悲。"]'),
('afc5629e-7a49-4b06-ac09-d545e2444a89','送吳元茂丞浦江','范成大','宋','宋诗','song-poetry','','["\u897f\u6e56"]','玉筍翻乘縣佐車，飄然不肯待新除。',64,'全唐诗/poet.song.137000.json','["玉筍翻乘縣佐車，飄然不肯待新除。", "才名已被人爭說，官薄何妨計小疎。", "憶昨西湖同我載，從今南浦望君書。", "遥知斂板趨風後，始覺丞哉果負予。"]'),
('9b4ce9e6-a919-4889-87cc-022855278827','雪晴呈子永','范成大','宋','宋诗','song-poetry','','[]','碧空無處泊同雲，晴入荒園鳥雀馴。',64,'全唐诗/poet.song.137000.json','["碧空無處泊同雲，晴入荒園鳥雀馴。", "冰面小風池欲動，雪邊濃日瓦如薰。", "塵容俗狀長爲客，冷蕊疎枝又作春。", "詩卷豈能生暖熱，犯寒聊復惱比鄰。"]'),
('35e03e46-658c-4ab3-90cb-af8a3b1b447b','次韻子永雪後見贈','范成大','宋','宋诗','song-poetry','','[]','雪瓴待伴半陰晴，竟日檐冰溜雨聲。',64,'全唐诗/poet.song.137000.json','["雪瓴待伴半陰晴，竟日檐冰溜雨聲。", "九陌泥乾塵未動，南山石露塔猶明。", "稍聞吉語占農事，便覺歸心勝宦情。", "想得秫田來歲好，瓦盆加釀灌愁城。"]'),
('c51201aa-6eb9-4d91-8e64-8a1269829ebf','次韻郊祀慶成','范成大','宋','宋诗','song-poetry','','[]','帝德重堯緒，天心與舜禋。',168,'全唐诗/poet.song.137000.json','["帝德重堯緒，天心與舜禋。", "慶期符後甲，元日際初辛。", "土緯扶南極，旄胡拱北辰。", "律諧風自艮，衡正斗垂寅。", "桂燎靈宮曉，蕭脂太室晨。", "百神森壁壘，萬衛密鉤陳。", "日月青旂色，雷霆玉輅塵。", "洗兵銀漢水，收雪紫壇春。", "天步臨黄道，仙班像玉宸。", "陶匏宗素樸，琮璧慕精純。", "祕祝裒時對，高斿欻下賓。", "金鐘鳴傑簴，朱火熭芳薪。", "日麗雞竿矗，天旋鳳律新。", "端門敷錫後，六合共絪縕。"]'),
('1573bd32-f44f-4141-b73c-c6708ec2ab47','從巨濟乞蠟梅','范成大','宋','宋诗','song-poetry','','[]','寂寥人在曉雞窗，苦憶花前續斷腸。',32,'全唐诗/poet.song.137000.json','["寂寥人在曉雞窗，苦憶花前續斷腸。", "全樹折來應不惜，君家真色自生香。"]'),
('6b3604c6-0f29-499a-898d-b5f0bf025c95','次韻朋元賣花處見梅','范成大','宋','宋诗','song-poetry','','[]','煙濃日淡不多寒，擔上看花雪作團。',32,'全唐诗/poet.song.137000.json','["煙濃日淡不多寒，擔上看花雪作團。", "想得竹邊春已暗，明朝走馬過溪看。"]'),
('ee317738-5521-4cf0-b677-cef47bf5838c','與正夫朋元遊陳侍御園','范成大','宋','宋诗','song-poetry','','[]','沙際春風捲物華，意行聊復到君家。',64,'全唐诗/poet.song.137000.json','["沙際春風捲物華，意行聊復到君家。", "年年我是曾來客，處處梅皆舊識花。", "官減不妨詩事業，地寒猶辦醉生涯。", "城中馬上那知此，塵滿長裾席帽斜。"]'),
('f35c9272-6086-45e1-a0bb-a5a9d276b176','正月十四日雨中與正夫朋元小集夜歸','范成大','宋','宋诗','song-poetry','','[]','燈市淒清燈火稀，雨巾風帽笑歸遲。',64,'全唐诗/poet.song.137000.json','["燈市淒清燈火稀，雨巾風帽笑歸遲。", "月明想在雲堆處，客醉都忘馬滑時。", "老去樽前花隔霧，春來句裏鬢成絲。", "浮生不了悲歡事，作劇兒童總未知。"]'),
('3dd6fb1a-72dd-410a-b85a-d74e5697ea0b','次韻子永夜雨','范成大','宋','宋诗','song-poetry','','[]','辦作長愁客，工哦苦雨吟。',48,'全唐诗/poet.song.137000.json','["辦作長愁客，工哦苦雨吟。", "挑燈今夕意，欹枕故園心。", "漏屋疎疎滴，空檐細細斟。", "相過巷南北，屐齒怕泥深。"]'),
('43b6d9b6-0540-48a5-9b6a-70d6e21c0cc9','次韻朋元遊王氏園','范成大','宋','宋诗','song-poetry','','[]','聯翩步屧翠微間，回首紅塵自鮮歡。',64,'全唐诗/poet.song.137000.json','["聯翩步屧翠微間，回首紅塵自鮮歡。", "捲地雨添千澗急，擁門雲鎖兩山盤。", "絕憐茶笋能留客，仍喜蛙聲不在官。", "雪白楊梅消息未，重來應至麥秋寒。"]'),
('8077e5e4-0e67-4647-821b-a9744946a1c0','遊靈石山寺','范成大','宋','宋诗','song-poetry','','["\u897f\u6e56"]','西湖富清麗，城府塵事并。',132,'全唐诗/poet.song.137000.json','["西湖富清麗，城府塵事并。", "我獨數能來，不負雙眼明。", "騷騷殘絮罷，颭颭新荷成。", "歲華日夜好，遊子能無情。", "午陰釀初暑，稍喜巾袂輕。", "小風吹鬢毛，將我入松聲。", "崖寺金碧暗，石泉肝膽清。", "壽藟萬蛟舞，靈峰雙髻撐。", "仙人昔來游，筆墨上朱甍。", "舉臂尋丈高，聊得兒童驚。", "老矣謝狡獪，題詩記吾曾。"]'),
('04a3a228-1403-4d51-a92c-b063a68685d6','次韻李器之編修靈石山萬歲藤歌','范成大','宋','宋诗','song-poetry','','[]','君不見東林怪蔓之詩三百年，字如金繩鐵索相糾纏。',185,'全唐诗/poet.song.137000.json','["君不見東林怪蔓之詩三百年，字如金繩鐵索相糾纏。", "不如李侯靈石句，筆陣壓倒長城堅。", "藤陰詩律兩秀發，此段奇事今無前。", "吾聞草木未有不黄落，雨荒霜倒相後先。", "綿綿紫藟天所壽，風雨不動常蒼然。", "堅姿絕鄰傲一所，深本無極融三泉。", "騰虯舞蛟矯欲去，流蘇絡带翩如仙。", "班荆芘藾得吾黨，酌泉共吸杯中天。", "詩成一斗屬太白，擘牋揮掃如雲煙。", "北門西掖君自有，坐擁紅藥然金蓮。", "山腰澗底莫濡滯，早晚天風吹蛻蟬。"]'),
('22495ce4-79a6-46f4-81f2-72cbe64344c6','次韻正夫遊王園會者六人','范成大','宋','宋诗','song-poetry','','[]','丘園窈窕復崎嶇，草木生香景倍殊。',64,'全唐诗/poet.song.137000.json','["丘園窈窕復崎嶇，草木生香景倍殊。", "花下百杯齊物我，雲邊一眼盡江湖。", "不知朱戶趦趄者，能勝青山放浪無。", "六逸蕭然真可畫，爲君題作竹溪圖。"]'),
('12f4d727-a21d-44a0-ae72-d4addc4da40d','四月五日集陳園照山堂','范成大','宋','宋诗','song-poetry','','[]','尋壑經丘到此堂，官閑聊作送春忙。',64,'全唐诗/poet.song.137000.json','["尋壑經丘到此堂，官閑聊作送春忙。", "短籬水面殘紅滿，團扇風前衆綠香。", "盡捲簾旌延竹色，深斟杯酒納山光。", "洞門無鎖城門近，轉午雞啼日正長。"]'),
('e2d1b152-936a-44eb-b327-551fae5c58da','題寶林寺可賦軒','范成大','宋','宋诗','song-poetry','','[]','十里山行雜市聲，道傍無處濯塵纓。',32,'全唐诗/poet.song.137000.json','["十里山行雜市聲，道傍無處濯塵纓。", "寶林寺裏逢修竹，方有詩情約略生。"]'),
('50e63dce-4c47-48f3-8b96-8073dc8bef2e','次韻朋元久雨','范成大','宋','宋诗','song-poetry','','[]','誰釀愁䨧玉宇間，都緣梅子要斕斑。',64,'全唐诗/poet.song.137000.json','["誰釀愁䨧玉宇間，都緣梅子要斕斑。", "騰騰困思午猶夢，擾擾奔雲風未還。", "休問滿城騎馬滑，不妨長日閉門閑。", "今朝晴色熹微似，乾鵲飛來語屋山。"]'),
('ceefb2c2-823b-48d3-8e2d-19897f73bc1e','韓無咎檢詳出示所賦陳季陵戶部巫山圖詩仰窺高作歎息彌襟余嘗考宋玉談朝雲事漫稱先王時本無據依及襄王夢之命玉爲賦但云頩顔怒以自持曾不可乎犯干後世弗察一切溷以媟語曹子建賦宓妃亦感此而作此嘲誰當解者輒用此意次韻和呈以資撫掌','范成大','宋','宋诗','song-poetry','','[]','瑶姬家山高插天，碧叢奇秀古未傳。',195,'全唐诗/poet.song.137000.json','["瑶姬家山高插天，碧叢奇秀古未傳。", "向來題目經楚客，名字徑度岷峨前。", "是邪非邪莽誰識，喬林古廟常秋色。", "暮去行雨朝行雲，翠帷瑶席知何人。", "峽船一息且千里，五兩竿頭見旛尾。", "仰窺仙館至今疑，行人問訊居人指。", "千年遺恨何當申，陽臺愁絕如荒村。", "高唐賦裏人如畫，玉色頩顔元不嫁。", "後來饑客眼長寒，浪傳樂府吹復彈。", "此事牽連到溫洛，更憐塵襪有無間。", "君不見天孫住在銀濤許，塵間猶作兒女語。", "公家春風錦瑟傍，莫爲此圖虛斷腸。"]'),
('41485263-2adc-4a9e-9e42-e247df708e0f','次韻樂先生吳中見寄八首  其一','范成大','宋','宋诗','song-poetry','','[]','金鶴飛來尺素通，新詩字字挾光風。',32,'全唐诗/poet.song.137000.json','["金鶴飛來尺素通，新詩字字挾光風。", "三年湖海關心處，都在先生句子中。"]'),
('4477ff2e-e5a6-4526-bf95-12785c1d819e','次韻樂先生吳中見寄八首  其二','范成大','宋','宋诗','song-poetry','','[]','官居門巷果園西，桃李成蹊杏壓枝。',32,'全唐诗/poet.song.137000.json','["官居門巷果園西，桃李成蹊杏壓枝。", "如許年芳忙裏過，斬新今日試題詩。"]'),
('a6d09a94-03bc-4316-9633-57521741e6f6','次韻樂先生吳中見寄八首  其三','范成大','宋','宋诗','song-poetry','','[]','暮林棲鳥各深枝，燕子知巢觸幔飛。',32,'全唐诗/poet.song.137000.json','["暮林棲鳥各深枝，燕子知巢觸幔飛。", "倘有三椽今已去，不關五斗解忘歸。"]'),
('0f8a2e9f-11ee-4cf8-926e-44a6deb54aae','次韻樂先生吳中見寄八首  其四','范成大','宋','宋诗','song-poetry','','[]','懶不看書似姓邊，夢魂飛繞白鷗前。',32,'全唐诗/poet.song.137000.json','["懶不看書似姓邊，夢魂飛繞白鷗前。", "須知席帽衝塵出，不似篷窗聽雨眠。"]'),
('6f68659a-9811-453c-b39e-8e81fb482b59','次韻樂先生吳中見寄八首  其五','范成大','宋','宋诗','song-poetry','','[]','送春濛雨漲蘋灘，荷葉田田柳絮闌。',32,'全唐诗/poet.song.137000.json','["送春濛雨漲蘋灘，荷葉田田柳絮闌。", "想見垂虹三萬頃，拍天湖水釣絲寒。"]'),
('c45dfb67-0429-45e4-8386-b1cd465795fc','次韻樂先生吳中見寄八首  其六','范成大','宋','宋诗','song-poetry','','[]','知從了義透音聞，古井無波豈更渾。',32,'全唐诗/poet.song.137000.json','["知從了義透音聞，古井無波豈更渾。", "便好一坑埋衆妙，何須六結解諸根。"]'),
('7f4c4611-af5a-491b-87dc-7831f2a2b927','次韻樂先生吳中見寄八首  其七','范成大','宋','宋诗','song-poetry','','[]','幾多螻蟻與王侯，往古來今共一丘。',32,'全唐诗/poet.song.137000.json','["幾多螻蟻與王侯，往古來今共一丘。", "遮莫功名掀宇宙，百年兩角寄蝸牛。"]'),
('081d7f64-981b-493d-aa65-8fbf7df38cf6','次韻樂先生吳中見寄八首  其八','范成大','宋','宋诗','song-poetry','','[]','粟囊聊復寄三餐，埋沒緇塵懶濯冠。',32,'全唐诗/poet.song.137000.json','["粟囊聊復寄三餐，埋沒緇塵懶濯冠。", "紅紫百般紛過眼，鄉山歲晚自蒼官。"]'),
('cd060dc8-98bb-49f1-b083-449f5803f055','胡長民監元輓詞','范成大','宋','宋诗','song-poetry','','[]','太學虀鹽舊，中吳翰墨聲。',48,'全唐诗/poet.song.137000.json','["太學虀鹽舊，中吳翰墨聲。", "關山題柱筆，風露讀書檠。", "夜雨綠荷破，孤墳丹桂生。", "空將擅場手，往記玉樓成。"]'),
('3b8e5f05-dc21-43e5-95c8-759e27b6a5b9','次韻朋元正夫夜飲','范成大','宋','宋诗','song-poetry','','[]','歌豪仍作家，弈勝豈徼幸。',84,'全唐诗/poet.song.137000.json','["歌豪仍作家，弈勝豈徼幸。", "莫嗤老非少，乃尚可以逞。", "玉瓶引杯長，政爾寒漏永。", "二三文章公，共此銀燭影。", "陳卿得秀句，劉郎一笑領。", "羸驂兀殘夢，乘墜恍難省。", "曉枕訌更潮，俱墜無何境。"]'),
('a105f6d4-3af9-4c4e-ab79-277586906f72','次韻趙正之同年客中  其一','范成大','宋','宋诗','song-poetry','','[]','清班合列大明宮，自要牛刀試一同。',32,'全唐诗/poet.song.137000.json','["清班合列大明宮，自要牛刀試一同。", "踏徧巉巖吾道在，莫將尋尺較窮通。"]'),
('e7bf3904-06b8-44a5-8b56-87a4e4fdf10c','次韻趙正之同年客中  其二','范成大','宋','宋诗','song-poetry','','[]','氈車席帽各青春，花下驊騮一鬨塵。',32,'全唐诗/poet.song.137000.json','["氈車席帽各青春，花下驊騮一鬨塵。", "離合飄零十霜露，咸陽客舍有詩人。"]'),
('9f2973ec-539d-4e9e-a205-ca941938161b','次韻趙正之同年客中  其三','范成大','宋','宋诗','song-poetry','','[]','可憐山縣五斤手，不識王孫八斗才。',32,'全唐诗/poet.song.137000.json','["可憐山縣五斤手，不識王孫八斗才。", "君自扶搖有霄漢，從渠蜩鷃舞蒿萊。"]'),
('466685fd-5ccf-4c99-b2a7-9dff7f817858','次韻陳季鄰戶部旦過菴','范成大','宋','宋诗','song-poetry','','[]','宦遊觸處似懸匏，北嶽南山想獻嘲。',64,'全唐诗/poet.song.137000.json','["宦遊觸處似懸匏，北嶽南山想獻嘲。", "指手百年休鑄鐵，蓋頭一把暫誅茅。", "玉京歲晚梧桐落，水國霜清橘柚包。", "飛錫已隨歸夢去，何人頂上鵲成巢。"]'),
('7a57cc0e-f2b9-4207-b29d-07032bb2c639','朋元不赴湖上觀雪之集明日余召試玉堂見寄二絕次其韻  其一','范成大','宋','宋诗','song-poetry','','[]','雪溪清興未渠闌，晚上西樓带月看。',32,'全唐诗/poet.song.137000.json','["雪溪清興未渠闌，晚上西樓带月看。", "公子自貪低唱酒，肯來同對玉峰寒。"]'),
('b54f96c6-2967-473b-a365-77033908ef4b','朋元不赴湖上觀雪之集明日余召試玉堂見寄二絕次其韻  其二','范成大','宋','宋诗','song-poetry','','[]','文場寧復鬢霜宜，白玉堂前雪霽時。',32,'全唐诗/poet.song.137000.json','["文場寧復鬢霜宜，白玉堂前雪霽時。", "不惜狂言棖忌諱，禿毫冰硯竟無奇。"]'),
('24db8ef9-a17b-4f98-ad70-647fd6ba2f3f','翰林學士何公輓詞','范成大','宋','宋诗','song-poetry','','[]','盛際羣多士，諸儒遜一賢。',48,'全唐诗/poet.song.137000.json','["盛際羣多士，諸儒遜一賢。", "名場魁淡墨，官簿到花磚。", "地近行知政，天高不假年。", "書生稽古力，何必盡台躔。"]'),
('ddabd91d-f452-4ee1-8dfd-771f7088cff8','送洪內翰使虜二首  其一','范成大','宋','宋诗','song-poetry','','[]','郊廟熙成霈率濱，罪如猾夏亦維新。',64,'全唐诗/poet.song.137000.json','["郊廟熙成霈率濱，罪如猾夏亦維新。", "邊烽已却來南虜，使節猶煩第一人。", "遥想穹廬占漢月，便呼重譯布唐春。", "單于若問公家世，說與麒麟畫老臣。"]'),
('c957aa3a-11e6-4ca6-948e-4656454c5e71','送洪內翰使虜二首  其二','范成大','宋','宋诗','song-poetry','','[]','峨冠方侍玉輿香，雙節飄然照大荒。',64,'全唐诗/poet.song.137000.json','["峨冠方侍玉輿香，雙節飄然照大荒。", "正倚先生令趙重，寧容驕子詫胡强。", "天教忠信行區脫，人許功名上太常。", "試卜和羹知未晚，歸來煙雨正梅黄。"]'),
('69902a4e-feed-4735-8bd9-689d481127ca','次韻趙德莊吏部休沐','范成大','宋','宋诗','song-poetry','','[]','窈窕新堂好，委蛇夜直還。',48,'全唐诗/poet.song.137000.json','["窈窕新堂好，委蛇夜直還。", "遥知欹帽髮，正奈捲簾山。", "門外客姑去，窗前人對閑。", "誰能烏帽底，塵土涴朱顔。"]'),
('0db1741c-596b-473f-87d9-87c10b158363','次韻王夷仲正字同遊成氏園','范成大','宋','宋诗','song-poetry','','[]','秀巖堂上玉東西，把酒登臨望眼迷。',64,'全唐诗/poet.song.137000.json','["秀巖堂上玉東西，把酒登臨望眼迷。", "天宇四垂粘地近，海山一抹带潮低。", "絕知客好無塵事，聊記吾曾有醉題。", "倚頼羣仙聯姓字，他年誰敢一杴泥。"]'),
('3f7fcc47-a65a-4881-a33f-d5608d445a40','王季海祕監再賦成園復次韻','范成大','宋','宋诗','song-poetry','','[]','雲莊風榭對東西，清暑光陰近竹迷。',64,'全唐诗/poet.song.137000.json','["雲莊風榭對東西，清暑光陰近竹迷。", "一斗正緣詩興盡，兩眉休爲客愁低。", "披開豹霧尋陳迹，掃盡蛛塵看舊題。", "健往莫愁騎馬滑，闌珊梅雨不成泥。"]'),
('04b22f4c-bbec-46b7-bd12-3fd9376f5fc0','春晚偶題','范成大','宋','宋诗','song-poetry','','[]','寂寥春事冷於秋，雨打風吹斷送休。',32,'全唐诗/poet.song.137000.json','["寂寥春事冷於秋，雨打風吹斷送休。", "點檢梨花成一夢，蘸紅新綠滿枝頭。"]'),
('888818d3-c87b-4255-986a-860582271523','倪文舉奉常將歸東林出示綺川西溪二賦輒賦長句爲謝且以贈行','范成大','宋','宋诗','song-poetry','','[]','綺川亭上凌雲賦，人在回仙舊遊處。',160,'全唐诗/poet.song.137000.json','["綺川亭上凌雲賦，人在回仙舊遊處。", "誰教書劍走長安，荻月霜楓等閑度。", "朱門不炙釣竿手，萬卷難供折腰具。", "偶然把筯憶蓴羹，乞得閑官徑呼渡。", "江漲橋頭有渡船，船頭歷歷東林路。", "雲煙如畫水如天，笑憶紅塵問良苦。", "我亦吳松一釣舟，蟹舍漂搖幾風雨。", "因君賦裏說江湖，破帽蹇馿明亦去。", "雞犬相聞望可見，鷗鷺同盟心亦許。", "相過得得款溪門，雪夜前村聽鳴櫓。"]'),
('95e45e34-fa65-46dd-99a3-b8a73bb91549','送吳智叔檢詳直中祕使閩','范成大','宋','宋诗','song-poetry','','[]','抗章襆被豈公難，已說高風立懦頑。',64,'全唐诗/poet.song.137000.json','["抗章襆被豈公難，已說高風立懦頑。", "客路莫嫌河畔草，直廬須愛道家山。", "秋生蓮浦船初泛，春滿茶溪騎趣還。", "却訪故人西府舊，定煩書札墮田間。"]'),
('7db7fa75-e98f-4599-b10d-3e54aad254e1','楊君居士輓詞','范成大','宋','宋诗','song-poetry','','[]','孝至蘭陔茂，身脩梓里恭。',48,'全唐诗/poet.song.137000.json','["孝至蘭陔茂，身脩梓里恭。", "名場兒中鵠，婣黨婿乘龍。", "駒隙驚年運，蟬嫣有慶鍾。", "幽光定無憾，豐刻妙形容。"]'),
('bb903a82-23f7-4b83-8dfa-6749081cce62','送周畏知司直歸上饒待次','范成大','宋','宋诗','song-poetry','','[]','漫郎西笑費三年，故業新聞腹果然。',64,'全唐诗/poet.song.137000.json','["漫郎西笑費三年，故業新聞腹果然。", "長麈劇談抽繭緒，短檠細字綴蠶眠。", "頻驚陸海風波夢，未了京塵粥飯緣。", "後日重來應訪舊，五湖煙浪有漁船。"]'),
('bc5e4193-dec1-4a37-bd60-cd299d68abe9','次韻魏端仁感懷俳諧體','范成大','宋','宋诗','song-poetry','','[]','浪學騷人賦遠游，大千何事不悠悠。',64,'全唐诗/poet.song.137000.json','["浪學騷人賦遠游，大千何事不悠悠。", "酒邊點檢顔紅在，鏡裏端詳鬢雪羞。", "過眼浮雲翻覆易，曲肱短夢破除休。", "孤煙落日冥鴻去，心更冥鴻最上頭。"]'),
('9b786780-26a1-4756-8fb5-035d2decce97','次韻李子永梅村散策圖','范成大','宋','宋诗','song-poetry','','[]','光風先放越溪春，蕭散尋詩索笑人。',32,'全唐诗/poet.song.137000.json','["光風先放越溪春，蕭散尋詩索笑人。", "藜杖前頭春浩蕩，三生應是主林神。"]'),
('0681651f-1adc-4a2d-8ab1-278cf4408e58','太師陳文恭公輓詞  其一','范成大','宋','宋诗','song-poetry','','[]','日者更皇化，公來輔聖能。',48,'全唐诗/poet.song.137000.json','["日者更皇化，公來輔聖能。", "無心殊轍混，不作衆波澄。", "舉國材真相，他年了中興。", "天如遺一老，人亦望三登。"]'),
('45dbb05b-89aa-41d4-83bb-d05d9d233d14','太師陳文恭公輓詞  其二','范成大','宋','宋诗','song-poetry','','[]','候火朝連夕，籌帷决縱擒。',48,'全唐诗/poet.song.137000.json','["候火朝連夕，籌帷决縱擒。", "一江遮虜障，千古殺胡林。", "皦日黄河誓，浮雲綠野心。", "身名兩無憾，天壤獨清音。"]'),
('fc4bd927-30ab-4251-8f30-d0e95cadf93f','太師陳文恭公輓詞  其三','范成大','宋','宋诗','song-poetry','','[]','聖父咨當璧，元臣預斷金。',48,'全唐诗/poet.song.137000.json','["聖父咨當璧，元臣預斷金。", "玉衡賓舜日，黄屋遂堯心。", "國定功無迹，身閑病已深。", "旌忠有謨訓，碑牓照來今。"]'),
('9f03b46b-fbce-47e3-901d-44674c8ce348','太師陳文恭公輓詞  其四','范成大','宋','宋诗','song-poetry','','[]','趣召單車至，驚傳兩鬢凋。',48,'全唐诗/poet.song.137000.json','["趣召單車至，驚傳兩鬢凋。", "傾城迎國老，即日走天驕。", "夢已商人奠，身猶漢相朝。", "古來賢達意，生滅兩消搖。"]'),
('2816ce75-d35d-4fc9-89a4-5488661ef101','送陳朋元赴溧陽','范成大','宋','宋诗','song-poetry','','[]','九畹滋蘭靜自芳，啁啾誰復認孤凰。',64,'全唐诗/poet.song.137000.json','["九畹滋蘭靜自芳，啁啾誰復認孤凰。", "風流歲晚嫌杯酒，文字功深得鬢霜。", "斂板君猶能俛仰，倚樓吾敢計行藏。", "船開便作江南客，天色無情更鴈行。"]'),
('f34fd971-af5e-487b-98b9-25dc072dee84','次韻韓無咎右司上巳泛湖','范成大','宋','宋诗','song-poetry','','[]','休沐辰良不待晴，徑稱閑客此閑行。',64,'全唐诗/poet.song.137000.json','["休沐辰良不待晴，徑稱閑客此閑行。", "春衫欺雨任教冷，病眼得山元自明。", "抹黛濃嵐圍坐晚，揉藍新淥沒篙清。", "棲鴉未到催歸去，想被東風笑薄情。"]'),
('a5779a16-fed0-49ac-854c-5dee3c24b53b','太保節使趙公輓詞','范成大','宋','宋诗','song-poetry','','[]','結髮險艱會，捐軀跳盪功。',48,'全唐诗/poet.song.137000.json','["結髮險艱會，捐軀跳盪功。", "鬢凋猶陛戟，心在惜弢弓。", "劍履三槐次，樓臺四壁中。", "諸郎競文武，不朽是清風。"]'),
('fcb898f9-4f06-4193-8426-f5c4384c7d69','太宜人程氏輓詞  其一','范成大','宋','宋诗','song-poetry','','[]','我昔官黟歙，人傳女訓芳。',48,'全唐诗/poet.song.137000.json','["我昔官黟歙，人傳女訓芳。", "尊章宜小婦，孫子壽高堂。", "風木真無定，冰魚已不嘗。", "遥憐霜露感，何必薤歌傷。"]'),
('c69c11ae-b8b0-4416-be56-01624ad5c347','太宜人程氏輓詞  其二','范成大','宋','宋诗','song-poetry','','[]','捧檄三牲養，稱觴百歲期。',48,'全唐诗/poet.song.137000.json','["捧檄三牲養，稱觴百歲期。", "身猶孺子泣，世已隙駒馳。", "吉夢青衣卜，豐碑黄絹辭。", "佳城有奇事，應足洗餘悲。"]'),
('69894db0-2b81-4246-954a-4118335b8009','與王夷仲檢討祀社','范成大','宋','宋诗','song-poetry','','[]','殘夜露如雨，秋氣淒以分。',132,'全唐诗/poet.song.137000.json','["殘夜露如雨，秋氣淒以分。", "牆西雲正黑，跕跕墮金盆。", "良耜酢西成，豆籩蓊芳芬。", "去年歲大祲，小家甑生塵。", "疫鬼投其巇，虐甚溺與焚。", "皇慈降清問，下招離散魂。", "調糜鬻藥石，黑簿回春溫。", "德馨典神天，秋稼如雲屯。", "社公亦塞責，醉此豐年樽。", "神兮率舊職，爲國憂元元。", "自今歲其有，驅癘蒼煙根。"]'),
('f87d0ee2-24b8-4526-a5d8-5313c14b970a','王園官舍睡起','范成大','宋','宋诗','song-poetry','','[]','公退閉閣卧，官居如浄坊。',48,'全唐诗/poet.song.137000.json','["公退閉閣卧，官居如浄坊。", "屋角斷虹飲，日西楊柳黄。", "客來束我带，客去書滿牀。", "睡覺有忙事，煮茶翻斷香。"]'),
('a0ec8ec2-b920-4ce6-afbd-df4bbf2aa4e9','古風酬胡元之','范成大','宋','宋诗','song-poetry','','[]','拂我膝上琴，當客清風襟。',76,'全唐诗/poet.song.137000.json','["拂我膝上琴，當客清風襟。", "我琴無軫絃不和，願借之子調其音。", "美人一笑千黄金，彈作江岸花木深。", "下有同隊之游魚，上有同聲之鳴禽。", "琴聲一疊一歎息，江花江草無終極。"]'),
('24a12809-08b7-4a29-bb46-4063f9a8ac07','題徑山凌霄菴','范成大','宋','宋诗','song-poetry','','[]','峰頭非塵寰，一舍誰所茇。',72,'全唐诗/poet.song.137000.json','["峰頭非塵寰，一舍誰所茇。", "軒眉玉霄近，按指沙界豁。", "萬山紛累塊，衆水眇聚沫。", "來雲觸石迴，去鳥墮煙沒。", "向無超俗緣，茲路詎可越。", "偕行木上坐，同我證解脫。"]'),
('7a8e6d29-50f7-40dc-b8da-5e7e80d7609b','徑山傾蓋亭','范成大','宋','宋诗','song-poetry','','[]','萬杉離立翠雲幢，嫋嫋稀聞晚吹香。',32,'全唐诗/poet.song.137000.json','["萬杉離立翠雲幢，嫋嫋稀聞晚吹香。", "山下行人塵撲面，誰知世界有清凉。"]'),
('e280f508-08e9-4d67-92a8-718372d23550','題徑山寺樓','范成大','宋','宋诗','song-poetry','','[]','浴日蒼茫水，捫星縹緲樓。',48,'全唐诗/poet.song.137000.json','["浴日蒼茫水，捫星縹緲樓。", "神光來燭夜，壽木不知秋。", "海內五峰秀，天涯雙徑遊。", "愛山吾欲住，衰疾懶乘流。"]'),
('793329cd-8157-4e2d-969b-7c0fb65d9acb','丙戌閏七月九日與王必大登姑蘇臺招王浚明陳淵叔耿時舉避暑次時舉韻','范成大','宋','宋诗','song-poetry','','[]','始賀火流西，還嗟斗斜閏。',168,'全唐诗/poet.song.137000.json','["始賀火流西，還嗟斗斜閏。", "餘暑猶强顔，新凉頗難進。", "燥剛渴欲坼，焦卷禿如燼。", "炎官扶日轂，輝赫不停運。", "登臨有高臺，勇往得三俊。", "仍將王郎子，飛步凌劫仞。", "風從噫氣來，雲作壞山陣。", "鄉如垂頭魚，忽已蟄蟲振。", "空明晚逾清，更要孤月印。", "書生乃易與，俛仰更喜慍。", "憑闌天爲高，舉酒山欲近。", "奇書鐵鉤鎖，麗句錦窠暈。", "茲遊我輩獨，難挽軟紅軔。", "君看籠中鳥，寧識咸池韻。"]'),
('a1b2fe31-8f6e-45d4-8f19-3af78438101a','明日夜雨陡凉復次前韻呈時舉','范成大','宋','宋诗','song-poetry','','[]','幽懷青松獨，直道黄楊閏。',168,'全唐诗/poet.song.137000.json','["幽懷青松獨，直道黄楊閏。", "懶從褦襶子，遮日干主進。", "閉戶友千載，脫簡理秦燼。", "秋熱出意表，誰云法天運。", "摧頹如鎩翮，何暇賈餘俊。", "願從青溪仙，飛下二千仞。", "撇波嘯長風，鏖暑陷其陣。", "茲行病未能，暍卧何時振。", "一雨忽破慳，江湖發封印。", "天公如仲尼，亦念季路慍。", "團扇未全疎，短檠差可近。", "細字讀蠶眠，揩眼眩燈暈。", "明當呼我友，乘凉蹳游軔。", "賡詩代僕吶，非敢翫强韻。"]'),
('7a6d7213-924b-4b38-b141-6f78c9f597d8','七月二日上沙夜泛','范成大','宋','宋诗','song-poetry','','[]','困倚船窗看斗斜，起來風露滿天涯。',64,'全唐诗/poet.song.137000.json','["困倚船窗看斗斜，起來風露滿天涯。", "亭亭宿鷺明菰葉，閃閃凉螢入稻花。", "月下片雲應夜雨，山根炬火忽人家。", "江湖處處無窮景，半世紅塵老歲華。"]'),
('1af96473-de56-48f0-9239-7dd65ac9633c','浴罷','范成大','宋','宋诗','song-poetry','','[]','西城落日半輪明，浴罷衣裳一倍輕。',32,'全唐诗/poet.song.137000.json','["西城落日半輪明，浴罷衣裳一倍輕。", "玉宇風來歸鳥急，火雲銷盡綠雲生。"]'),
('af552c4f-1f01-49b7-8aab-0b2f2a83df0c','寄溧陽陳朋元明府約秋末過之','范成大','宋','宋诗','song-poetry','','[]','海內交情兩斷金，一官分袂阻登臨。',64,'全唐诗/poet.song.137000.json','["海內交情兩斷金，一官分袂阻登臨。", "書來恰值看雲眼，夢往誰知共月心。", "道義只今無捷徑，溪山依舊有清音。", "西風滿棹蒲帆飽，秉燭相尋語夜深。"]'),
('cad9ec2f-0aca-47b8-8650-b5b2e71ea2c3','次韻耿時舉苦熱','范成大','宋','宋诗','song-poetry','','[]','赤日纔低又火雲，巷南街北斷知聞。',64,'全唐诗/poet.song.137000.json','["赤日纔低又火雲，巷南街北斷知聞。", "荷風拂簟昭蘇我，竹月篩窗慰藉君。", "避暑無奇那避謗，能觴便了莫能文。", "浮湛放蕩從今始，悔把長裾强沐薰。"]'),
('637c711f-6ab1-48ac-90bd-bf22d6ef4953','次韻王浚明用時舉苦熱韻見贈','范成大','宋','宋诗','song-poetry','','[]','暑窗當午思昏昏，雷起千峰睡不聞。',64,'全唐诗/poet.song.137000.json','["暑窗當午思昏昏，雷起千峰睡不聞。", "鑠石誰能招楚魄，斲冰我欲訪湘君。", "年華衹合加餐飯，事業休工刺繡文。", "頼有兩賢南北巷，歲寒幽谷共蘭薰。"]'),
('6230d6ab-72d3-4ccf-b214-0a59e1a4e731','李次山自畫兩圖其一泛舟湖山之下小女奴坐船頭吹笛其一跨馿渡小橋入深谷各題一絕  其一','范成大','宋','宋诗','song-poetry','','[]','船頭月午坐忘歸，不管風鬟露滿衣。',32,'全唐诗/poet.song.137000.json','["船頭月午坐忘歸，不管風鬟露滿衣。", "橫玉三聲湖起浪，前山應有鵲驚飛。"]'),
('bfb9e9ba-a774-4164-ada4-8aaa4185fed0','李次山自畫兩圖其一泛舟湖山之下小女奴坐船頭吹笛其一跨馿渡小橋入深谷各題一絕  其二','范成大','宋','宋诗','song-poetry','','[]','黄塵車馬夢初闌，杳杳騎馿紫翠間。',32,'全唐诗/poet.song.137000.json','["黄塵車馬夢初闌，杳杳騎馿紫翠間。", "飽識千峰真面目，當年拄笏漫看山。"]'),
('9a852e5b-038f-45d5-b615-bdd2c34ed472','太傅楊和王輓歌詞二首  其一','范成大','宋','宋诗','song-poetry','','[]','先廟垂忠烈，孤童侈舊勳。',48,'全唐诗/poet.song.137000.json','["先廟垂忠烈，孤童侈舊勳。", "風雲天策府，心膂殿前軍。", "汴猘漸臺蹙，胡驕罽幕焚。", "人亡汗青在，足以詔無垠。"]'),
('ebb8c75e-1ed2-409f-a6d2-2533b4be2748','太傅楊和王輓歌詞二首  其二','范成大','宋','宋诗','song-poetry','','[]','歲與靈光晚，名登甲令芳。',48,'全唐诗/poet.song.137000.json','["歲與靈光晚，名登甲令芳。", "剖符山若礪，交戟鬢如霜。", "半世三槐位，千秋異姓王。", "哀榮公不憾，人自惜堂堂。"]'),
('485a6b2a-2f68-4946-ba33-090f9d3ac8eb','少卿直閣鄭公輓歌詞  其一','范成大','宋','宋诗','song-poetry','','[]','今代魁梧老，終身寂寞濱。',48,'全唐诗/poet.song.137000.json','["今代魁梧老，終身寂寞濱。", "鬢霜三館直，碑淚五州春。", "壽相空壬甲，行年竟巳辰。", "墳丘纔馬鬣，何處著經綸。"]'),
('3a2db660-89a0-4b76-b3d4-a4d4e64c6ee4','少卿直閣鄭公輓歌詞  其二','范成大','宋','宋诗','song-poetry','','[]','憶昨登門日，驩傳考室詩。',48,'全唐诗/poet.song.137000.json','["憶昨登門日，驩傳考室詩。", "謂公安且吉，何意哭於斯。", "遺老典刑盡，此邦名教悲。", "誰能傳耆舊，他日慰吳兒。"]'),
('20b79c46-60ab-42de-ae0e-32f5e55367d9','高景菴讀舊題有感','范成大','宋','宋诗','song-poetry','','[]','莓苔風雨舊詩留，十七年前鬢未秋。',32,'全唐诗/poet.song.137000.json','["莓苔風雨舊詩留，十七年前鬢未秋。", "巖桂拂雲篁竹拱，樹猶如此一搔頭。"]'),
('3a6f30a3-0c1b-427d-99d8-47e49949b336','華山道中','范成大','宋','宋诗','song-poetry','','[]','過午曾雲未肯開，暖寒村店竹初灰。',32,'全唐诗/poet.song.137000.json','["過午曾雲未肯開，暖寒村店竹初灰。", "蕭蕭林響棠梨戰，晚恐陽山有雨來。"]'),
('9a42cd84-5397-49c5-81c3-6de3cfbcbff5','送嚴子文通判建康','范成大','宋','宋诗','song-poetry','','[]','四海論交頼有子，一日不見真愁予。',64,'全唐诗/poet.song.137000.json','["四海論交頼有子，一日不見真愁予。", "人誰可與話心曲，天忽遣來同里居。", "懊惱春來不數面，丁寧歲晚猶頻書。", "黑頭屢別那敢惜，歎息駸駸霜滿梳。"]'),
('f8b37faf-0f2f-4fb1-ad69-4fc563afaa55','次韻王浚明詠新居木犀','范成大','宋','宋诗','song-poetry','','[]','月窟移來有貴名，一簾金碧照東榮。',64,'全唐诗/poet.song.137000.json','["月窟移來有貴名，一簾金碧照東榮。", "鼻端入妙睡魔醒，眼底會真詩句生。", "日氣瓏璁無奈醉，露華凌亂不勝清。", "君家傾國何時見，淡掃蛾眉撚夕陰。"]'),
('a1e2a56f-09af-4b93-be91-49bf5d9433c8','提刑察院王丈輓詞  其一','范成大','宋','宋诗','song-poetry','','[]','論蜀三年戍，還吳萬里船。',48,'全唐诗/poet.song.137000.json','["論蜀三年戍，還吳萬里船。", "雲歸雙節後，雪白短檠前。", "百世春秋傳，一丘陽羨田。", "浮生如此了，何必更凌煙。"]'),
('bbc90b66-3658-4562-bbf9-af0f0538e2ba','提刑察院王丈輓詞  其二','范成大','宋','宋诗','song-poetry','','[]','日者悲離索，公今又眇冥。',48,'全唐诗/poet.song.137000.json','["日者悲離索，公今又眇冥。", "門人辦韓集，子舍得韋經。", "此去念築室，空來聞過庭。", "平生無路見，終古泣松銘。"]'),
('5c7f57dd-3dd3-4cfe-8761-c99d919cc866','送關壽卿校書出守簡州','范成大','宋','宋诗','song-poetry','','[]','東壁星宮館列仙，一麾苦欲近田園。',64,'全唐诗/poet.song.137000.json','["東壁星宮館列仙，一麾苦欲近田園。", "宅家但寶千金鑑，臣輩何辭萬里船。", "京洛知心塵鞅裏，江吳携手暮帆邊。", "聲名如此歸安往，日日閶門望眼穿。"]'),
('437cb48a-0ea1-408c-bb50-e079ba12b2a0','頃自吏部郎去國時獨同舍趙友益追路送詩數月友益得儀真過吳江次元韻招之','范成大','宋','宋诗','song-poetry','','[]','東風分袂省西廊，袖有明珠照客航。',64,'全唐诗/poet.song.137000.json','["東風分袂省西廊，袖有明珠照客航。", "道義有情通出處，文章無地著炎凉。", "君今猶把一麾去，我敢倦鋤三徑荒。", "邂逅天涯如夢寐，肯來相對話更長。"]'),
('8686d95a-1f15-4d78-b8f8-0c40db60f68d','長沙王墓在閶門外','范成大','宋','宋诗','song-poetry','','[]','英雄轉眼逐東流，百戰工夫土一抔。',32,'全唐诗/poet.song.137000.json','["英雄轉眼逐東流，百戰工夫土一抔。", "蕎麥茫茫花似雪，牧童吹笛上高丘。"]'),
('598e09cb-4ff3-4811-aba6-3497d5be1224','次韻孫長文泊姑蘇館','范成大','宋','宋诗','song-poetry','','[]','讀書窗下一燈殘，忽有詩來爲暖寒。',32,'全唐诗/poet.song.137000.json','["讀書窗下一燈殘，忽有詩來爲暖寒。", "聞道扁舟春共載，雪雲雖冷不相干。"]'),
('c7f37fc8-b914-4034-b130-589e970a1ded','長文再作復次韻','范成大','宋','宋诗','song-poetry','','[]','渚蒲汀蓼得霜殘，歸客思家不計寒。',32,'全唐诗/poet.song.137000.json','["渚蒲汀蓼得霜殘，歸客思家不計寒。", "喜鵲門前人一笑，絕勝風色候長干。"]'),
('fb503314-e4ff-4799-90e4-21a58564820d','次韻耿時舉王直之夜坐','范成大','宋','宋诗','song-poetry','','[]','庭葉翻翻閙，燈花粟粟穠。',48,'全唐诗/poet.song.137000.json','["庭葉翻翻閙，燈花粟粟穠。", "關山千里鴈，風雨滿城鐘。", "隴上新登穀，江頭舊熄烽。", "今年吾計得，安穩讀三冬。"]'),
('c5d5cec3-d2ba-4e6d-b54a-97a551ae04fa','次韻徐子禮提舉鶑花亭  其一','范成大','宋','宋诗','song-poetry','','[]','灘長石出水鳴隄，城郭西頭舊小溪。',32,'全唐诗/poet.song.137000.json','["灘長石出水鳴隄，城郭西頭舊小溪。", "游子斷魂招不得，秋來春草更萋萋。"]'),
('cc460d2f-a4cb-40ae-9efa-31b138fc7880','次韻徐子禮提舉鶑花亭  其二','范成大','宋','宋诗','song-poetry','','[]','愁邊逢酒却成憎，衣带寬來不自勝。',32,'全唐诗/poet.song.137000.json','["愁邊逢酒却成憎，衣带寬來不自勝。", "煙水蒼茫外沙路，東風何處拄枯藤。"]'),
('58204594-6df9-4380-af8c-6168d43b9bff','次韻徐子禮提舉鶑花亭  其三','范成大','宋','宋诗','song-poetry','','[]','壚下三年世路窮，蟻封盤馬竟難工。',32,'全唐诗/poet.song.137000.json','["壚下三年世路窮，蟻封盤馬竟難工。", "千山雖隔日邊夢，猶到平陽池館中。"]'),
('01fddf74-af88-4325-af4d-9cf894561e2c','次韻徐子禮提舉鶑花亭  其四','范成大','宋','宋诗','song-poetry','','[]','文章光焰照金閨，豈是遭逢乏聖時。',32,'全唐诗/poet.song.137000.json','["文章光焰照金閨，豈是遭逢乏聖時。", "縱有百身那可贖，琳瑯空有萬篇垂。"]'),
('58d12a2b-1175-410d-8012-541dff02dfce','次韻徐子禮提舉鶑花亭  其五','范成大','宋','宋诗','song-poetry','','[]','山碧叢叢四打圍，煩將舊恨訪黄鸝。',32,'全唐诗/poet.song.137000.json','["山碧叢叢四打圍，煩將舊恨訪黄鸝。", "纈林霜後黄鸝少，須是愁紅萬點時。"]'),
('8f9a5cf6-ee26-4d0c-8bb1-cfd2d743cbf1','次韻徐子禮提舉鶑花亭  其六','范成大','宋','宋诗','song-poetry','','[]','古藤陰下醉中休，誰與低眉唱此愁。',32,'全唐诗/poet.song.137000.json','["古藤陰下醉中休，誰與低眉唱此愁。", "團扇他年書好句，平生知已識儋州。"]'),
('7fc14877-956f-4452-a5c7-3119fff6336a','己丑五月被召至行在遇周畏知司直和五年前送周歸弋陽韻見贈復次韻答之','范成大','宋','宋诗','song-poetry','','["\u897f\u6e56"]','分袂悠悠爾許年，莫嗔蓬鬢兩蕭然。',64,'全唐诗/poet.song.137000.json','["分袂悠悠爾許年，莫嗔蓬鬢兩蕭然。", "酒槽不奈青春老，經笥空供白晝眠。", "暗綠千章新活計，軟紅三尺舊塵緣。", "相逢且作西湖客，山繞荷花檥畫船。"]'),
('3247ba51-b24d-4011-be4c-23b7cb3442db','次韻馬少伊郁舜舉寄示同游石湖詩卷七首  其一','范成大','宋','宋诗','song-poetry','','[]','蕪城老蘚不知春，忽有柴門月色新。',32,'全唐诗/poet.song.137000.json','["蕪城老蘚不知春，忽有柴門月色新。", "芝草琅玕無鎖鑰，自無超俗扣門人。"]'),
('8eb8394c-25af-4ad5-b4ed-73f71c6712ac','次韻馬少伊郁舜舉寄示同游石湖詩卷七首  其二','范成大','宋','宋诗','song-poetry','','[]','莫問朝歌與棘津，浮生惟有一杯春。',32,'全唐诗/poet.song.137000.json','["莫問朝歌與棘津，浮生惟有一杯春。", "君看百戰功名地，越戍吳臺兩窖塵。"]'),
('b7f318f2-9799-407c-b282-430ef64caae8','次韻馬少伊郁舜舉寄示同游石湖詩卷七首  其三','范成大','宋','宋诗','song-poetry','','[]','鏡面波光倒碧峰，半湖雲錦萬芙蓉。',32,'全唐诗/poet.song.137000.json','["鏡面波光倒碧峰，半湖雲錦萬芙蓉。", "去年蕩槳香風裏，行傍石橋花正濃。"]'),
('c506a40c-5899-4c59-a963-851001604196','次韻馬少伊郁舜舉寄示同游石湖詩卷七首  其四','范成大','宋','宋诗','song-poetry','','[]','紅皺黄團熟暑風，甘瓜削玉藕玲瓏。',32,'全唐诗/poet.song.137000.json','["紅皺黄團熟暑風，甘瓜削玉藕玲瓏。", "身謀已落園丁後，滿帽京塵日正中。"]'),
('a8a271bd-0b10-4361-818f-2c8e4383064d','次韻馬少伊郁舜舉寄示同游石湖詩卷七首  其五','范成大','宋','宋诗','song-poetry','','[]','兩賢風度藹春陽，步屧隨風上柳塘。',32,'全唐诗/poet.song.137000.json','["兩賢風度藹春陽，步屧隨風上柳塘。", "綵筆紅牋芳徑裏，句中挾我萬花香。"]'),
('c5e759d5-8e61-4f79-8e0f-00dde52107b7','次韻馬少伊郁舜舉寄示同游石湖詩卷七首  其六','范成大','宋','宋诗','song-poetry','','[]','得得來題小隠詩，拂香縈柳畫船移。',32,'全唐诗/poet.song.137000.json','["得得來題小隠詩，拂香縈柳畫船移。", "湖邊好景春猶未，須到秋清月滿時。"]'),
('9c29129e-5910-4e89-bbdf-f57d6dc61f23','次韻馬少伊郁舜舉寄示同游石湖詩卷七首  其七','范成大','宋','宋诗','song-poetry','','[]','瀟灑王郎亦勝流，今年何事阻清遊。',32,'全唐诗/poet.song.137000.json','["瀟灑王郎亦勝流，今年何事阻清遊。", "當家風味今如此，孤負山陰夜雪舟。"]'),
('14832546-338d-4837-ada5-72792bf7c14f','玉堂寓直','范成大','宋','宋诗','song-poetry','','[]','摛文窗戶九霄中，岸幘燒香愧老農。',64,'全唐诗/poet.song.137000.json','["摛文窗戶九霄中，岸幘燒香愧老農。", "上直馬歸催下鑰，傳更人唱促鳴鐘。", "金城嶻嵲雲千雉，碧瓦參差月萬重。", "骨冷魂清都不夢，玉階蕭瑟聽秋蛩。"]'),
('66cd70cb-f5d9-4d0a-9fdc-c7b84e20531b','己丑中秋寓宿玉堂聞沈公雅大卿劉正夫戶部集張園賞月走筆寄之','范成大','宋','宋诗','song-poetry','','[]','笑看收雲捲雨忙，沉沉宮樹納空光。',64,'全唐诗/poet.song.137000.json','["笑看收雲捲雨忙，沉沉宮樹納空光。", "夜長來伴玉堂宿，天近似聞丹桂香。", "鳷鵲樓欄浮瑞氣，鳳凰城闕带新凉。", "遥知勝絕西園會，也憶車公對舉觴。"]'),
('12551529-89db-4527-81e9-14077b9fa1f5','八月二十二日寓直玉堂雨後頓凉','范成大','宋','宋诗','song-poetry','','[]','雨意蒸雲暗夕陽，濃薰滿院落花香。',32,'全唐诗/poet.song.137000.json','["雨意蒸雲暗夕陽，濃薰滿院落花香。", "題詩弄筆北窗下，將此工夫報答凉。"]'),
('17b60e03-a464-4944-9c41-d61dc491d02f','次韻答吳江周縣尉飲垂虹見寄','范成大','宋','宋诗','song-poetry','','[]','垂虹亭上角巾傾，鼉怒龍吟醉不聽。',64,'全唐诗/poet.song.137000.json','["垂虹亭上角巾傾，鼉怒龍吟醉不聽。", "安得對君浮大白，想應嗤我汗新青。", "夢魂舞蝶隨春草，時節賓鴻點暮汀。", "湖海扁舟須及健，莫教明月照星星。"]'),
('acb66adc-f891-4522-a67d-c9e9ee65e107','次韻徐廷獻機宜送自釀石室酒三首  其一','范成大','宋','宋诗','song-poetry','','[]','元亮折腰嘻已久，故山應有欲蕪田。',32,'全唐诗/poet.song.137000.json','["元亮折腰嘻已久，故山應有欲蕪田。", "因君辦作送酒客，憶我北窗清晝眠。"]'),
('777abc88-0947-49fd-8a82-8cf0ce10cf4c','次韻徐廷獻機宜送自釀石室酒三首  其二','范成大','宋','宋诗','song-poetry','','[]','清絕仍香如橘露，甘餘小苦似松肪。',32,'全唐诗/poet.song.137000.json','["清絕仍香如橘露，甘餘小苦似松肪。", "官槽重濁那知此，付與街頭白面郎。"]'),
('ea3513ce-2c55-4ad5-bfc1-18562158e857','次韻徐廷獻機宜送自釀石室酒三首  其三','范成大','宋','宋诗','song-poetry','','[]','一語爲君評石室，三杯便可博凉州。',32,'全唐诗/poet.song.137000.json','["一語爲君評石室，三杯便可博凉州。", "百年兀兀同渠住，何處能生半點愁。"]'),
('f8688523-6787-401e-b9e6-a6128b438721','玉堂寓直曉起書事記直舍老兵語','范成大','宋','宋诗','song-poetry','','[]','江湖垂釣手，天漢摛文堂。',84,'全唐诗/poet.song.137000.json','["江湖垂釣手，天漢摛文堂。", "魂清不得眠，室虛自生光。", "曉緯澹天闕，江濤隠胡牀。", "傳呼九門開，奔走千官忙。", "若若誇組綬，紛紛夢黄粱。", "微聞鈴下騶，竊議馬上郎。", "但計夢長短，寧論己行藏。"]'),
('f70e4aca-49bc-4a6f-8c19-1bdf7352ca9f','與長文正夫游北山','范成大','宋','宋诗','song-poetry','','[]','柳岸松門勝處通，馬蹄踏霧入空濛。',64,'全唐诗/poet.song.137000.json','["柳岸松門勝處通，馬蹄踏霧入空濛。", "春寒有力欺遊子，天色無情沒斷鴻。", "雨脚遠連山脚暗，杏梢斜倚竹梢紅。", "駞裘擁鼻吾衰矣，年少猶嫌料峭風。"]'),
('69cda6f1-80f7-4d76-b0d8-4e126daba27e','致政承奉盧君輓詞二首  其一','范成大','宋','宋诗','song-poetry','','[]','泮水橋門識太平，歸來霜鬢老柴荆。',64,'全唐诗/poet.song.137000.json','["泮水橋門識太平，歸來霜鬢老柴荆。", "淹中學邃方成傳，谷口名高豈待卿。", "黄壤無情埋玉樹，青衫有道勝金籯。", "襄陽耆舊今蕭索，惟有松風到晚清。"]'),
('01141b28-dc80-4779-9c89-44d82fb917d1','致政承奉盧君輓詞二首  其二','范成大','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','純孝當年有護持，赤眉那敢近姜詩。',64,'全唐诗/poet.song.137000.json','["純孝當年有護持，赤眉那敢近姜詩。", "眼看庭玉成名後，身及堂萱未老時。", "湖海青鞵驚斷夢，風霜丹旐挂新悲。", "尊前五客今誰在，愁絕廬山十段奇。"]'),
('3c2b43a9-0bbc-4f44-8516-c47cb62f0ce3','寓直玉堂拜賜御酒','范成大','宋','宋诗','song-poetry','','[]','歸鴉陸續墮宮槐，簾幙參差晚不開。',64,'全唐诗/poet.song.137000.json','["歸鴉陸續墮宮槐，簾幙參差晚不開。", "小雨遂將秋色至，長風時送市聲來。", "近瞻北斗璿璣次，猶夢西山翠碧堆。", "慚愧君恩來甲夜，殿頭宣勸紫金杯。"]'),
('785354c5-9f9e-4e20-b7f6-9533240ba738','送汪仲嘉侍郎使虜分韻得待字','范成大','宋','宋诗','song-poetry','','[]','聖人坐明堂，洪覆等穹蓋。',120,'全唐诗/poet.song.137000.json','["聖人坐明堂，洪覆等穹蓋。", "歲頒兩玉節，前後歌出塞。", "公才有廊廟，安用試專對。", "要煩第一人，鎮撫大荒外。", "嫩寒欺別酒，微月見征旆。", "遥知燕山雪，飄灑漢冠佩。", "玉色照穹廬，驕子亦心醉。", "要領一笑得，歸來安鼎鼐。", "是時春正佳，湖上花如海。", "清遊不可遲，日日檥船待。"]'),
('7f4f4631-c3c4-4946-a8b1-8a54ae5da2ec','李翬知縣作亭西湖上余用東坡語名之曰飲綠遂爲勝概','范成大','宋','宋诗','song-poetry','','["\u897f\u6e56"]','芷葺蓮巢喚客遊，蘆鞭席帽爲君留。',64,'全唐诗/poet.song.137000.json','["芷葺蓮巢喚客遊，蘆鞭席帽爲君留。", "未論吹水堪添酒，且要移牀學枕流。", "乍霽却陰梅釀雨，暫暄還冷麥催秋。", "石湖也似西湖好，煩向蒼煙問白鷗。"]'),
('19bb128f-b879-4b17-b430-dd52b4129705','草蟲扇','范成大','宋','宋诗','song-poetry','','[]','莫嫌絡緯股鳴悲，解向寒窗促曉機。',32,'全唐诗/poet.song.137000.json','["莫嫌絡緯股鳴悲，解向寒窗促曉機。", "海眼多花無藉在，顛狂只待學于飛。"]'),
('30e58873-5b0e-4319-9c78-24daadaa18f2','送汪仲嘉待制奉祠歸四明分韻得論字','范成大','宋','宋诗','song-poetry','','[]','丹霄碧海眇高鶱，厭直承明却自論。',64,'全唐诗/poet.song.137000.json','["丹霄碧海眇高鶱，厭直承明却自論。", "寶馬十年聽漏箭，扁舟一雨看潮痕。", "侍臣相憶松門遠，歸客還憐菊徑存。", "清潤要非山澤相，又煩一札下雲根。"]'),
('d792c015-4e55-488f-b469-efd81fa77c04','魯如晦郎中輓詞二首  其一','范成大','宋','宋诗','song-poetry','','[]','術業推游刃，功名苦溯洄。',48,'全唐诗/poet.song.137000.json','["術業推游刃，功名苦溯洄。", "著鞭孤壯志，籌算老奇才。", "星省龐眉去，雲山袖手來。", "知公了時命，何必誄餘哀。"]'),
('ded2b754-4341-42ac-b52e-1c25f72a6ff8','魯如晦郎中輓詞二首  其二','范成大','宋','宋诗','song-poetry','','[]','自古歸來引，于今遂隠篇。',48,'全唐诗/poet.song.137000.json','["自古歸來引，于今遂隠篇。", "碁燈熒夜觀，歌板聒春船。", "陳迹空華似，佳城露草邊。", "寂寥雞黍約，望眼一潸然。"]'),
('a43d9672-004e-4b49-8627-f243471c51aa','初約鄰人至石湖','范成大','宋','宋诗','song-poetry','','[]','窈窕崎嶇學種園，此生丘壑是前緣。',64,'全唐诗/poet.song.137000.json','["窈窕崎嶇學種園，此生丘壑是前緣。", "隔籬日上浮天水，當戶山橫匝地煙。", "春入葑田蘆綻筍，雨傾沙岸竹垂鞭。", "荒寒未辦招君醉，且吸湖光當酒泉。"]'),
('0e0856f8-79bf-4c2f-b107-7e507782b21c','社日獨坐','范成大','宋','宋诗','song-poetry','','[]','海棠雨後沁臙脂，楊柳風前撚綠絲。',32,'全唐诗/poet.song.137000.json','["海棠雨後沁臙脂，楊柳風前撚綠絲。", "香篆結雲深院靜，去年今日燕來時。"]'),
('0c33b3aa-42a2-461b-be1c-180b7bd6835e','與周子充侍郎同宿石湖','范成大','宋','宋诗','song-poetry','','[]','幽香馥蕙帳，清夢安且吉。',84,'全唐诗/poet.song.137000.json','["幽香馥蕙帳，清夢安且吉。", "蘿月墮蒼茫，松風隠蕭瑟。", "曉禽啄且鳴，喚我起盥櫛。", "鈎窗納雲濤，灧灧浴初日。", "金鉦忽騰上，倒景落書帙。", "佳晴有新課，曬種催藝秫。", "從今不得閒，東臯草過膝。"]'),
('6203998e-e96b-4390-a859-deece33fe53d','和周子充侍郎見寄樂府戲贈之作','范成大','宋','宋诗','song-poetry','','[]','釣海風水急，登樓塵霧高。',48,'全唐诗/poet.song.137000.json','["釣海風水急，登樓塵霧高。", "不如岸綸巾，春船携小橋。", "芳草含奇薰，光景上東壁。", "桂林那辦此，辦作安昌客。"]'),
('10f7b952-0a19-4d7b-a115-c1ee2ac6ab23','壬辰三月十八日石湖花下作','范成大','宋','宋诗','song-poetry','','[]','夜飲海棠月，朝漱山茶露。',96,'全唐诗/poet.song.137000.json','["夜飲海棠月，朝漱山茶露。", "臞儒槁木形，受用侈如許。", "荆扉隔黄塵，誰識花島路。", "惟有瘦筇枝，共飽園中趣。", "林神釀餘春，政爾美無度。", "葱蘢千萬重，芳意未渠暮。", "風香薦秀色，鼎俎謝腥腐。", "雖無稻粱謀，捫腹有餘飫。"]'),
('fda0b077-382b-4b66-aaf9-b455ab208b92','刈麥行','范成大','宋','宋诗','song-poetry','','[]','菊花開時我種麥，桃李花飛麥叢碧。',64,'全唐诗/poet.song.137000.json','["菊花開時我種麥，桃李花飛麥叢碧。", "多病經旬不出門，東陂已作黄雲色。", "腰鐮刈熟趁晴歸，明朝雨來麥沾泥。", "犁田待雨插晚稻，朝出移秧夜食麨。"]'),
('d0d91aaa-750b-439e-9ba0-a0431a6b8a21','壬辰天申節赴平江錫燕因懷去年以侍臣攝事捧御盃殿上賦二小詩  其一','范成大','宋','宋诗','song-poetry','','[]','去歲排場德壽宮，薰風披拂酒鱗紅。',32,'全唐诗/poet.song.137000.json','["去歲排場德壽宮，薰風披拂酒鱗紅。", "小臣供奉金龍盞，親到虛皇玉座東。"]'),
('e17c79b4-cfd5-4304-9ccb-177ed70d40ae','壬辰天申節赴平江錫燕因懷去年以侍臣攝事捧御盃殿上賦二小詩  其二','范成大','宋','宋诗','song-poetry','','[]','天中繖動玉輿來，萬歲三聲徹九街。',32,'全唐诗/poet.song.137000.json','["天中繖動玉輿來，萬歲三聲徹九街。", "想見牙牀當殿過，舜裳雲委拜堯階。"]'),
('c325ea04-0ef4-43aa-b2f3-7cb6e4f179e9','壬辰七月十六日侵晨真率會石湖路中書事','范成大','宋','宋诗','song-poetry','','[]','白葛烏紗稱老農，溪南溪北水車風。',32,'全唐诗/poet.song.137000.json','["白葛烏紗稱老農，溪南溪北水車風。", "稻頭的皪粘朝露，步入明珠翠網中。"]'),
('b8d19676-13ca-457b-97a0-465d2a568c9d','次韻施進之惠紫芝朮','范成大','宋','宋诗','song-poetry','','[]','山精媒長生，仙理信可詰。',60,'全唐诗/poet.song.137000.json','["山精媒長生，仙理信可詰。", "梨棗本寓言，杞菊亦凡質。", "幽人愛臞儒，藥鼎薦珍物。", "絕粒謝煙火，耘苗換肌骨。", "摩挲萊蕪甑，塵生不須拂。"]'),
('4cda160c-d90e-4b42-9925-8cc9d34aee09','題醉道士圖','范成大','宋','宋诗','song-poetry','','[]','蜩鷃鵬鵾任過前，壺中春色甕中天。',32,'全唐诗/poet.song.137000.json','["蜩鷃鵬鵾任過前，壺中春色甕中天。", "朝來兀兀三杯後，且作人間有漏仙。"]'),
('33eef722-e601-4c76-a85f-2293ae2141c1','五雜組四首  其一','范成大','宋','宋诗','song-poetry','','[]','五雜組，同心結。',24,'全唐诗/poet.song.137000.json','["五雜組，同心結。", "往復來，當窗月。", "不得已，話離別。"]'),
('4e3f866e-0182-4c1f-97b6-08b19304566b','五雜組四首  其二','范成大','宋','宋诗','song-poetry','','[]','五雜組，流蘇縷。',24,'全唐诗/poet.song.137000.json','["五雜組，流蘇縷。", "往復來，臨行語。", "不得已，上馬去。"]'),
('72095f48-b608-43bc-a6f5-7edbc2642131','五雜組四首  其三','范成大','宋','宋诗','song-poetry','','[]','五雜組，回文機。',24,'全唐诗/poet.song.137000.json','["五雜組，回文機。", "往復來，錦梭飛。", "不得已，獨畫眉。"]'),
('b7f69e5d-89a0-47b7-954e-d27606c07534','五雜組四首  其四','范成大','宋','宋诗','song-poetry','','[]','五雜組，綵絲鍼。',24,'全唐诗/poet.song.137000.json','["五雜組，綵絲鍼。", "往復來，鳥投林。", "不得已，夢孤衾。"]'),
('83fb2814-f435-42a3-9957-78f1b157cf71','兩頭纖纖二首  其一','范成大','宋','宋诗','song-poetry','','[]','兩頭纖纖探官繭，半白半黑鶴氅緣。',32,'全唐诗/poet.song.137000.json','["兩頭纖纖探官繭，半白半黑鶴氅緣。", "腷腷膊膊上帖箭，磊磊落落封侯面。"]'),
('16378220-47cf-4ee1-99e3-a3b06a666086','兩頭纖纖二首  其二','范成大','宋','宋诗','song-poetry','','[]','兩頭纖纖小秤衡，半白半黑月未明。',32,'全唐诗/poet.song.137000.json','["兩頭纖纖小秤衡，半白半黑月未明。", "腷腷膊膊扣戶聲，磊磊落落金盤冰。"]'),
('6897fee2-262f-4a12-97ca-ce6fcdda1be5','再賦五雜組四首  其一','范成大','宋','宋诗','song-poetry','','[]','五雜組，綬若若。',24,'全唐诗/poet.song.137000.json','["五雜組，綬若若。", "往復來，大車鐸。", "不得已，去丘壑。"]'),
('816a081f-c7b0-4499-b373-3b80fd92c7ae','再賦五雜組四首  其二','范成大','宋','宋诗','song-poetry','','[]','五雜組，侯門戟。',24,'全唐诗/poet.song.137000.json','["五雜組，侯門戟。", "往復來，道上檄。", "不得已，天涯客。"]'),
('944620bb-0f32-424a-8eec-40c5524edd74','再賦五雜組四首  其三','范成大','宋','宋诗','song-poetry','','[]','五雜組，漢旌旆。',24,'全唐诗/poet.song.137000.json','["五雜組，漢旌旆。", "往復來，賓鴻字。", "不得已，餐氈使。"]'),
('c745e0c5-c27b-47ba-9cb4-f68a1c6fb2c7','再賦五雜組四首  其四','范成大','宋','宋诗','song-poetry','','[]','五雜組，非煙雲。',24,'全唐诗/poet.song.137000.json','["五雜組，非煙雲。", "往復來，朝馬塵。", "不得已，嬰龍鱗。"]'),
('96dd03e1-e543-4ef0-95be-b9742e737559','夜坐聽雨','范成大','宋','宋诗','song-poetry','','[]','四檐密密又疎疎，聲到蒲團醉夢蘇。',32,'全唐诗/poet.song.137000.json','["四檐密密又疎疎，聲到蒲團醉夢蘇。", "恰似秋眠天竺寺，東軒窗外聽跳珠。"]'),
('13a8e60b-c789-4191-a94b-b1b97471e859','寒夜獨步中庭','范成大','宋','宋诗','song-poetry','','[]','忍寒索句踏霜行，刮面風來鬚結冰。',32,'全唐诗/poet.song.137000.json','["忍寒索句踏霜行，刮面風來鬚結冰。", "倦僕觸屏呼不應，梅花影下一窗燈。"]'),
('84ac211e-4a4c-4b5e-888c-d0412a421bff','會散夜步','范成大','宋','宋诗','song-poetry','','[]','忘却下樓扶我誰，接䍦顛倒酒沾衣。',32,'全唐诗/poet.song.137000.json','["忘却下樓扶我誰，接䍦顛倒酒沾衣。", "貪看雪樣滿街月，不上籃輿步砌歸。"]'),
