('49e803ec-be92-41bf-9fa1-b7bfec4abd7a','臨洺鎮','范成大','宋','宋诗','song-poetry','','[]','竟日霜寒暮解圍，融融桑柘染斜暉。',32,'全唐诗/poet.song.137000.json','["竟日霜寒暮解圍，融融桑柘染斜暉。", "北人爭勸臨洺酒，云有棚頭得兔歸。"]'),
('095c1489-ce3d-47f3-beb9-bd4df82f4eaf','邢臺驛','范成大','宋','宋诗','song-poetry','','[]','太行東麓照邢州，萬疊煙螺紫翠浮。',32,'全唐诗/poet.song.137000.json','["太行東麓照邢州，萬疊煙螺紫翠浮。", "誰解登臨管風物，枯荷老柳替人愁。"]'),
('ecdb629e-7c69-4a1b-b73d-52aecd4f5d37','柳公亭','范成大','宋','宋诗','song-poetry','','[]','主人敬客有餘情，催喚繩牀坐柳亭。',32,'全唐诗/poet.song.137000.json','["主人敬客有餘情，催喚繩牀坐柳亭。", "曲水流觴非故物，馬鞍山色舊青青。"]'),
('306c4bf8-3cfd-47a5-8a0a-b5df2fd81c80','內丘梨園','范成大','宋','宋诗','song-poetry','','[]','汗後鵝梨爽似冰，花身耐久老猶榮。',32,'全唐诗/poet.song.137000.json','["汗後鵝梨爽似冰，花身耐久老猶榮。", "園翁指似還三笑，曾共翁身見太平。"]'),
('8b00243f-2688-46d7-a837-f94d4ea95b12','大寧河','范成大','宋','宋诗','song-poetry','','[]','梨棗從來數內丘，大寧河畔果園稠。',32,'全唐诗/poet.song.137000.json','["梨棗從來數內丘，大寧河畔果園稠。", "荆箱擾擾攔街賣，紅皺黄團滿店頭。"]'),
