('7a44fc34-ec85-4df0-8de5-351019f993e1','定興','范成大','宋','宋诗','song-poetry','','[]','新城遷次少人煙，桑柘中間井徑寒。',32,'全唐诗/poet.song.137000.json','["新城遷次少人煙，桑柘中間井徑寒。", "亦有染人來賣纈，淡紅深碧挂長竿。"]'),
('e8be5bca-8b81-4964-acde-056e9ed84a9a','清遠店','范成大','宋','宋诗','song-poetry','','[]','女僮流汗逐氈軿，云在淮鄉有父兄。',32,'全唐诗/poet.song.137000.json','["女僮流汗逐氈軿，云在淮鄉有父兄。", "屠婢殺奴官不問，大書黥面罰猶輕。"]'),
('fa96e17a-6cfa-4dcf-b7ec-9135c44c33fd','琉璃河','范成大','宋','宋诗','song-poetry','','[]','煙林葱蒨带回塘，橋眼驚人失睡鄉。',32,'全唐诗/poet.song.137000.json','["煙林葱蒨带回塘，橋眼驚人失睡鄉。", "健起褰帷揩病眼，琉璃河上看鴛鴦。"]'),
('e4234af3-9081-4355-9950-d7c4e02ebb86','灰洞','范成大','宋','宋诗','song-poetry','','[]','塞北風沙漲帽檐，路經灰洞十分添。',32,'全唐诗/poet.song.137000.json','["塞北風沙漲帽檐，路經灰洞十分添。", "據鞍莫問塵多少，馬耳冥濛不見尖。"]'),
('4e483688-29ca-4c1a-b9ff-32df384bc84a','良鄉','范成大','宋','宋诗','song-poetry','','[]','新寒凍指似排籤，村酒雖酸未可嫌。',32,'全唐诗/poet.song.137000.json','["新寒凍指似排籤，村酒雖酸未可嫌。", "紫爛山梨紅皺棗，總輸易栗十分甜。"]'),
('e5cf83dc-5cde-4a9b-b53e-762c5c9c12d5','盧溝','范成大','宋','宋诗','song-poetry','','[]','草草魚梁枕水低，匆匆小駐濯漣漪。',32,'全唐诗/poet.song.137000.json','["草草魚梁枕水低，匆匆小駐濯漣漪。", "河邊服匿多生口，長記軺車放鴈時。"]'),
('3df889ca-54d2-43ed-9fec-38a5e4ef8a67','燕賓館','范成大','宋','宋诗','song-poetry','','[]','九日朝天種落驩，也將佳節勸杯盤。',32,'全唐诗/poet.song.137000.json','["九日朝天種落驩，也將佳節勸杯盤。", "苦寒不似東籬下，雪滿西山把菊看。"]'),
('56fd8e03-a4d3-4715-8985-d99e4f739e1a','橙綱','范成大','宋','宋诗','song-poetry','','[]','堯舜方堪橘柚包，穹廬亦復使民勞。',32,'全唐诗/poet.song.137000.json','["堯舜方堪橘柚包，穹廬亦復使民勞。", "華清荔子沾恩幸，一騎回時萬騎騷。"]'),
('4d512f79-75cd-46a7-a173-e40d227689af','蹋鴟巾','范成大','宋','宋诗','song-poetry','','[]','重譯知書自貴珍，一生心愧蹋鴟巾。',32,'全唐诗/poet.song.137000.json','["重譯知書自貴珍，一生心愧蹋鴟巾。", "雨中折角君何愛，帝有衣裳易介鱗。"]'),
('02e92a84-db69-42bf-826a-240439028066','耶律侍郎','范成大','宋','宋诗','song-poetry','','[]','乍見華書眼似麞，低頭慚愧紫荷囊。',32,'全唐诗/poet.song.137000.json','["乍見華書眼似麞，低頭慚愧紫荷囊。", "人間無事無奇對，伏獵今成兩侍郎。"]'),
('4f29c46d-f28e-40e8-a8e4-6a62eccab12b','龍津橋','范成大','宋','宋诗','song-poetry','','[]','燕石扶欄玉作堆，柳塘南北抱城迴。',32,'全唐诗/poet.song.137000.json','["燕石扶欄玉作堆，柳塘南北抱城迴。", "西山剩放龍津水，留待官軍飲馬來。"]'),
('12e2de78-364d-49c3-bd53-a10b0be4b81a','燕宮','范成大','宋','宋诗','song-poetry','','[]','金盆濯足段文昌，乞索家風飽便忘。',32,'全唐诗/poet.song.137000.json','["金盆濯足段文昌，乞索家風飽便忘。", "他日楚人能一炬，又從焦土說阿房。"]'),
('83d874fe-a022-4030-a02f-3abed51c0df7','會同館','范成大','宋','宋诗','song-poetry','','[]','萬里孤臣致命秋，此身何止一漚浮。',32,'全唐诗/poet.song.137000.json','["萬里孤臣致命秋，此身何止一漚浮。", "提携漢節同生死，休問羝羊解乳不。"]'),
('db866602-3ca2-4d7e-aff6-202d56ebb9c7','與吳興薛士隆使君遊弁山石林先生故居','范成大','宋','宋诗','song-poetry','','[]','白蘋有嘉招，蒼弁得勝踐。',144,'全唐诗/poet.song.137000.json','["白蘋有嘉招，蒼弁得勝踐。", "會心不憚遠，乘興恐失便。", "籃輿犯窮臘，共作忍寒面。", "溟濛雲釀雪，浩蕩風落鴈。", "松篁漸清幽，猿鶴或悲怨。", "英英文章公，作舍鎖葱蒨。", "嶢峰俯前榮，佳木秀諸院。", "窮搜發山骨，林立侍談讌。", "西巖踞熊虎，東巖峙屏案。", "履綦故仿佛，蓋瓦已零亂。", "經營三十年，成毀一飛電。", "摩挲土花碧，小立爲三歎。"]'),
('dffbaced-3e29-4acf-8e86-92f10eedf7d3','自石林回過小玲瓏巖竇益奇昔爲富人吳氏所有今一子尚幼山檢校於官','范成大','宋','宋诗','song-poetry','','[]','一丘乃中虛，洞穴四無礙。',144,'全唐诗/poet.song.137000.json','["一丘乃中虛，洞穴四無礙。", "却略巖岫杳，黝糾石牀怪。", "蒼牛飲前池，碧罅灧微瀨。", "雕鎪具百巧，圖畫窘千態。", "哀湍寫壞磴，凍雨濕空翠。", "疎梅照草棘，瘦竹拔蹊隧。", "當時閭閻子，目力在塵外。", "孤童藐難料，奇事疑有待。", "誰歟千金捐，來換把茅蓋。", "不仙亦足豪，衆垤皆累塊。", "我評北山遊，勝絕此無對。", "玲瓏詎可小，孰能爲之大。"]'),
('6f6637f7-1a6e-46fb-9bb0-daabf23c6bfe','濯纓亭在吳興南門外','范成大','宋','宋诗','song-poetry','','[]','淒風急雨脫然晴，當道橫山似見迎。',32,'全唐诗/poet.song.137000.json','["淒風急雨脫然晴，當道橫山似見迎。", "野水茫茫何用許，爛供遊子濯塵纓。"]'),
('4e2319f9-dae7-42eb-abf7-caf6876d9475','乾道己丑守括被召再過釣臺自和十年前小詩刻之柱間後五年自西掖帥桂林癸巳元日雪晴復過之再用舊韻三絕  其一','范成大','宋','宋诗','song-poetry','','[]','浮生渺渺但飛埃，問訊星宮又獨來。',32,'全唐诗/poet.song.137000.json','["浮生渺渺但飛埃，問訊星宮又獨來。", "天上人間最高處，爲君題作鬰蕭臺。"]'),
('4da99d03-49d2-427d-a17d-31fc07edb07f','乾道己丑守括被召再過釣臺自和十年前小詩刻之柱間後五年自西掖帥桂林癸巳元日雪晴復過之再用舊韻三絕  其二','范成大','宋','宋诗','song-poetry','','[]','拙疎何計補涓埃，慚愧雙旌去復來。',32,'全唐诗/poet.song.137000.json','["拙疎何計補涓埃，慚愧雙旌去復來。", "三過溪門今老矣，病無脚力更登臺。"]'),
('c5a9eac4-9274-4a0a-ac03-42df140fce64','乾道己丑守括被召再過釣臺自和十年前小詩刻之柱間後五年自西掖帥桂林癸巳元日雪晴復過之再用舊韻三絕  其三','范成大','宋','宋诗','song-poetry','','[]','界天山雪浄黄埃，溪上扁舟夜汎來。',32,'全唐诗/poet.song.137000.json','["界天山雪浄黄埃，溪上扁舟夜汎來。", "匝地東風勸椒酒，山頭今日是春臺。"]'),
('f9a00208-6add-45fa-8f50-8ec5d10b8449','玉山道中','范成大','宋','宋诗','song-poetry','','[]','常山多清溪，玉山富喬木。',48,'全唐诗/poet.song.137000.json','["常山多清溪，玉山富喬木。", "行色鬰蒼然，頗亦慰愁目。", "梅花隔籬見，瓏璁照茅屋。", "晚來風刮地，想見飄香玉。"]'),
('be0f814e-304a-49ff-a024-80bffb1c5597','桃花壇下望龜峰','范成大','宋','宋诗','song-poetry','','[]','石壇無土謾嶔岑，何自能生小柏林。',32,'全唐诗/poet.song.137000.json','["石壇無土謾嶔岑，何自能生小柏林。", "擬擘蛤蜊龜殻上，病來不殺懶登臨。"]'),
('61104c91-7595-4906-bf88-71093deecb71','清音堂與趙德莊太常小飲在餘干琵琶洲傍洲以形似得名','范成大','宋','宋诗','song-poetry','','[]','曲浦彎環繞縣青，一盃閒客兩飄零。',32,'全唐诗/poet.song.137000.json','["曲浦彎環繞縣青，一盃閒客兩飄零。", "琵琶不語蒼煙暮，山水清音著意聽。"]'),
('57c883bf-f710-41e4-9bef-cd3d6b24abc2','過鄱陽湖次游子明韻','范成大','宋','宋诗','song-poetry','','[]','春工釀雪無端密，大塊囊風不肯收。',64,'全唐诗/poet.song.137000.json','["春工釀雪無端密，大塊囊風不肯收。", "休問巉巖與欹側，我今弟靡共波流。", "野鷹兀兀平沙上，折葦蕭蕭古渡頭。", "滿眼荒寒底處所，令人腸斷五湖舟。"]'),
('34d7025c-761c-4e2d-ad49-c105b7b5b542','豫章南浦亭泊舟二首  其一','范成大','宋','宋诗','song-poetry','','[]','繡檻臨滄渚，牙檣插暮沙。',48,'全唐诗/poet.song.137000.json','["繡檻臨滄渚，牙檣插暮沙。", "浦雲沉斷鴈，江雨入昏鴉。", "野曠天何近，春寒歲未華。", "來朝風一席，隨處且浮家。"]'),
('96538ad0-fdd2-45a0-bee8-50b08bb0812c','豫章南浦亭泊舟二首  其二','范成大','宋','宋诗','song-poetry','','[]','閏歲花光晚，霜朝草色荒。',48,'全唐诗/poet.song.137000.json','["閏歲花光晚，霜朝草色荒。", "趁墟猶市井，收潦再耕桑。", "客路東西懶，江流日夜忙。", "長歌情不盡，一酌酹滄浪。"]'),
('e913ff16-8a3f-4f59-ae50-e7c9c9d16e59','清江道中橘園甚夥','范成大','宋','宋诗','song-poetry','','[]','芳林不斷清江曲，倒影入江江水綠。',64,'全唐诗/poet.song.137000.json','["芳林不斷清江曲，倒影入江江水綠。", "未論萬戶比封君，瓦屋人家衣食足。", "暑風汎花蘭芷香，秋日籬落明青黄。", "客舟來遲佳景盡，但見碧樹愁春霜。"]'),
('5e7bf2f6-698a-4b9a-82b0-2e5de2a18ffa','清江臺在臨江郡圃西岡上張安國題榜','范成大','宋','宋诗','song-poetry','','[]','南來富壽岡，形勝此蟠結。',96,'全唐诗/poet.song.137000.json','["南來富壽岡，形勝此蟠結。", "岑竮戴高臺，欄檻了風月。", "蕭灘曳長煙，閤皂炯殘雪。", "江流當带橫，練綀浮木末。", "天風來無鄉，萬里吹醉纈。", "登臨信奇事，忍凍亦癡絕。", "故人春夢覺，遺墨秋蛇掣。", "浮雲真可咍，揮觶酹空闊。"]'),
('6759f3b0-df5f-4cb7-ac65-fb3433b3b42a','自冬徂春道中多雨至臨江宜春之間特甚遂作苦語','范成大','宋','宋诗','song-poetry','','[]','客行無晴時，涔涔如漏天。',144,'全唐诗/poet.song.137000.json','["客行無晴時，涔涔如漏天。", "東吳至西江，舊歲接新年。", "蠟屐驚踵決，油衣笑鶉懸。", "掀淖起復仆，頃步如重關。", "略似鴨與豬，汩沒泥水闌。", "我塗未渠窮，一晴愧天慳。", "倒塔橋已斷，壁破渡無船。", "路人相告語，未到先長歎。", "薄晚得磽确，稍入袁州山。", "不辭石齧足，聊免泥沒韉。", "自古行路吟，聽者凋朱顔。", "軒渠尚能賦，詩人類癡頑。"]'),
('99b71b31-5cec-424b-93d6-b8a9420e1b40','玉虛觀去宜春二十五里許君上升時飛白茅數葉以賜王長史王以宅爲觀觀旁至今有仙茅極異常草備五味尤辛辣云久食可仙道士煮湯以設客','范成大','宋','宋诗','song-poetry','','[]','白雲堆裏白茅飛，香味芳辛勝五芝。',32,'全唐诗/poet.song.137000.json','["白雲堆裏白茅飛，香味芳辛勝五芝。", "揉葉煮泉摩腹去，全勝石髓畏風吹。"]'),
('8b8b6e20-9d4f-4240-aaab-8876653db808','入分宜','范成大','宋','宋诗','song-poetry','','[]','新喻渡無橋，分宜橋有欄。',48,'全唐诗/poet.song.137000.json','["新喻渡無橋，分宜橋有欄。", "孰歟兩徼吏，賢否已判然。", "堂上著威信，四郊如目前。", "入國政可知，茲焉略闚觀。"]'),
('9f2a7e2c-2a77-410d-afdb-822a44ddef58','方竹杖','范成大','宋','宋诗','song-poetry','','[]','竹君箇箇面團團，此士剛方獨凜然。',32,'全唐诗/poet.song.137000.json','["竹君箇箇面團團，此士剛方獨凜然。", "外貌中心俱壁立，任從癡子削教圓。"]'),
('cd8f0d28-d693-4b0b-b388-8d1d05eb2f1f','游仰山謁小釋迦塔訪孚惠二王遺蹟贈長老混融','范成大','宋','宋诗','song-poetry','','[]','堵田溪淵清洄洄，梅洲問路寒雲堆。',192,'全唐诗/poet.song.137000.json','["堵田溪淵清洄洄，梅洲問路寒雲堆。", "連空磴道虬尾滑，竹輿直上無梯階。", "蒼官來迎夾道立，相逢無言心眼開。", "翠微中斷雪磵吼，兩耳不辦供喧豗。", "林間靜極成斷相，政要萬壑號風雷。", "山如蓮盆繞金地，龍官避席餘蒼崖。", "祖師抱膝坐古塔，大禪海浪翻天來。", "騰空狡獪我未暇，拄杖踏濕撞莓苔。", "問龍亦借一席地，解包聽雨眠西齋。", "當年公案忌錯舉，神通佛法同坑埋。", "混融庵中的的意，笑我舌本空崔巍。", "茲事且置飽喫飯，稊田米賤如黄埃。"]'),
('ebd37f8f-ac7d-4825-be58-47d7d21f043a','大雨宿仰山翌旦驟霽混融云無乃開仰山之雲乎出山道中作此寄混融','范成大','宋','宋诗','song-poetry','','["\u8861\u5c71"]','誰開大仰雲，此豈吾力及。',156,'全唐诗/poet.song.137000.json','["誰開大仰雲，此豈吾力及。", "日光千丈毫，彈指衆峰立。", "衡山捲陰氣，海市發冬蟄。", "韓蘇兩枯魚，出語自濡濕。", "人厄與天窮，底用苦封執。", "但喜拄杖俊，仍欣芒屩澀。", "向來三尺泥，有足似羈馽。", "龍淵古橋皴，獺徑寒溜泣。", "春淺山容瘦，風饕澗聲急。", "一簞寄前村，野䔩旋收拾。", "貓頭髠筍尖，雀舌剝茶粒。", "土毛冠江西，斗酒況可挹。", "聊同一笑粲，緩賦百憂集。"]'),
('b7955f7e-d21d-4526-ac83-76fc71998ba7','初入湖南醴陵界','范成大','宋','宋诗','song-poetry','','[]','崖樹陰陰夾暝途，出山歡喜見平蕪。',32,'全唐诗/poet.song.137000.json','["崖樹陰陰夾暝途，出山歡喜見平蕪。", "一春客夢飽風雨，行盡江南聞鷓鴣。"]'),
('92f41f99-9bc0-4c64-bae5-823f7062a4e7','醴陵驛','范成大','宋','宋诗','song-poetry','','[]','綠水橋通縣，門前柳已黄。',48,'全唐诗/poet.song.137000.json','["綠水橋通縣，門前柳已黄。", "人稀山木壽，土瘦水泉香。", "乍脫泥中滑，還嗟堠子長。", "櫧洲何日到，鼓枻上滄浪。"]'),
('27ccf7e1-a579-461d-a4e7-b08a8ac0f1a8','湘潭道中詠芳草','范成大','宋','宋诗','song-poetry','','[]','積雨倏然晴，秀野若新沐。',48,'全唐诗/poet.song.137000.json','["積雨倏然晴，秀野若新沐。", "芳草徑寸姿，中有不勝綠。", "萋萋路傍情，頗亦念幽獨。", "驅馬去不顧，斷腸招隠曲。"]'),
('df7ce869-2173-4f77-bdc8-feefcc398899','初見山花','范成大','宋','宋诗','song-poetry','','[]','三日晴泥尚沒鞾，幾將風雨過年華。',32,'全唐诗/poet.song.137000.json','["三日晴泥尚沒鞾，幾將風雨過年華。", "湘東二月春纔到，恰有山櫻一樹花。"]'),
('1de4436a-795b-488e-8e90-81a7d2f42afa','櫧洲道中','范成大','宋','宋诗','song-poetry','','[]','煙凝山如影，雲褰日射毫。',48,'全唐诗/poet.song.137000.json','["煙凝山如影，雲褰日射毫。", "桃間紅樹迥，麥裏綠叢高。", "客子歎游倦，田家甘作勞。", "乘除吾尚可，未擬賦離騷。"]'),
('5d569ccc-1b94-4106-bf7a-9d42b3a9c682','浮湘行','范成大','宋','宋诗','song-poetry','','[]','湘山中間湘水橫，綠蘋葉齊春漲生。',176,'全唐诗/poet.song.137000.json','["湘山中間湘水橫，綠蘋葉齊春漲生。", "盤渦沄沄去無聲，吾乘桂舟泝中𤃩。", "揚波擊汰雙櫓獰，轆轤引笮如牛鳴。", "篙師絕叫疊鼓轟，潛魚跳奔乳猿驚。", "暖煙浮空晝夢騰，山長水遠天無情。", "吹簫拊瑟弔湘靈，水妃風御繽來迎。", "問客良苦遠征行，昨者斧鉞下青冥。", "命我盡護安南兵，嶺海一視如王庭。", "布蕩陽春濯腐腥，王事靡盬來有程。", "匪躬之故惟爾甿，芳洲杜若空青青。", "九歌淒悲不可聽，願賡楚調歸和平。"]'),
('b53a3940-dfc7-46f2-97c7-01d13ff03dec','湘江洲尾快風挂帆','范成大','宋','宋诗','song-poetry','','[]','船頭雪浪吼奔雷，十丈高帆滿意開。',64,'全唐诗/poet.song.137000.json','["船頭雪浪吼奔雷，十丈高帆滿意開。", "我自只憑忠信力，風應不爲世情來。", "兒童屢惜峰巒過，將士猶教鼓笛催。", "明日祝融天柱去，更煩先捲亂雲堆。"]'),
('af84b636-ddae-4852-9cf8-1797fda602bd','泊湘江魚口灘','范成大','宋','宋诗','song-poetry','','[]','知時社燕語檣竿，游子奔波自鮮歡。',64,'全唐诗/poet.song.137000.json','["知時社燕語檣竿，游子奔波自鮮歡。", "趁客賣魚雙槳急，隔林沽酒小旗寒。", "瀟湘渾似日南落，嶽麓已從天外看。", "薄暮灘前收百丈，卧聞三老報平安。"]'),
('89ef07bc-5274-4543-843b-7124757be26a','謁南嶽','范成大','宋','宋诗','song-poetry','','["\u8861\u5c71"]','湘中固多山，夾岸萬馬屯。',288,'全唐诗/poet.song.137000.json','["湘中固多山，夾岸萬馬屯。", "坡陀無敢高，似遜喬嶽尊。", "曉投望雲亭，衆丘拱牆藩。", "濃嵐忽飄蕩，積翠浮雲端。", "天柱已峻極，祝融更高寒。", "紫蓋鬰當中，岡勢洶崩奔。", "峙爲赤帝峰，下直宮壖垣。", "角樓捧雙闕，圓方模九閽。", "炎符撫中興，南正實司天。", "草木薰協氣，山林奠神姦。", "妥靈有備物，龍卷鸞旗軒。", "走忝桂林伯，與神俱南轅。", "上謁禮亦宜，爲國憂元元。", "心空禍福相，古井寒無瀾。", "杯珓不用擲，但願歸田園。", "相傳壁畫好，拂拭塵埃昏。", "弓刀立壯士，劍珮班靈官。", "後宮行樂處，窈窕千雲鬟。", "錦地舞月晝，珠櫳侍春閑。", "武氏筆已絕，梗概猶清妍。", "旋車闔廟去，頗厭山市喧。", "勝果招客遊，徑排集賢關。", "梵庋絢雜組，錫杖鏘古鐶。", "避雨勝業閣，晚晴留憑欄。"]'),
('85915a9e-efa2-4c21-9132-442e87e57317','兩蟲','范成大','宋','宋诗','song-poetry','','[]','鷓鴣憂兄行不得，杜宇勸客不如歸。',32,'全唐诗/poet.song.137000.json','["鷓鴣憂兄行不得，杜宇勸客不如歸。", "天涯羈思難繪畫，惟有兩蟲相發揮。"]'),
('03a1d497-b219-43c3-b948-f9a4c5987179','衡陽道中二絕  其一','范成大','宋','宋诗','song-poetry','','[]','桑下蕪菁晚，高花出短籬。',24,'全唐诗/poet.song.137000.json','["桑下蕪菁晚，高花出短籬。", "茅簷少春事，惟記浴蠶時。"]'),
('44453bb5-cf1b-4b60-8f7a-768a7ce8e6b4','衡陽道中二絕  其二','范成大','宋','宋诗','song-poetry','','[]','黑羖鑽籬破，花豬突戶開。',24,'全唐诗/poet.song.137000.json','["黑羖鑽籬破，花豬突戶開。", "空山竹瓦屋，猶有燕飛來。"]'),
('f6476f1a-d97a-451f-aef5-d72553667882','衡州石鼓書院','范成大','宋','宋诗','song-poetry','','[]','古磴浮滄渚，新黌鎖碧蘿。',48,'全唐诗/poet.song.137000.json','["古磴浮滄渚，新黌鎖碧蘿。", "要津山獨立，巨壑水同波。", "俎豆彌文肅，衣冠盛事多。", "地靈鍾傑俊，寧但拾儒科。"]'),
('5cbc0d25-7c76-4c0b-8e82-f5714eb8484c','合江亭','范成大','宋','宋诗','song-poetry','','[]','石鼓鬰嵯峨，截然踞滄洲。',132,'全唐诗/poet.song.137000.json','["石鼓鬰嵯峨，截然踞滄洲。", "有如古盟主，勤王會諸侯。", "蒸湘伯叔國，稟命會葵丘。", "敢不承載書，戮力朝宗周。", "混爲同軌去，崩奔不敢留。", "宜哉百谷王，博大無與儔。", "氈毳昔亂華，車馬隔中州。", "未聞齊晉勳，包茅費誅求。", "威文亦弘規，尚取童子羞。", "安知千載後，但泣新亭囚。", "我題石鼓詩，願言續春秋。"]'),
('18baafbd-bebe-4b47-a348-29bca5f3b685','沈家店道傍棣棠花','范成大','宋','宋诗','song-poetry','','[]','乍晴芳草競懷新，誰種幽花隔路塵。',32,'全唐诗/poet.song.137000.json','["乍晴芳草競懷新，誰種幽花隔路塵。", "綠地縷金羅結带，爲誰開放可憐春。"]'),
('59a7da1b-9be8-4569-bb67-712d3c79b377','邵陽口路粗惡積雨餘濘難行','范成大','宋','宋诗','song-poetry','','[]','平生春夢境，俛仰撫八極。',96,'全唐诗/poet.song.137000.json','["平生春夢境，俛仰撫八極。", "湖南天盡頭，夢亦未常識。", "豈知多病身，今乃著脚歷。", "山泉澄不清，崖土璺而赤。", "坳堂滑勝油，累塊硬逾石。", "貪夫一回顧，壯士三歎息。", "不知清淑氣，果復曾鬰積。", "我豈鄙夷之，短咏聊一劇。"]'),
('ca3e7875-0f23-4245-8b14-d4b52fb8fc35','馬鞍驛飯罷縱步','范成大','宋','宋诗','song-poetry','','[]','食飽倦輿馬，散策步前岡。',72,'全唐诗/poet.song.137000.json','["食飽倦輿馬，散策步前岡。", "意行踏芳草，蕭艾蓊生香。", "春事甚寂寥，山桃带松篁。", "游蜂入菜花，此豈堪蜜房。", "今年蠶出遲，柘葉分寸長。", "好晴纔數日，歲事未渠央。"]'),
('cebf87b0-d8eb-4387-ba79-e4f21f172b36','黄羆嶺','范成大','宋','宋诗','song-poetry','','[]','薄遊每違己，茲行遂登危。',156,'全唐诗/poet.song.137000.json','["薄遊每違己，茲行遂登危。", "峻阪盪胸立，恍若對鏡窺。", "傳呼半空響，濛濛上煙霏。", "木末見前驅，可望不可追。", "躋攀百千盤，有頃身及之。", "白雲叵攬擷，但覺沾人衣。", "高木傲燒痕，葱蘢茁新荑。", "春禽斷不到，惟有蜀魄啼。", "謂非人所寰，居然見鋤犁。", "山農如木客，上下翾以飛。", "寧知有康莊，生死安嶮巇。", "室屋了無處，恐尚橧巢栖。", "安得拔汝出，王路方清夷。"]'),
('10711aa5-7979-42df-8585-532ef4f1f610','衡永之間山路艱澀薄晚吏卒鬨云漸近祁陽路已平夷皆有津津之色','范成大','宋','宋诗','song-poetry','','[]','朝登赤土嶺，暮入黄泥谷。',132,'全唐诗/poet.song.137000.json','["朝登赤土嶺，暮入黄泥谷。", "春江弄花月，歸夢恍在目。", "覺來行路難，杜宇叫高木。", "凹中泥沒踝，凸處石齧足。", "坐輿我尚病，想見肩輿僕。", "衡陽復祁陽，可暫不可宿。", "晚來出前岡，路坦亭堠促。", "將士走相賀，喜色如膏沐。", "人生本無悶，逆境要先熟。", "不從憂患來，安識平爲福。", "夷塗不常遇，歷險始知足。"]'),
('d590be21-abac-4da0-ad7d-f177863fbdc2','書浯溪中興碑後','范成大','宋','宋诗','song-poetry','','[]','三頌遺音和者希，丰容寧有刺譏辭。',64,'全唐诗/poet.song.137000.json','["三頌遺音和者希，丰容寧有刺譏辭。", "絕憐元子春秋法，都寓唐家清廟詩。", "歌詠當諧琴搏拊，策書自管璧瑕疵。", "紛紛健筆剛題破，從此磨崖不是碑。"]'),
('a765c192-e45f-4da4-bdf4-ce9823715ff1','愚溪在零陵城對岸渡江即至溪甚狹一石澗耳蓋衆山之水流出湘中','范成大','宋','宋诗','song-poetry','','[]','一水彎環羅带闊，千古零陵擅風月。',128,'全唐诗/poet.song.137000.json','["一水彎環羅带闊，千古零陵擅風月。", "取名如許安得愚，因病成妍却奇絕。", "至今鏡浄不可唾，猶恐先生遺翰墨。", "澤及溪流不庇身，付與後來商巧拙。", "我欲扁舟窮石澗，春漲未生寒瀨咽。", "紛紅駭綠四山空，惟有風篁韻騷屑。", "清溪東去客西征，鈷鉧潭邊聊駐節。", "何時隨汝下瀟湘，歸路三千櫓伊軋。"]'),
('d0b70953-0039-41c3-a5e3-cc66cd130480','宿清湘城外田家','范成大','宋','宋诗','song-poetry','','[]','驅馬力猶彊，奏牀身始疲。',48,'全唐诗/poet.song.137000.json','["驅馬力猶彊，奏牀身始疲。", "浮浮雲拂帳，潏潏水鳴籬。", "未熟燈前夢，閑尋道上詩。", "湘中多夜雨，客枕最先知。"]'),
('abd83d10-3dd4-4811-bf4c-e5c167a2778c','宿深溪驛去廣右界只一程','范成大','宋','宋诗','song-poetry','','[]','北戶書頻到，南雲鴈不飛。',48,'全唐诗/poet.song.137000.json','["北戶書頻到，南雲鴈不飛。", "試評騎馬路，何似釣魚磯。", "擊柝黄茅店，篝燈白竹扉。", "故園桑柘暖，亦有稻粱肥。"]'),
('8e196f57-f461-4cc2-9fef-85d2e9ce545f','晚春二首  其一','范成大','宋','宋诗','song-poetry','','[]','靜極聞檐珮，慵來愛枕幃。',48,'全唐诗/poet.song.137000.json','["靜極聞檐珮，慵來愛枕幃。", "隙虹飛永晝，簾影碎斜暉。", "燕踏花枝語，蜂縈柳絮歸。", "輕颸宜白紵，時節近清微。"]'),
('89f1010f-1a66-49ea-ac70-ec002b65e349','晚春二首  其二','范成大','宋','宋诗','song-poetry','','[]','好事憐春老，無愁耐日長。',48,'全唐诗/poet.song.137000.json','["好事憐春老，無愁耐日長。", "爐煙驚扇影，酒面舞花光。", "照水雲容嬾，移牀竹意凉。", "更煩紅槿帽，促拍打山香。"]'),
('6bdc8d00-3d88-4443-abb3-ade2f0a444a9','紅豆蔻花','范成大','宋','宋诗','song-poetry','','[]','綠葉焦心展，紅苞竹籜披。',48,'全唐诗/poet.song.137000.json','["綠葉焦心展，紅苞竹籜披。", "貫珠垂寶珞，剪綵倒鸞枝。", "且入花欄品，休論藥裹宜。", "南方草木狀，爲爾首題詩。"]'),
('c551bfc5-4c54-47b6-8986-0a5adbd6bdf1','偶題','范成大','宋','宋诗','song-poetry','','[]','檐雨初乾團扇風，夕陽芳樹綠葱葱。',32,'全唐诗/poet.song.137000.json','["檐雨初乾團扇風，夕陽芳樹綠葱葱。", "蕉心榴萼俱無頼，要與春衫相並紅。"]'),
('bd7794c5-1051-4851-b02c-8717cd04fccd','次韻郭季勇機宜雪觀席上留別','范成大','宋','宋诗','song-poetry','','[]','勝絕尊前萬事休，縱非吾土且登樓。',64,'全唐诗/poet.song.137000.json','["勝絕尊前萬事休，縱非吾土且登樓。", "山迎雨脚俄飛過，風約江聲欲倒流。", "野水漸堪添酒面，夕陽依舊滿簾鈎。", "憑闌從此遲歸鞅，能及中秋對月不。"]'),
('1953d28f-9672-46c9-9317-0078da874f31','次韻許季韶通判雪觀席上','范成大','宋','宋诗','song-poetry','','[]','把酒臨風瑞露傾，瓊漿何用謁雲英。',64,'全唐诗/poet.song.137000.json','["把酒臨風瑞露傾，瓊漿何用謁雲英。", "捲簾雨脚銀絲挂，倚杖江頭綠漲生。", "嶺海一凉蘇暑病，山林千籟試秋聲。", "茲遊奇絕忘羈宦，慚愧煙中短棹橫。"]'),
('7c182dbe-b662-4b3f-bfef-3e7d95f7193b','送周直夫教授歸永嘉','范成大','宋','宋诗','song-poetry','','[]','青燈相對話儒酸，老去羈遊自鮮歡。',64,'全唐诗/poet.song.137000.json','["青燈相對話儒酸，老去羈遊自鮮歡。", "昨夜榕溪三寸雨，今朝桂嶺十分寒。", "知心海內向來少，解手天涯良獨難。", "一笑不須論聚散，少焉吾亦跨歸鞍。"]'),
('006be608-f26f-4b35-8c90-7c76d65cc1f7','贈趙廉州','范成大','宋','宋诗','song-poetry','','[]','馬羣雜沓草蒙茸，刮目權奇一洗空。',64,'全唐诗/poet.song.137000.json','["馬羣雜沓草蒙茸，刮目權奇一洗空。", "天末也煩行李到，歲寒聊得酒尊同。", "梅花夜夜湘南雨，榕葉年年海北風。", "少待佳晴看山去，玉篸高插翠雲叢。"]'),
('ccf86c3b-6e71-43a3-95e3-8b26f30fb356','去年過弋陽訪趙恂道通判話西湖舊遊因題小詩近忽刻石寄來謾錄','范成大','宋','宋诗','song-poetry','','["\u897f\u6e56"]','紅塵寶馬碧湖船，一夢如今費十年。',32,'全唐诗/poet.song.137000.json','["紅塵寶馬碧湖船，一夢如今費十年。", "却照清溪尋綠鬢，但餘衰雪兩蕭然。"]'),
('8e27f0e8-add8-4bb7-bc48-e834c93b0b55','送唐彥博宰安豐兼寄呈淮西帥趙渭師郎中','范成大','宋','宋诗','song-poetry','','[]','唐子皦自鮮，水清石粼粼。',120,'全唐诗/poet.song.137000.json','["唐子皦自鮮，水清石粼粼。", "繡腸五車書，不鄙簿領塵。", "黟山與桂嶺，一笑二十春。", "天涯會面難，歲晚情話真。", "五管無賢侯，但有嵐煙昏。", "此豈功名場，往戍清淮濱。", "北門詩書帥，平生吾故人。", "問訊今何如，凌煙上星辰。", "爲言落南客，病作寒螿呻。", "飄飄北歸夢，夜繞吳淞雲。"]'),
('8b13d505-16be-4d6a-844b-14d37fb4169a','燕堂後盧橘一株冬前先開極香','范成大','宋','宋诗','song-poetry','','[]','盧橘花殘細細飛，滿枝晴日閙蜂兒。',32,'全唐诗/poet.song.137000.json','["盧橘花殘細細飛，滿枝晴日閙蜂兒。", "霜餘有此香無奈，合與稱題賦小詩。"]'),
('7e3d2ecb-5f72-42e7-9285-3ad8601ad0d7','乾道癸巳臘後二日桂林大雪尺餘郡人云前此未省見也郭季勇機宜賦古風爲賀次其韻','范成大','宋','宋诗','song-poetry','','[]','憶昔北征秋遇雪，穹廬苦寒不堪說。',256,'全唐诗/poet.song.137000.json','["憶昔北征秋遇雪，穹廬苦寒不堪說。", "飛花如席暗燕然，把酒悲歌度佳節。", "胡兒館客類西河，鐍戶不容浮蟻泄。", "當時已分餐氈莩，寧復夢遊炎嶺熱。", "忽逐梅花行萬里，又與故山輕話別。", "天公恐我愁瘴霧，十日號風吹石裂。", "同雲乃肯度嚴關，一夜玉峰高嶻嵲。", "老榕蓊密最先縞，穉竹枵虛時一折。", "須知桂海接蓬瀛，滿目三山白銀闕。", "不管樓高翠袖單，但嫌酒淺金杯凸。", "東郭先生履雖敝，詩情却鬭冰壺潔。", "歸撚凍髭搜好句，山館青燈對明滅。", "爲憐叶氣到黄茅，何止森森松柏悅。", "豐年作守會飽暖，羈宦思歸自愁絕。", "豈無菊徑樂琴書，亦有秫田供麴糵。", "東岡雪後一犁春，誰在陂頭憶調燮。"]'),
('3878a731-b0eb-4dea-bdb7-b9766f11d296','次韻陳仲思經屬西峰觀雪','范成大','宋','宋诗','song-poetry','','[]','仙人灕江遊，剪水馮夷宮。',120,'全唐诗/poet.song.137000.json','["仙人灕江遊，剪水馮夷宮。", "賓友來鄒枚，寒轡搖冬瓏。", "起望天南陲，玉沙滿長風。", "越人來省識，把酒酹層空。", "從來嶠南北，人謂將無同。", "那知梁園霰，飛入瑞露中。", "幕府有清士，尋僧上西峰。", "六花信娟巧，未及五字工。", "我亦滌冰硯，課虛貴新功。", "莫嗤兩臞儒，毫端尚清豐。"]'),
('2e9ad0fc-9623-4d2f-8575-c0b713b4c657','喜雪示桂人','范成大','宋','宋诗','song-poetry','','[]','臘雪同雲嶺外稀，南人北客盡冬衣。',32,'全唐诗/poet.song.137000.json','["臘雪同雲嶺外稀，南人北客盡冬衣。", "從今老杜詩猶信，梅片飛時雪也飛。"]'),
('f7881acc-2f9f-45a7-ad07-363f83a7b83e','寄題商華叔心遠堂用卷中韻','范成大','宋','宋诗','song-poetry','','[]','示我新詩卷，知君遯俗情。',48,'全唐诗/poet.song.137000.json','["示我新詩卷，知君遯俗情。", "安流視巫峽，灰劫笑昆明。", "徽外夜絃語，甕頭春蟻生。", "藍橋即仙窟，何況有雲英。"]'),
('3888a17d-efbc-46f8-90b2-dbb01ff51e1d','送郭季勇同年歸衡山','范成大','宋','宋诗','song-poetry','','["\u8861\u5c71"]','天壤郭有道，文獻今在茲。',168,'全唐诗/poet.song.137000.json','["天壤郭有道，文獻今在茲。", "啄啄家雞羣，見子野鶴姿。", "塵籠萬里心，擇食中夜饑。", "拙宦避捷徑，瘴風吹鬢絲。", "平生杏園友，把酒天南陲。", "何敢吏朱浮，但喜見紫芝。", "問君今何適，舊圃餘荒畦。", "提携漢陰甕，歲晚俱忘機。", "勿開衡山雲，恐驚隠淪棲。", "定肯從君遊，歲晚攀桂枝。", "我亦理吳榜，春湘綠蘋齊。", "風蒲爲誰落，之子同襟期。", "丁寧祝融峰，將迎兩枯藜。", "一望五千里，共洗蠻煙悲。"]'),
('c3a9efea-81b0-411f-9544-29ea80667fe6','甲午歲朝寓桂林記去年是日泊桐江謁嚴子陵祠迤邐度嶺感懷賦詩','范成大','宋','宋诗','song-poetry','','[]','去年曉纜解江臯，也把屠蘇泛濁醪。',64,'全唐诗/poet.song.137000.json','["去年曉纜解江臯，也把屠蘇泛濁醪。", "一席飽風漁浦闊，千山封雪釣臺高。", "將軍老矣鳴孤劍，客子歸哉咏大刀。", "早晚扁舟尋舊路，柁樓吹笛破雲濤。"]'),
('32d1fb46-2e3e-4481-a770-3de1f8a4b83c','癸水亭落成示坐客長老之記曰癸水繞東城永不見刀兵余作亭於水上其詳具記中','范成大','宋','宋诗','song-poetry','','[]','天將福地鞏嚴城，形勝山川表裏明。',64,'全唐诗/poet.song.137000.json','["天將福地鞏嚴城，形勝山川表裏明。", "舊說桂林無瘴氣，今知灕水辟刀兵。", "雲深銅柱邊聲樂，月冷珠池海面平。", "願挽江流接河漢，爲君直北洗欃槍。"]'),
('a1b45d5f-4d15-4211-befa-51f1465e544a','緩带軒獨坐','范成大','宋','宋诗','song-poetry','','[]','午日烘開豆蔻苞，檐塵飛動雀爭巢。',32,'全唐诗/poet.song.137000.json','["午日烘開豆蔻苞，檐塵飛動雀爭巢。", "蒙蒙困眼無安處，閒送爐煙到竹梢。"]'),
('8a5317c3-0112-4ad3-bc04-069a17da05d3','食罷書字','范成大','宋','宋诗','song-poetry','','[]','甲子霖涔雨，東南濕蟄風。',48,'全唐诗/poet.song.137000.json','["甲子霖涔雨，東南濕蟄風。", "荔枝梅子綠，豆蔻杏花紅。", "捫腹蠻茶快，扶頭老酒中。", "荒隅經歲客，土俗漸相通。"]'),
('544cba30-114e-4ec9-afb4-1eff5d463208','次韻平江韓子師侍郎見寄三首  其一','范成大','宋','宋诗','song-poetry','','[]','自古四愁湘水深，誰將城郭啟山林。',64,'全唐诗/poet.song.137000.json','["自古四愁湘水深，誰將城郭啟山林。", "有情碧嶂團欒繞，無數朱樓縹緲臨。", "蚺鼓揭天驚客坐，象鍪航海厭蠻琛。", "三千客路長安遠，故舊書來直萬金。"]'),
('9849b47e-898c-4528-ad60-faa367518d03','次韻平江韓子師侍郎見寄三首  其二','范成大','宋','宋诗','song-poetry','','[]','靈泉杖屨浙江頭，經濟長懷尚典州。',64,'全唐诗/poet.song.137000.json','["靈泉杖屨浙江頭，經濟長懷尚典州。", "堂上讀書朝氣爽，臺前呼月海光浮。", "交情尺素勤雙鯉，筆力枯松挽萬牛。", "已把三章翻樂府，爲君擊節變蠻謳。"]'),
('c185f050-2504-4e8e-8f17-892036142c4c','次韻平江韓子師侍郎見寄三首  其三','范成大','宋','宋诗','song-poetry','','[]','前年衝雪過雙溪，風帽泥韉騎吹隨。',64,'全唐诗/poet.song.137000.json','["前年衝雪過雙溪，風帽泥韉騎吹隨。", "爛醉依前逢錦瑟，好音惟是欠黄鸝。", "功名未試玉璜玦，離別頻傾金屈巵。", "疇昔北征煩吉夢，南征合有夢歸時。"]'),
('bb6a5bdb-7985-4390-a1f0-d1c284ad83c0','宜齋雨中','范成大','宋','宋诗','song-poetry','','[]','秀麥一番冷，送梅三日霖。',48,'全唐诗/poet.song.137000.json','["秀麥一番冷，送梅三日霖。", "綠肥新荔子，紅浥舊蕉心。", "映竹千絲舞，垂檐一線斟。", "終朝盤膝坐，卑濕恐相侵。"]'),
('01d827bb-89e3-47ac-aa36-65f1d9fed880','次韻許季韶通判水鄉席上','范成大','宋','宋诗','song-poetry','','[]','青山綠浦竹間明，彷彿苕溪好處行。',64,'全唐诗/poet.song.137000.json','["青山綠浦竹間明，彷彿苕溪好處行。", "解慍風來如故舊，催詩雨作要將迎。", "休兵幕府烏鳶樂，熟稻邊城鼓笛聲。", "摹寫箇中須綵筆，句成仍挾水雲清。"]'),
('d741520b-483e-4ebb-8114-6a61e6f54185','水鄉酌別但能之主管能之將過石康','范成大','宋','宋诗','song-poetry','','[]','南郭河橋市井喧，綠荷香處有江天。',64,'全唐诗/poet.song.137000.json','["南郭河橋市井喧，綠荷香處有江天。", "一簾梅雨爐煙外，三疊陽關燭淚前。", "馬耳西風君並海，船頭北渚我歸田。", "後期只恐參商似，且醉金槽四十絃。"]'),
('f76d7243-89fd-44d5-8da8-46dfe5918db4','六月十五日夜汎西湖風月溫麗','范成大','宋','宋诗','song-poetry','','["\u897f\u6e56"]','暮檥金龜潭，追隨今夕凉。',120,'全唐诗/poet.song.137000.json','["暮檥金龜潭，追隨今夕凉。", "波紋挾月影，搖蕩舞船窗。", "夜久四山高，松桂黯以蒼。", "長煙界巖腹，浮空餘劍鋩。", "棹夫三弄笛，跳魚翻素光。", "我亦醉夢驚，解纓濯滄浪。", "多情芙蕖風，嫋嫋吹鬢霜。", "會心有奇賞，天涯此何方。", "清潤不立塵，空明滿生香。", "過清難久留，俛俯墮渺茫。"]'),
('b99fdfb1-ad34-4d97-bc68-fd17bfa35918','燕堂書事','范成大','宋','宋诗','song-poetry','','[]','歲稔齋鈴閴，年深屋塈摧。',48,'全唐诗/poet.song.137000.json','["歲稔齋鈴閴，年深屋塈摧。", "狸爭雷瓦過，螘化雨窗來。", "盡日風常籟，無時地不梅。", "耳邊情話少，笑口若爲開。"]'),
('8852e7b7-9244-4bed-bdcf-b9020b8e8a1a','酒邊二絕  其一','范成大','宋','宋诗','song-poetry','','[]','團扇香中嫋嫋風，斷腸聲裏看羞紅。',32,'全唐诗/poet.song.137000.json','["團扇香中嫋嫋風，斷腸聲裏看羞紅。", "不須過處催乾盞，聽徹歌頭盞自空。"]'),
('4a2e1579-c152-4a9e-b1b4-74e2d8baa7be','酒邊二絕  其二','范成大','宋','宋诗','song-poetry','','[]','日長繡倦酒紅潮，閒束羅巾理六么。',32,'全唐诗/poet.song.137000.json','["日長繡倦酒紅潮，閒束羅巾理六么。", "新樣築毬花十八，丁寧小玉慢吹簫。"]'),
('ab6468b8-c07d-4509-83a1-519432637f1d','枕上作','范成大','宋','宋诗','song-poetry','','[]','繞枕蚊相聒，翻釭鼠自忙。',48,'全唐诗/poet.song.137000.json','["繞枕蚊相聒，翻釭鼠自忙。", "早衰秋夢亂，不寢曉更長。", "賦擬騷人屈，吟成病客莊。", "安心無可覓，隨處且爲鄉。"]'),
('4bc2ee9b-0233-4b43-8b5f-53769aae5612','思歸再用枕上韻','范成大','宋','宋诗','song-poetry','','[]','老覺觸事懶，病添歸計忙。',48,'全唐诗/poet.song.137000.json','["老覺觸事懶，病添歸計忙。", "行年心已化，疇昔意空長。", "五柳栗里宅，百花錦城莊。", "何時去檢校，一棹水雲鄉。"]'),
('493a4d00-afc9-4522-beaa-d7269c5a8771','李正之提點行至郴用予忙字韻寄和答','范成大','宋','宋诗','song-poetry','','[]','天涯逢我病，秋晚送君忙。',48,'全唐诗/poet.song.137000.json','["天涯逢我病，秋晚送君忙。", "感慨交情厚，留連別恨長。", "賓筵猶雪觀，客路已雲莊。", "搖落郴江路，應須憶醉鄉。"]'),
('4f63131d-8d19-455c-b53c-80d5f84fb0cb','曉出北郊','范成大','宋','宋诗','song-poetry','','[]','偪仄深巷中，葱蘢綠陰交。',96,'全唐诗/poet.song.137000.json','["偪仄深巷中，葱蘢綠陰交。", "山家不早起，閉戶如藏逃。", "濃露蛻蟬咽，小風饑燕高。", "新渠厪涓流，壞陂方怒號。", "遐甿病瘠土，不肯昏作勞。", "滅裂復滅裂，晚秧如牛毛。", "空餘朝氣白，浮浮濕弓刀。", "官稱勸農使，臨風首頻搔。"]'),
('e780957a-91b1-448d-a4f5-e56375859399','甘雨應祈三絕  其一','范成大','宋','宋诗','song-poetry','','[]','晚稻成苞未肯肥，鵓鳩啼曉雨來時。',32,'全唐诗/poet.song.137000.json','["晚稻成苞未肯肥，鵓鳩啼曉雨來時。", "黄紬被冷初眠覺，先向芭蕉葉上知。"]'),
('d541015c-0962-419e-a74e-15994ef911cd','甘雨應祈三絕  其二','范成大','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','數日雖蒙霢霂霑，浥塵終恨太廉纖。',32,'全唐诗/poet.song.137000.json','["數日雖蒙霢霂霑，浥塵終恨太廉纖。", "今朝健起巡檐看，恰似廬山看水簾。"]'),
('07f63b65-4614-4d05-bd3d-4c59e10f51c4','甘雨應祈三絕  其三','范成大','宋','宋诗','song-poetry','','[]','高田一雨免飛埃，上水綱船亦可催。',32,'全唐诗/poet.song.137000.json','["高田一雨免飛埃，上水綱船亦可催。", "說與東江津吏道，打量今晚漲痕來。"]'),
('37688505-6cfd-428b-b361-ecd3b3fd6d07','與鄭少融趙養民二使者訪古訾家洲歸憩松關二君欲助力興廢戲書此付長老善良以當疏頭','范成大','宋','宋诗','song-poetry','','[]','飄飄竹雨潤輕裘，嫋嫋松風繫小舟。',32,'全唐诗/poet.song.137000.json','["飄飄竹雨潤輕裘，嫋嫋松風繫小舟。", "安得從容興廢手，越人重上訾家洲。"]'),
('36eb0859-438b-4fb2-a368-d66c3e6306aa','淳熙甲午桂林鹿鳴燕輒賦小詩少見勸駕之意','范成大','宋','宋诗','song-poetry','','[]','維南吾國最多儒，聳看招招赴隴書。',64,'全唐诗/poet.song.137000.json','["維南吾國最多儒，聳看招招赴隴書。", "竹實秋風辭穴鳳，桃花春浪脫淵魚。", "月宮移種新栽桂，江水朝宗舊鑿渠。", "況有狀頭坊井上，明年應表第三閭。"]'),
('fc03ffcc-4e6d-4f2c-a79d-b524d29ec0df','逍遥樓席上贈張邦達教授張癸未省闈門生也同年進士俱會樓上者七人','范成大','宋','宋诗','song-poetry','','[]','疇昔金門看選賢，一星終矣半英躔。',64,'全唐诗/poet.song.137000.json','["疇昔金門看選賢，一星終矣半英躔。", "誰憐蠻府清池句，不著南山捷徑鞭。", "作者七人茅瘴地，肅霜九月菊殘天。", "浮生聚散如風雨，同倚東樓豈偶然。"]'),
('724a5756-34bd-45f7-9182-a6d2e38e5f6a','畫工李友直爲余作冰天桂海二圖冰天畫使北虜渡黄河時桂海畫游佛子巖道中也戲題','范成大','宋','宋诗','song-poetry','','[]','許國無功浪著鞭，天教飽識漢山川。',64,'全唐诗/poet.song.137000.json','["許國無功浪著鞭，天教飽識漢山川。", "酒邊蠻舞花低帽，夢裏胡笳雪沒韉。", "收拾桑榆身老矣，追隨萍梗意茫然。", "明朝重上歸田奏，更放岷江萬里船。"]'),
('018c645a-aaf9-4521-bd17-f67bfe166be6','耳鳴戲題','范成大','宋','宋诗','song-poetry','','[]','歷歷從何起，泠泠與耳謀。',48,'全唐诗/poet.song.137000.json','["歷歷從何起，泠泠與耳謀。", "人言衰相現，我以妄心求。", "遠磬山房夜，寒蜩隴樹秋。", "圓通無別法，但自此根修。"]'),
('b3c66576-46ba-44f9-9988-1f2a6de60dda','復作耳鳴二首  其一','范成大','宋','宋诗','song-poetry','','[]','至音豈寂透希夷，珍重幽田爲發揮。',64,'全唐诗/poet.song.137000.json','["至音豈寂透希夷，珍重幽田爲發揮。", "妙用何關新卷葉，圓通自有倒聞機。", "夢中鼓響生千偈，覺後舂聲失百非。", "寄語爵陰吞賊道，玉牀安穩坐朱衣。"]'),
('06164711-e692-4ff7-9a0b-5469a1acce10','復作耳鳴二首  其二','范成大','宋','宋诗','song-poetry','','[]','東極空歌下始青，西方寶網奏韶英。',64,'全唐诗/poet.song.137000.json','["東極空歌下始青，西方寶網奏韶英。", "不須路入兜元國，自有音聞室筏城。", "牛蟻誰知牀下鬭，雞蠅任向夢中鳴。", "如今却笑難陀種，無耳何勞强聽聲。"]'),
('b54e6276-b32b-4976-9867-89268d5e2b5d','碧虛席上得趙養民運使寄詩約今晚可歸次韻迓之','范成大','宋','宋诗','song-poetry','','[]','偶携尊酒上孱顔，忽憶行人瘴霧間。',32,'全唐诗/poet.song.137000.json','["偶携尊酒上孱顔，忽憶行人瘴霧間。", "便好來分蒼石坐，已教不鎖翠雲關。"]'),
('8fb8dfc5-eb18-4c02-a3bf-6dc29e6b6f89','寒夜','范成大','宋','宋诗','song-poetry','','[]','萬象閒無語，一蛩吟獨譁。',72,'全唐诗/poet.song.137000.json','["萬象閒無語，一蛩吟獨譁。", "肅肅月浸樹，滿庭穠李花。", "風從月中來，吹我兩鬢華。", "北斗聲迴環，南斗亦橫斜。", "人生幾良夜，吾行久天涯。", "離居隔江漢，何由寄疏麻。"]'),
('c6cce579-b9b4-4d17-bf57-b81767c03bc9','甲午除夜猶在桂林念致一弟使虜今夕當宿燕山會同館兄弟南北萬里感悵成詩','范成大','宋','宋诗','song-poetry','','[]','把酒新年一笑非，鶺鴒原上巧相違。',64,'全唐诗/poet.song.137000.json','["把酒新年一笑非，鶺鴒原上巧相違。", "墨濃雲瘴我猶住，席大雪花君未歸。", "萬里關山燈自照，五更風雨夢如飛。", "別離南北人誰免，似此別離人亦稀。"]'),
('aa2df46c-dede-4e4f-af01-1699fe6f21cd','乙未元日用前韻書懷今年五十矣','范成大','宋','宋诗','song-poetry','','[]','浮生四十九俱非，樓上行藏與願違。',64,'全唐诗/poet.song.137000.json','["浮生四十九俱非，樓上行藏與願違。", "縱有百年今過半，別無三策但當歸。", "定中久已安心竟，飽外何須食肉飛。", "若使一丘并一壑，還鄉曲調儘依稀。"]'),
('3a3a73ef-86a0-4f60-b472-6961bf36f7d2','再用前韻','范成大','宋','宋诗','song-poetry','','[]','休論今昨總皆非，世味誠甘與我違。',64,'全唐诗/poet.song.137000.json','["休論今昨總皆非，世味誠甘與我違。", "蜀道雖如履平地，杜鵑終勸不如歸。", "三冬自苦坐毛穎，一夢微官陪螱飛。", "夜久南枝翻倦鵲，茫茫月白衆星稀。"]'),
('b3ce0b70-a9a6-40e5-8066-33519eeca1b4','與同僚遊栖霞洞極深遠中有數路相傳有通九疑者燭將盡乃還飲碧虛上陳仲思用二華君韻賦詩即席和之','范成大','宋','宋诗','song-poetry','','[]','竹杖芒鞵俗網疎，每逢絕勝更踟躕。',64,'全唐诗/poet.song.137000.json','["竹杖芒鞵俗網疎，每逢絕勝更踟躕。", "但隨岐路東西去，莫計光陰大小餘。", "彷彿桃源猶舞鳳，辛勤李白謾騎魚。", "今朝真作遊仙夢，不似騷人賦子虛。"]'),
('4dee65bd-7cf5-4a2b-85ec-8a4ebb7ca0a8','施元光在崑山病中遠寄長句次韻答之','范成大','宋','宋诗','song-poetry','','[]','四海飄蓬客舍邊，幾多雲水與風煙。',64,'全唐诗/poet.song.137000.json','["四海飄蓬客舍邊，幾多雲水與風煙。", "絕無膂力驅長轡，空有孤忠誓大川。", "參井忽隨征馬上，斗牛應挂故山前。", "親交情話知何許，詩到天涯喜欲顛。"]'),
('c6b63ca7-6304-4779-bb1d-157b11da85e0','次韻趙養民碧虛坐上','范成大','宋','宋诗','song-poetry','','[]','已將山色染眉黛，更挽江波添酒罍。',32,'全唐诗/poet.song.137000.json','["已將山色染眉黛，更挽江波添酒罍。", "珍重江山勸人醉，笑人驅馬惺惺迴。"]'),
('e91620cc-b0fd-4223-ac89-c20f8e01a769','贛州明府楊同年輓歌詞二首  其一','范成大','宋','宋诗','song-poetry','','[]','拱璧溫無纇，深蘭遠自芳。',48,'全唐诗/poet.song.137000.json','["拱璧溫無纇，深蘭遠自芳。", "清班孤玉筍，薄宦老銅章。", "傳業麒麟子，承家鴻鴈行。", "門闌自簪笏，吾獨憾堂堂。"]'),
('8d092951-1555-4a04-ba48-87b73f6ece1b','贛州明府楊同年輓歌詞二首  其二','范成大','宋','宋诗','song-poetry','','[]','憶昔龍門化，曾容鴈塔陪。',48,'全唐诗/poet.song.137000.json','["憶昔龍門化，曾容鴈塔陪。", "逡巡九閏過，迢遞一書來。", "未報錯刀贈，驚傳丹旐迴。", "辰陽隔江渚，空些楚詞哀。"]'),
('fe0e2b3b-5995-4585-9507-55213234a3a4','初發桂林有出嶺之喜但病餘便覺登頓至靈川疲甚自歎羸軀乃無一可偶陸融州有使來書此寄之','范成大','宋','宋诗','song-poetry','','[]','桂林獨宜人，無瘴古所傳。',168,'全唐诗/poet.song.137000.json','["桂林獨宜人，無瘴古所傳。", "北客守炎官，恃此以泰然。", "堂高愜宴坐，訟簡容佳眠。", "不計身落南，璿柄三回天。", "今朝遂出嶺，歡呼繫行纏。", "罝兔脫豐草，池魚躍清淵。", "那知多病身，久靜翻懷安。", "長風蕩籃輿，簾箔飄以翾。", "靈泉路喫蹶，僕夫告頳肩。", "我亦頭岑岑，中若磨蟻旋。", "走投破驛宿，强飯不下咽。", "茲事未渠央，萬里蜀道難。", "十年故倦遊，況乃成華巔。", "蠶老當作繭，不繭夫何言。"]'),
('0e4336ad-ed23-4c3c-af8b-b9edd3f80d99','甘棠驛','范成大','宋','宋诗','song-poetry','','[]','萬里三年醉嶺梅，東風刮地馬頭迴。',32,'全唐诗/poet.song.137000.json','["萬里三年醉嶺梅，東風刮地馬頭迴。", "心勞政拙無遺愛，慚向甘棠驛裏來。"]'),
('8e707a4f-25a9-4065-a7c4-5ada66e01687','靈泉','范成大','宋','宋诗','song-poetry','','[]','泉螭無語笑經過，欲拊煢鰥奈拙何。',32,'全唐诗/poet.song.137000.json','["泉螭無語笑經過，欲拊煢鰥奈拙何。", "孤奉明恩雖出嶺，歡顔終少汗顔多。"]'),
('f771db1b-6a8e-4a7d-89b6-6c0d7f6e44ba','嚴關','范成大','宋','宋诗','song-poetry','','[]','回看瘴嶺已無憂，尚有嚴關限北州。',32,'全唐诗/poet.song.137000.json','["回看瘴嶺已無憂，尚有嚴關限北州。", "裹飯長歌關外去，車如飛電馬如流。"]'),
('d1316d6c-59c1-4d89-9792-8a889ac67624','施進之追路出嚴關且寫予真戲題其上','范成大','宋','宋诗','song-poetry','','[]','喚渡牂牁瘴水濱，嚴關關外又逢春。',32,'全唐诗/poet.song.137000.json','["喚渡牂牁瘴水濱，嚴關關外又逢春。", "神仙富貴俱何在，且作全家出嶺人。"]'),
('cfda866f-1e94-4aae-9ef9-8fcd0499cab5','興安乳洞有上中下三巖妙絕南州率同僚餞別者二十一人遊之','范成大','宋','宋诗','song-poetry','','[]','山水敦夙好，煙霞痼奇懷。',192,'全唐诗/poet.song.137000.json','["山水敦夙好，煙霞痼奇懷。", "向聞乳洞勝，出嶺更徘徊。", "雪林縞萬李，東風知我來。", "華裾繡高原，故人紛後陪。", "繫馬玉溪橋，嵌根豁崔嵬。", "蕩蕩碧瑶宮，冰泉漱牆隈。", "芝田溉石液，深畦龍所開。", "丐我一掬慳，頮此炎州埃。", "仍呼輪袍舞，醉倒瑞露杯。", "但恐驚山靈，腰鼓轟春雷。", "薪翁雜餉婦，圜視歡以咍。", "茲巖何時鑿，閲世幾劫灰。", "始有此客狂，後會真悠哉。", "南遊冠平生，已去首猶回。", "歲月可無紀，三洞俱磨崖。", "會有好事者，摩挲讀蒼苔。"]'),
('6b3afeb3-a9da-4f6a-a896-7c9bfab55784','鏵嘴','范成大','宋','宋诗','song-poetry','','[]','導江自海陽，至縣廼瀰迤。',108,'全唐诗/poet.song.137000.json','["導江自海陽，至縣廼瀰迤。", "狂瀾即奔傾，中流遇鏵嘴。", "分爲兩道開，南灕北湘水。", "至今舟楫利，楚粵徑萬里。", "人謀奪天造，史祿所經始。", "無謂秦無人，虎鼠用否耳。", "紫藤纏老蒼，白石溜清泚。", "是間可作社，牲酒百世祀。", "修廢者誰歟，配以臨川李。"]'),
('7b3072c4-8b4b-45ca-900b-99c0a731f57c','大通界首驛','范成大','宋','宋诗','song-poetry','','[]','愚悃無華敢自欺，寸誠珍重吏民知。',32,'全唐诗/poet.song.137000.json','["愚悃無華敢自欺，寸誠珍重吏民知。", "東風重倚庭前樹，送別人情似到時。"]'),
('fd3a8d8c-bae4-4b3e-9c83-97d5da471b6b','陳仲思陳席珍李靜翁周直夫鄭夢授追路過大通相送至羅江分袂留詩爲別','范成大','宋','宋诗','song-poetry','','[]','相送不忍別，更行一程路。',144,'全唐诗/poet.song.137000.json','["相送不忍別，更行一程路。", "情知不可留，猶勝輕別去。", "二陳拱連璧，僊李瑚璉具。", "周子雋拔俗，鄭子秀風度。", "嗟我與五君，曩如栖鳥聚。", "偶投一林宿，飄搖共風雨。", "明發各飛散，後會渺何處。", "栖鳥固無情，我輩豈漫與。", "班荆一炊頃，聽此昆弟語。", "把酒不能觴，有淚若兒女。", "脩程各著鞭，慷慨中夜舞。", "功名在公等，臞儒老農圃。"]'),
('a00247b0-82ad-4a4a-89d6-670c88b5d3e8','懷桂林所思亭','范成大','宋','宋诗','song-poetry','','[]','篸山奇絕送歸時，曾榜新亭號所思。',32,'全唐诗/poet.song.137000.json','["篸山奇絕送歸時，曾榜新亭號所思。", "桂水祗今湘水外，他年空有四愁詩。"]'),
('14504124-1811-4134-a4ee-c73232e9095d','羅江','范成大','宋','宋诗','song-poetry','','[]','嶺北初程分外貪，驚心猶自怯晴嵐。',32,'全唐诗/poet.song.137000.json','["嶺北初程分外貪，驚心猶自怯晴嵐。", "如何花木湘江上，也有黄茅似嶺南。"]'),
('4ad3e1e7-4d62-4c55-bcfc-b334adb2a47b','初入湖湘懷南州諸官','范成大','宋','宋诗','song-poetry','','[]','今晨入湖南，甘土絳以紫。',168,'全唐诗/poet.song.137000.json','["今晨入湖南，甘土絳以紫。", "厥壤既殊異，風氣當稱此。", "回思始安城，舊籍贅楚尾。", "實惟荆州隸，零陵之南鄙。", "時雪度嚴關，物色號清美。", "儻以土宜觀，尚非清湘比。", "何況引而南，焦茅數千里。", "向我作牧時，客過不停軌。", "憧憧走官下，既至輒咎悔。", "書來無別語，但說瘴鄉鬼。", "我今幸北轅，又念衆君子。", "懷哉千金軀，博此五斗米。", "作詩諷方來，南遊可以已。", "車輪倘無角，吾詩亦金柅。"]'),
('b253bc9e-7f39-4d5f-91b6-01d8516019a0','清湘縣郊外雜花盛開有懷石湖','范成大','宋','宋诗','song-poetry','','[]','午行清湘縣，妍暖春事嘉。',120,'全唐诗/poet.song.137000.json','["午行清湘縣，妍暖春事嘉。", "柴荆閙桃李，冥冥一川花。", "故園豈少此，愈此百倍加。", "我寧不念歸，顧作失木鴉。", "百年北窗凉，安用天一涯。", "君恩重喬嶽，敢計征路賒。", "鄉心與官身，鑿枘方聱牙。", "橘柚走珍貢，何如繫匏瓜。", "明當復露奏，天日臨幽遐。", "儻許清江使，曳尾還汙邪。"]'),
('25589d8c-b0c0-4ae1-9e8b-b8ba82d76f03','珠塘','范成大','宋','宋诗','song-poetry','','[]','林茂鳥烏急，坡長馿馱鳴。',48,'全唐诗/poet.song.137000.json','["林茂鳥烏急，坡長馿馱鳴。", "坐輿猶足痹，負笈想肩頳。", "廢廟藤遮合，危橋竹織成。", "路傍行役苦，隨處有柴荆。"]'),
('e537c880-8e85-42fa-8dd0-0174f90f8e68','題湘山大施堂','范成大','宋','宋诗','song-poetry','','[]','重倚春林淚竹枝，南遊風物鬢成絲。',64,'全唐诗/poet.song.137000.json','["重倚春林淚竹枝，南遊風物鬢成絲。", "難尋桂嶺千峰夢，更了湘山一段奇。", "來去別無心外法，行藏休問塔中師。", "若論大施門前事，竿木逢場且賦詩。"]'),
('de757aef-09a1-41eb-8e9d-a01302953d69','清湘驛送祝賀州南歸','范成大','宋','宋诗','song-poetry','','[]','海內交情兩斷金，離歌倡和俱吳音。',64,'全唐诗/poet.song.137000.json','["海內交情兩斷金，離歌倡和俱吳音。", "桃花如雨暮春酒，竹箭有筠他日心。", "萬里書來蜀道易，四愁詩成湘水深。", "田園將蕪各早計，一棹五湖能見尋。"]'),
('fc61a023-f932-4c5b-b560-6062ac43b5e6','清湘驛送王柳州南歸二絕  其一','范成大','宋','宋诗','song-poetry','','[]','南歸北去路茫茫，不是行人也斷腸。',32,'全唐诗/poet.song.137000.json','["南歸北去路茫茫，不是行人也斷腸。", "可惜湘江春夜月，落花時節照離觴。"]'),
('498cb980-a042-4158-b625-7dffb2a4b1fc','清湘驛送王柳州南歸二絕  其二','范成大','宋','宋诗','song-poetry','','[]','我已兼程無脚力，君猶追路有襟期。',32,'全唐诗/poet.song.137000.json','["我已兼程無脚力，君猶追路有襟期。", "從今月下共花下，誰復醉吟先和詩。"]'),
('a8c5b642-2616-4476-a736-f882c9ebb0d4','七里店口占','范成大','宋','宋诗','song-poetry','','[]','分手暮江寒，徘徊立馬看。',24,'全唐诗/poet.song.137000.json','["分手暮江寒，徘徊立馬看。", "尋常相見易，倍覺別離難。"]'),
('505512b2-8c06-4b9b-8715-2261b3dcfa5c','全守支耀卿飲餞七里倅楊仲宣復携具至深溪酌別且乞余書走筆作此兼寄耀卿','范成大','宋','宋诗','song-poetry','','[]','店舍煙火寒，塵沙亭堠遠。',120,'全唐诗/poet.song.137000.json','["店舍煙火寒，塵沙亭堠遠。", "嫣紅糝芸綠，春事亦已晚。", "年芳去踆踆，江水來衮衮。", "故人瀟湘逢，留落一笑莞。", "已張七里飲，更出深溪餞。", "草間艷紅粉，竹裏趣厨傳。", "故意如許長，由來共鄉縣。", "愧我不能觴，負此離歌囀。", "別愁滿天末，不醉何由遣。", "却憶支使君，風前白波捲。"]'),
('00135f54-e284-48b3-91e5-58df40e3eb58','深溪鋪中二絕追路寄呈元將仲顯二使君  其一','范成大','宋','宋诗','song-poetry','','[]','賀州歸去柳州還，分路千山與萬山。',32,'全唐诗/poet.song.137000.json','["賀州歸去柳州還，分路千山與萬山。", "把酒故人都別盡，今朝真箇出陽關。"]'),
('5a50087a-86c3-4be9-bcd5-e33096d22831','深溪鋪中二絕追路寄呈元將仲顯二使君  其二','范成大','宋','宋诗','song-poetry','','[]','祗有南風捲路塵，斷無南客送車輪。',32,'全唐诗/poet.song.137000.json','["祗有南風捲路塵，斷無南客送車輪。", "故人合在瀟湘見，却向瀟湘別故人。"]'),
('16d552af-d683-4f1b-a605-590bfaec5ae1','戲題愚溪','范成大','宋','宋诗','song-poetry','','[]','碧湍漱白石，沄沄復湯湯。',72,'全唐诗/poet.song.137000.json','["碧湍漱白石，沄沄復湯湯。", "既爲人所愚，安用爾許忙。", "我昔曾經過，重來已三霜。", "無事趼雙足，奔走寧非狂。", "溪流到江平，翻笑客路長。", "豈不有歲晚，乞身還故鄉。"]'),
('20b926bb-f4c4-4c69-a298-ac0fb0a06c11','初泛瀟湘','范成大','宋','宋诗','song-poetry','','[]','六槳齊飛急下灘，碧琉璃上雪花翻。',32,'全唐诗/poet.song.137000.json','["六槳齊飛急下灘，碧琉璃上雪花翻。", "越來溪色清如此，只欠磯頭一釣竿。"]'),
('a68914af-91d6-435a-844f-522ac3ea4eaf','湘口夜泊南去零陵十里矣營水來自營道過零陵下湘水自桂林之海陽至此與營會合爲一江','范成大','宋','宋诗','song-poetry','','[]','我從清湘發源來，直送湘流入營水。',160,'全唐诗/poet.song.137000.json','["我從清湘發源來，直送湘流入營水。", "故人亭前合江處，暮夜檣竿矗沙尾。", "却從湘口望湘南，城郭山川恍難紀。", "萬壑千巖詩不徧，惟有蒼苔痕屐齒。", "三年瘴霧亦奇絕，浮世登臨如此幾。", "湖南山色夾江來，無復瑶篸插天起。", "坡陀狠石蹲清漲，澹蕩光風浮白芷。", "騷人魂散若爲招，傷心極目春千里。", "我亦江南轉蓬客，白鳥愁煙思故壘。", "遠遊雖好不如歸，一聲鶗鴂花如洗。"]'),
('d4b6dbff-b118-4590-bd46-72b8e6c32681','南臺瑞應閣用壁間張安國韻','范成大','宋','宋诗','song-poetry','','[]','衝雨上山頭，臨雲看山脚。',48,'全唐诗/poet.song.137000.json','["衝雨上山頭，臨雲看山脚。", "松間一彈指，開此寶樓閣。", "草鞵方費錢，拂子不暇握。", "小偈出雷音，千古驚猿鶴。"]'),
('6ec50e3c-3d37-43ce-b307-60a230f25027','湘潭','范成大','宋','宋诗','song-poetry','','[]','暮雨檣竿縣一灣，長官立馬水雲間。',32,'全唐诗/poet.song.137000.json','["暮雨檣竿縣一灣，長官立馬水雲間。", "風吹江沫浮浮去，誰在沙頭閉戶閒。"]'),
('399f99a3-afee-4c1a-a6c3-f7de95f9f2f8','泊長沙楚秀亭  其一','范成大','宋','宋诗','song-poetry','','[]','雨從湘西來，波動南楚門。',24,'全唐诗/poet.song.137000.json','["雨從湘西來，波動南楚門。", "不知春漲高，但怪江水渾。"]'),
('7eced7b1-0b98-4ad3-8f19-077084fb1a73','泊長沙楚秀亭  其二','范成大','宋','宋诗','song-poetry','','[]','舟行風打頭，陸行泥沒鞍。',24,'全唐诗/poet.song.137000.json','["舟行風打頭，陸行泥沒鞍。", "且登裴公臺，半日心眼寬。"]'),
('e1d8bdee-1bdc-444d-a2c4-f25d248952eb','題嶽麓道鄉臺','范成大','宋','宋诗','song-poetry','','[]','山外江水黄，江外滿城綠。',48,'全唐诗/poet.song.137000.json','["山外江水黄，江外滿城綠。", "城外杳無際，天低到平陸。", "長煙貫楚尾，遠勢带吳蜀。", "故園東北望，遊子闌干曲。"]'),
('c0af6c9a-7381-4cfa-96f1-7e4715faff7e','寄題潭帥王樞使佚老堂','范成大','宋','宋诗','song-poetry','','[]','孺子滄浪濯纓處，千載新堂來卜鄰。',192,'全唐诗/poet.song.137000.json','["孺子滄浪濯纓處，千載新堂來卜鄰。", "潦收無波徹底靜，東湖之水堂中人。", "濛陽花譜勝洛下，竹西藥闌來海瀕。", "新篁綠沉桂丹渥，嶽立奇石蒼苔皴。", "賞心滿眼伴閉戶，天風夜下扶車輪。", "胸中種蠡妙經濟，鬢鬚白雪朱顔春。", "蒼生未佚身未老，斯堂未可忘斯民。", "四年西略可萬世，孤撐獨立扛千鈞。", "匹馬幡幡恃天日，危言岌岌愁鬼神。", "浮生蚤休信不惡，持此欲去非吾聞。", "客遊瀟湘逢騎吹，知公已爲蒼生起。", "公今少勞佚者多，湛輩乃可寒江蓑。"]'),
('b5ca1b59-2d6b-43b2-a99d-00c2b59e9a10','湘陰橋口市別游子明','范成大','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','馬首欲東舟欲西，洞庭橋口暮寒時。',64,'全唐诗/poet.song.137000.json','["馬首欲東舟欲西，洞庭橋口暮寒時。", "三年再別子輕去，萬里獨行吾蚤衰。", "遥憶美人湘水夢，側身西望劍門詩。", "老來不灑離亭淚，今日天涯老淚垂。"]'),
('dc522a87-2087-4680-9f48-55900a29a97c','竈渚','范成大','宋','宋诗','song-poetry','','[]','白魚出水卧銀刀，紫筍堆盤脫錦袍。',32,'全唐诗/poet.song.137000.json','["白魚出水卧銀刀，紫筍堆盤脫錦袍。", "捫腹將軍猶未快，棹船西岸摘蔞蒿。"]'),
('0b3a1112-de4a-471e-a7c2-31b8b1bd0d06','大波林','范成大','宋','宋诗','song-poetry','','[]','湖路荒寒又險艱，大千空水我居間。',32,'全唐诗/poet.song.137000.json','["湖路荒寒又險艱，大千空水我居間。", "篙師晚始分南北，指點青青漢口山。"]'),
('92d065dd-b151-4b62-ab98-d9dabb4e0790','連日風作洞庭不可渡出赤沙湖','范成大','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','金沙堆前風未平，赤沙湖邊波不驚。',160,'全唐诗/poet.song.137000.json','["金沙堆前風未平，赤沙湖邊波不驚。", "客行但逐安穩去，三十六灣漲痕生。", "滄洲寒食春亦到，荻芽深碧蔞芽青。", "汨羅水飽動荆渚，嶽麓雨來昏洞庭。", "大荒無依飛鳥絕，天地惟有孤舟行。", "慷慨悲歌續楚些，彷彿幽瑟迎湘靈。", "黄昏慘淡檥極浦，雖有漁舍無人聲。", "冬湖落𤃩此蹔住，春潦怒長隨傭耕。", "吾生一葉寄萬木，況復搖落浮滄溟。", "漁蠻尚自有常處，羈官方汝尤飄零。"]'),
('c9723da4-83ee-442f-9173-f64a2d88a10d','寄題贛江亭','范成大','宋','宋诗','song-poetry','','[]','二水之會新作亭，主人文章子墨卿。',96,'全唐诗/poet.song.137000.json','["二水之會新作亭，主人文章子墨卿。", "我記斯亭且不朽，千載當與文俱鳴。", "題榜誰歟漢使者，風流好事飾儒雅。", "平生兩君吾故人，安得繫馬亭階下。", "鼓旗西征上奔瀧，所思不見心難降。", "瞿塘縱有文鱗雙，愛莫致之章貢江。"]'),
('fe185d40-6bad-4654-a2ec-75059eaf9a52','浯溪道中','范成大','宋','宋诗','song-poetry','','[]','江流去不定，山石來無窮。',56,'全唐诗/poet.song.137000.json','["江流去不定，山石來無窮。", "步步有勝處，水清石玲瓏。", "安得扁舟繫絕壁，卧聽漁童吹短笛。", "弄水看山到月明，過盡行人不相識。"]'),
('ee587114-7755-49bb-a14d-9f4f960b5f94','夜泊灣洲大風雨未至衡州一百二十里','范成大','宋','宋诗','song-poetry','','[]','阿香攪客眠，夜半驅疾雷。',84,'全唐诗/poet.song.137000.json','["阿香攪客眠，夜半驅疾雷。", "空水受奇響，如從船底來。", "嘈嘈雨窗閙，軋軋風柁開。", "睡魔走辟易，耳界愁喧豗。", "有頃飄驟過，灘聲獨鳴哀。", "燈婢燭囊衣，篙師理檣桅。", "煩擾到明發，村雞亦喈喈。"]'),
('a2980cb1-e349-4939-9819-134d3e4aa7bc','泊衡州','范成大','宋','宋诗','song-poetry','','[]','客裏仍哦對雨吟，夜來星月曉還陰。',32,'全唐诗/poet.song.137000.json','["客裏仍哦對雨吟，夜來星月曉還陰。", "空江十日無春事，船到衡陽柳色深。"]'),
('b5a0bba2-e362-484e-b637-0f4b4bb1271b','步入衡山','范成大','宋','宋诗','song-poetry','','["\u8861\u5c71"]','應有人家住隔溪，綠陰亭午但聞雞。',64,'全唐诗/poet.song.137000.json','["應有人家住隔溪，綠陰亭午但聞雞。", "松根當路龍筋瘦，竹筍漫山鳳尾齊。", "墨染深雲猶似瘴，絲來小雨不成泥。", "更無騎吹喧相逐，散誕閒身信馬蹄。"]'),
('56efac46-3489-499d-b2ce-7e79bdef43e7','重遊南嶽','范成大','宋','宋诗','song-poetry','','["\u8861\u5c71"]','捨舟得馬如馭氣，步入青松三十里。',272,'全唐诗/poet.song.137000.json','["捨舟得馬如馭氣，步入青松三十里。", "我從蠻嶺瘴煙來，不怕雨雲埋嶽趾。", "憶昔南征款廟庭，往來無恙神所祉。", "當時已有歸田願，帝臨此心如白水。", "煌煌南正館於東，手握八觚溫玉璽。", "駿奔灊霍左右輔，好生不殺扶炎紀。", "崇禋竣事曉壇空，躋攀小試青鞋底。", "不知雲磴幾千丈，但見漫山白龍尾。", "石頭招我上南臺，瑞應闌干天半倚。", "福嚴鐘聲過橋來，彷彿三生如夢裏。", "堂中尊者已先去，苔鎖巖扉何日啟。", "竹嫌磽确老逾瘦，松畏高寒蟠不起。", "癯儒尚病怕深登，幽討未窮行且止。", "我評七十二高峰，鬰律穹窿少觀美。", "儼然可瞻不可玩，往往雄尊如負扆。", "乃知嶽鎮蓋深厚，不與他山爭秀偉。", "區區獻狀眩兒童，乳洞淡巖真戲耳。"]'),
('0b0467e3-1351-4afa-a1a2-6599ee2713bf','四明人董嶧久居嶽市乞詩','范成大','宋','宋诗','song-poetry','','[]','祝融峰下兩逢春，雨宿風餐老病身。',32,'全唐诗/poet.song.137000.json','["祝融峰下兩逢春，雨宿風餐老病身。", "莫笑五湖萍梗客，海邊亦有未歸人。"]'),
('ee915f46-0f55-4417-bd23-90c4909214a4','三月十五日華容湖尾看月出','范成大','宋','宋诗','song-poetry','','[]','雲銷澧陽風，月生岳陽水。',120,'全唐诗/poet.song.137000.json','["雲銷澧陽風，月生岳陽水。", "誰推赤金盤，湧出白銀地。", "徘徊忽騰上，蹀蹀恐顛墜。", "稍高輪漸安，飛彩到篷背。", "晶晶浪皆舞，靨靨星欲避。", "兜羅世界網，普現無邊際。", "官居束戶庭，有眼如幻翳。", "向非行大荒，寧有此巨麗。", "乘除較得失，漂泊非左計。", "妻孥競驩譁，渠亦知許事。"]'),
('07a16533-4db3-459d-8ab8-784c0c9a1b86','釣池口阻風迷失港道','范成大','宋','宋诗','song-poetry','','[]','回風打船失西東，柁癡櫓弱無適從。',128,'全唐诗/poet.song.137000.json','["回風打船失西東，柁癡櫓弱無適從。", "三老號呼鐵纜墜，招頭撾鼓驅魚龍。", "千篙撐折百丈斷，日暮稍與洪相通。", "推移尋尺力千里，時有黄帽來言功。", "康莊大逵世不乏，乃獨蹇産濤波中。", "一官橫起險易相，剎那憂喜隨兒童。", "漲湖連天遠目斷，且復加飯追萍蓬。", "蒲團坐暖看香篆，作止任滅如頑空。"]'),
('11c600b2-5765-4c75-833e-c17424b3dfb2','鼎河口枕上作','范成大','宋','宋诗','song-poetry','','[]','漂泊離巢燕，彎跧負殻蝸。',48,'全唐诗/poet.song.137000.json','["漂泊離巢燕，彎跧負殻蝸。", "瘦嫌莞席硬，老覺畫屏奢。", "報道帆當落，傳呼鼓已撾。", "且投人處宿，未到已聞蟇。"]'),
('6518b21e-4549-40d8-a9bc-5fd52a7139ab','安鄉縣西晚泊','范成大','宋','宋诗','song-poetry','','[]','水闊鳥烏倦，墟寒童僕饑。',48,'全唐诗/poet.song.137000.json','["水闊鳥烏倦，墟寒童僕饑。", "一灣村縣過，百折暮江遲。", "曉夢孤燈見，春陰病骨知。", "簡書寧不畏，旅力奈先疲。"]'),
('2f8a00a9-04a5-4a2f-a426-7f9b4842a5b0','澧陽江','范成大','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','順流下沅江，溯流上澧浦。',72,'全唐诗/poet.song.137000.json','["順流下沅江，溯流上澧浦。", "水深蘭芷寒，漂搖憚風雨。", "采采不盈掬，何由寄遠渚。", "洞庭浮天白，遐矚莽吳楚。", "有懷獨晤歎，櫓聲與人語。", "暮夜即維舟，蒼茫定何許。"]'),
('7bc7476c-066e-4009-912c-cd91d51a0205','澧浦','范成大','宋','宋诗','song-poetry','','[]','葦岸齊齊似碧城，江船罨岸逆風行。',32,'全唐诗/poet.song.137000.json','["葦岸齊齊似碧城，江船罨岸逆風行。", "綠蘋白芷俱憔悴，惟有蔞蒿滿意生。"]'),
('4ccca393-e56f-4cc6-a53a-32427200ddfd','澧江漁舍','范成大','宋','宋诗','song-poetry','','[]','狡窟空來四十年，沿江猶自少炊煙。',32,'全唐诗/poet.song.137000.json','["狡窟空來四十年，沿江猶自少炊煙。", "茫茫曠土無人問，蘆荻春深綠滿川。"]'),
('c38c5631-5dc6-44a9-b4c6-780ba6935870','孫黄渡','范成大','宋','宋诗','song-poetry','','[]','捨舟從陸更間關，徑仄仍荒亦未乾。',64,'全唐诗/poet.song.137000.json','["捨舟從陸更間關，徑仄仍荒亦未乾。", "棘刺近人牢閉眼，泥塗兀馬緊扶鞍。", "茶山盜藪路程惡，麥壠人家懷抱寬。", "擔僕輿夫盡劬瘁，病翁那得更加餐。"]'),
('7f4a55c8-d28d-4250-af4f-b35164111ac4','潺陵','范成大','宋','宋诗','song-poetry','','[]','舟橫攸河水，馬滑潺陵道。',120,'全唐诗/poet.song.137000.json','["舟橫攸河水，馬滑潺陵道。", "百里無鉏犁，閒田生春草。", "春草亦已瘦，栖栖晚花少。", "落日見行人，愁煙沒孤鳥。", "老翁雪髯鬢，生長識羣盜。", "歸來四十年，墟里迹如掃。", "莫訝土毛稀，須知人力槁。", "生聚何當復，茲事恐終老。", "人言古戰場，瘡痍猝難療。", "誰使至此極，天乎吾請禱。"]'),
('54069226-f2aa-4aff-a82f-317291cf6224','將至公安','范成大','宋','宋诗','song-poetry','','[]','前村後村啼杜宇，伴人憂煎與人語。',64,'全唐诗/poet.song.137000.json','["前村後村啼杜宇，伴人憂煎與人語。", "雲寒日薄春一夢，地闊天低淚如雨。", "我馬虺隤我僕痡，豈不懷歸畏簡書。", "公安縣前酒可沽，不如且聽提胡盧。"]'),
('ca8e3ae7-728b-471f-8d4d-33659c8dd8c1','公安渡江','范成大','宋','宋诗','song-poetry','','[]','食罷雨方作，起行泥已深。',48,'全唐诗/poet.song.137000.json','["食罷雨方作，起行泥已深。", "伴愁多楚些，吟病獨吳音。", "莫怨馬蹄滑，須愁蠶事侵。", "梅黄時節是，未可决晴陰。"]'),
('fd38b85c-fcce-4570-8c7d-cb28cf5ffeb0','荆渚堤上','范成大','宋','宋诗','song-poetry','','[]','原田何莓莓，野水亂平楚。',72,'全唐诗/poet.song.137000.json','["原田何莓莓，野水亂平楚。", "大堤少人行，誰與藝稷黍。", "獨木且百歲，骯髒立水滸。", "當年識兵燼，見赦幾樵斧。", "摩挲欲問訊，恨汝不能語。", "薄暮有底忙，沙頭聽鳴櫓。"]'),
('2c889a83-0f37-47d5-aec0-f5f45e9f0c94','渚宮野步題芳草','范成大','宋','宋诗','song-poetry','','[]','草色沐新雨，綠潤如得意。',48,'全唐诗/poet.song.137000.json','["草色沐新雨，綠潤如得意。", "披拂欲生煙，苒苒著巾袂。", "天涯各芳春，秦吳千萬里。", "故人攀桂枝，今夕念游子。"]'),
('db8c6e6a-8e6c-4ca1-9026-53899e882842','發荆州','范成大','宋','宋诗','song-poetry','','[]','初上篷籠竹笮船，始知身是劍南官。',64,'全唐诗/poet.song.137000.json','["初上篷籠竹笮船，始知身是劍南官。", "沙頭沽酒市樓暖，徑步買薪江墅寒。", "自古秦吳稱絕國，于今歸峽有名灘。", "千山萬水垂垂老，只欠天西蜀道難。"]'),
('3428384c-f838-4101-83ac-bb189e0b2f55','虎牙灘','范成大','宋','宋诗','song-poetry','','[]','傾崖溜雨色，慘淡水墨畫。',96,'全唐诗/poet.song.137000.json','["傾崖溜雨色，慘淡水墨畫。", "辛夷碎花縣，瘣木老藤挂。", "翠莽楚甸窮，黄流蜀江下。", "一灘今始嘗，三峽此其亞。", "雨點鼓士摻，雲騰挽夫跨。", "驚心度石林，破眼見村舍。", "牛眠草色裏，犬吠竹林罅。", "步頭可檥船，安穩睡殘夜。"]'),
('76ac5a8d-cd0a-4501-a2de-e9d9dbb8f332','峽州至喜亭','范成大','宋','宋诗','song-poetry','','[]','斷崖卧水口，連岡抱城樓。',84,'全唐诗/poet.song.137000.json','["斷崖卧水口，連岡抱城樓。", "下有吳蜀客，檣竿立滄洲。", "雨後漲江急，黄濁如潮溝。", "時見山峽船，鐃鼓噪中流。", "適從稠灘來，白狗連黄牛。", "渦濆大如屋，九死爭船頭。", "人鮓尚脫免，虎牙不須憂。"]'),
('c627d8ff-6dfb-4803-aee3-65ce96d6917f','初入峽山效孟東野','范成大','宋','宋诗','song-poetry','','[]','峽山偪而峻，峽泉湍以碕。',96,'全唐诗/poet.song.137000.json','["峽山偪而峻，峽泉湍以碕。", "峽草如毨毛，峽樹多樛枝。", "峽禽惟杜鵑，血吻日夜啼。", "峽馬類黄狗，不能長鳴嘶。", "峽曉虎跡多，峽暮人跡稀。", "峽路如登天，猿鶴不敢梯。", "僕夫負嵎哭，我亦呻吟悲。", "悲吟不成章，聊賡峽哀詩。"]'),
('94f54b47-c895-411d-9057-ca933c03266f','土門','范成大','宋','宋诗','song-poetry','','[]','汙泥汩峻阪，狠石卧中路。',72,'全唐诗/poet.song.137000.json','["汙泥汩峻阪，狠石卧中路。", "睥睨無敢前，趦趄屢却顧。", "長繩引籃輿，前輓後推去。", "吏士更叫號，作氣欲飛度。", "顛墜較分寸，商略營蹞步。", "須臾氣亦竭，一一汗如雨。"]'),
('bbce8bac-8811-47f8-b518-43348d1c6f6c','桃花舖','范成大','宋','宋诗','song-poetry','','[]','老蕨漫山鳳尾張，青楓直幹如攢槍。',64,'全唐诗/poet.song.137000.json','["老蕨漫山鳳尾張，青楓直幹如攢槍。", "山深嵐重鼻酸楚，石惡淖深神慘傷。", "陰崖風生吹客急，草中枯株似人立。", "昳晡卓幕先下程，將士黄昏始相及。"]'),
('c7ccb35f-f4ab-4dea-a43c-67b4eaf3fce3','覆盆舖','范成大','宋','宋诗','song-poetry','','[]','三登三降岡始斷，一步一休日欲斜。',32,'全唐诗/poet.song.137000.json','["三登三降岡始斷，一步一休日欲斜。", "濁酒半瓶不得煖，覆盆有舖無漿家。"]'),
('6a97e5a0-caa3-43e1-b42a-e2832e0f09c6','小望州','范成大','宋','宋诗','song-poetry','','[]','峰頭高絕鄰，四瞰若窺井。',120,'全唐诗/poet.song.137000.json','["峰頭高絕鄰，四瞰若窺井。", "小山萬蟻垤，大山拊其頂。", "叢霄一握近，罡風振衣冷。", "似聞天人語，笑我雪垂領。", "曩侍玉案香，委佩太清境。", "獨下赤城戲，俯仰一枰頃。", "豈其厭晨華，嗅此腥腐鼎。", "揮手謝天人，伶俜愧孤影。", "來償繭足債，尚欠界天嶺。", "老矣且倦遊，歸期行可請。"]'),
('64069b5e-197f-4445-b65d-91c7fe13e513','大望州','范成大','宋','宋诗','song-poetry','','[]','望州山頭天四低，東瞰夷陵西秭歸。',64,'全唐诗/poet.song.137000.json','["望州山頭天四低，東瞰夷陵西秭歸。", "峽江微茫細如带，江外千峰青打圍。", "黄牛廟磯石如劈，想看驚湍虎鬚白。", "水行陸走俱險艱，安得如鳥有羽翼。"]'),
('a3008d7d-3770-49b8-b6cd-d7ac740026fe','一百八盤','范成大','宋','宋诗','song-poetry','','[]','疇昔辭桂林，自謂已出嶺。',96,'全唐诗/poet.song.137000.json','["疇昔辭桂林，自謂已出嶺。", "蛻蟬蠻煙中，恍若醉夢醒。", "今來峽山路，步步躡雲頂。", "仍聞蚯蚓瘴，顧與嶠南等。", "平生行路難，驚浪兀漂梗。", "迷塗茲益遠，鳥道非人境。", "老矣法當佚，懷哉遊可屏。", "拜手天東南，亟上歸田請。"]'),
('2319695b-fc26-4c14-aeaa-de9ce997316a','火墨坡下嶺','范成大','宋','宋诗','song-poetry','','[]','清晨入岑蔚，嵐重寒颼飀。',72,'全唐诗/poet.song.137000.json','["清晨入岑蔚，嵐重寒颼飀。", "忽聞黄鸝語，方悟麥始秋。", "旅食法當瘦，遠行人所愁。", "況復深山中，不與和氣游。", "苦辛那敢憚，病悴良可憂。", "徒憂亦無益，聊作商聲謳。"]'),
('0992ae9c-f482-44f1-bb73-56ce8db69dd1','八場平聞猿','范成大','宋','宋诗','song-poetry','','[]','清猿泠泠鳴玉簫，三聲兩聲高樹梢。',64,'全唐诗/poet.song.137000.json','["清猿泠泠鳴玉簫，三聲兩聲高樹梢。", "子母聯拳傳枝去，忽作哀厲長鳴號。", "天寒林深山石惡，行人舉頭雙淚閣。", "雪澗琴心未足悲，須寫峽中腸斷時。"]'),
('f2e35ad8-1813-464e-a61f-d4548b86cbdb','鑽天三里','范成大','宋','宋诗','song-poetry','','[]','非岡非嶺復非坡，黄鵠不度吾經過。',64,'全唐诗/poet.song.137000.json','["非岡非嶺復非坡，黄鵠不度吾經過。", "妻孥下行啼且笑，聯手相携如踏歌。", "風吹汗乾人力盡，屐齒與石方相磨。", "鑽天三里似千里，四十八盤將奈何。"]'),
('47b3e5c3-2824-486a-aad4-62417274dfde','蛇倒退','范成大','宋','宋诗','song-poetry','','[]','山前壁如削，山後崖復斷。',192,'全唐诗/poet.song.137000.json','["山前壁如削，山後崖復斷。", "曏吾達隴首，如海到彼岸。", "那知下嶺處，慄甚履冰戰。", "牽前带相挽，縋後衣盡綻。", "健倒輒尋丈，徐行厪分寸。", "上疑緣竹竿，下劇滾金彈。", "豈惟蛇退舍，飛鳥望崖反。", "稍喜一徑平，猶有千石亂。", "仍逢新燒畬，約略似耕畔。", "心知人境近，顰末百憂散。", "山民茆數把，鬼質犢子健。", "腰鑱走迎客，再拜復三歎。", "謂匪人所蹊，官來定何幹。", "儻爲饑火驅，平地豈無飯。", "意者官事迫，如馬就羈絆。", "我乃不能答，付以一笑粲。"]'),
('04b15b44-9225-4bf1-a31d-fc892701c9d5','大丫隘','范成大','宋','宋诗','song-poetry','','[]','峽行五程無聚落，馬頭今日逢耕鑿。',64,'全唐诗/poet.song.137000.json','["峽行五程無聚落，馬頭今日逢耕鑿。", "麥苗疎瘦豆苗稀，椒葉尖新柘葉薄。", "家家婦女布纏頭，背負小兒領垂瘤。", "山深生理却不乏，人有銀釵一雙插。"]'),
('d188486b-df47-42ca-a1ec-1dac075683fc','麻線堆','范成大','宋','宋诗','song-poetry','','[]','雲木盪胸起，鬰峩一峰危。',288,'全唐诗/poet.song.137000.json','["雲木盪胸起，鬰峩一峰危。", "上有路千折，縺縷如縈絲。", "是爲麻線堆，厥險天下稀。", "偪仄容半足，顛墜寧復稽。", "騰猱尚愁苦，游子將安之。", "浮屠德寶者，悲智緒等慈。", "隨山刊古木，尋壑得長磯。", "輿梁捷飛度，布石綿階梯。", "自從新路改，重趼無齎咨。", "縣有孫少府，琬琰劖文詞。", "勿云此事小，惟有行人知。", "況觀峽山路，由來欠平治。", "官吏既弗跡，誰肯深長思。", "天險固自若，當令略成蹊。", "土工運畚鍤，石工操鑿椎。", "烈火敗磽确，築沙填隙巇。", "多用百夫力，遠無五旬期。", "但冀米鹽給，不煩金幣支。", "非客敢竊議，道傍詢旄倪。", "身雖雪山戍，亦願助毫釐。", "工費嗟小哉，政須賢有司。", "東有管夷陵，西有葉秭歸。", "上維沈隠侯，夔臺今吏師。", "下維熊繹孫，長材佐州麾。"]'),
('813ad48e-e73c-4d8c-aeab-633b404569dc','戲書麻線堆下','范成大','宋','宋诗','song-poetry','','[]','一身半世走奔波，疑是三生宿債多。',32,'全唐诗/poet.song.137000.json','["一身半世走奔波，疑是三生宿債多。", "折券已饒麻線嶺，責償難免竹竿坡。"]'),
('e2303383-71e6-4a1b-b921-f75d09327f42','胡孫愁','范成大','宋','宋诗','song-poetry','','[]','傾崖當胸石齧足，失勢毛氂槁幽谷。',64,'全唐诗/poet.song.137000.json','["傾崖當胸石齧足，失勢毛氂槁幽谷。", "王孫却走斷不到，惟有哀猿如鬼哭。", "僕夫酸嘶訴塗窮，我亦付命無何中。", "悲風忽來木葉戰，落日虎嘷枯竹叢。"]'),
('63433914-9150-4709-be05-2d57247227a0','判命坡','范成大','宋','宋诗','song-poetry','','[]','鑽天嶺上已飛魂，判命坡前更駭聞。',64,'全唐诗/poet.song.137000.json','["鑽天嶺上已飛魂，判命坡前更駭聞。", "側足三分垂壞磴，舉頭一握到孤雲。", "微生敢列千金子，後福猶幾萬石君。", "早晚北窗尋噩夢，故應含笑老榆枌。"]'),
('4f2d87e2-7f6d-4777-8440-fa8966bd56a2','千石嶺','范成大','宋','宋诗','song-poetry','','[]','晨光挂高嶺，晴色媚遠客。',72,'全唐诗/poet.song.137000.json','["晨光挂高嶺，晴色媚遠客。", "哀湍吼叢薄，宿霧裊絕壁。", "露重薊花紫，風來蓬背白。", "迷塗朴渥跳，飲澗於菟跡。", "層巔多折木，迮磴有飛石。", "不知山幾重，杳杳入叢碧。"]'),
('376882c6-94fd-42e8-af7c-337077d6ddeb','九盤坡布水','范成大','宋','宋诗','song-poetry','','[]','莫惜縈迴上九盤，洗心雙瀑雪花寒。',32,'全唐诗/poet.song.137000.json','["莫惜縈迴上九盤，洗心雙瀑雪花寒。", "野翁酌水煎茶獻，自古人來到此難。"]'),
('9558f572-213c-46d7-be82-d1152fc299b8','荒口','范成大','宋','宋诗','song-poetry','','[]','十步九喫蹶，百夫半蹣跚。',48,'全唐诗/poet.song.137000.json','["十步九喫蹶，百夫半蹣跚。", "豁然鳥道窮，努力造其巔。", "謂是嶺頭了，一峰復當前。", "既無反顧法，仰望心茫然。"]'),
('9383277a-3515-4689-94ab-82af8309059f','四十八盤','范成大','宋','宋诗','song-poetry','','[]','詰曲不前如宦拙，欹傾當面似交難。',32,'全唐诗/poet.song.137000.json','["詰曲不前如宦拙，欹傾當面似交難。", "若將世路比山路，世路更多千萬盤。"]'),
('d59f0d59-0db9-4acc-9c33-f297211afb29','紫荷車','范成大','宋','宋诗','song-poetry','','[]','綠英吐弱線，翠葉抱修莖。',48,'全唐诗/poet.song.137000.json','["綠英吐弱線，翠葉抱修莖。", "矗如青旄節，草中立亭亭。", "根有却老藥，鱗皴友松苓。", "長生不暇學，聊冀病身輕。"]'),
('75d3dba3-4a3d-4600-acfd-403d2f09cf5f','錦带花','范成大','宋','宋诗','song-poetry','','[]','妍紅棠棣粧，弱綠薔薇枝。',48,'全唐诗/poet.song.137000.json','["妍紅棠棣粧，弱綠薔薇枝。", "小風一再來，飄颻隨舞衣。", "吳下嫵芳檻，峽中滿荒陂。", "佳人墮空谷，皎皎白駒詩。"]'),
('48fc6564-6874-46db-98cb-c618dc4091fe','入秭歸界','范成大','宋','宋诗','song-poetry','','[]','山根繫馬得漿家，深入窮鄉事可嗟。',64,'全唐诗/poet.song.137000.json','["山根繫馬得漿家，深入窮鄉事可嗟。", "蚯蚓祟人能作瘴，茱萸隨俗强煎茶。", "幽禽不見但聞語，野草無名都著花。", "窈窕崎嶇殊未艾，去程方始問三巴。"]'),
('0a761a6d-6272-49e8-8c54-d93374cb2f17','早發周平驛過清烈祠下','范成大','宋','宋诗','song-poetry','','[]','物色近人境，喜歡嚴曉裝。',48,'全唐诗/poet.song.137000.json','["物色近人境，喜歡嚴曉裝。", "山月雞犬聲，野風麻麥香。", "登嶺既開豁，入林更清凉。", "三呼獨醒士，儻肯釂我觴。"]'),
('f359ea36-8c8f-48e1-b0d0-b0be30de4fd3','白狗峽','范成大','宋','宋诗','song-poetry','','[]','江紋圓復破，樹色昏還明。',120,'全唐诗/poet.song.137000.json','["江紋圓復破，樹色昏還明。", "連灘竹節稠，洶怒奔夷陵。", "石磯鐵色頑，相望如姦朋。", "踞岸意不佳，當流勢尤獰。", "山回水若盡，但見青竛竮。", "慘慘疑鬼寰，幽幽無人聲。", "顛沛安危機，艱難古今情。", "俯窺得目眩，却立恐神驚。", "白雲冒巖扉，下維玉虛庭。", "神仙坐閲世，應笑行人行。"]'),
('f86bff0b-bc60-4352-8f7d-a098b2c0f4cd','秭歸縣','范成大','宋','宋诗','song-poetry','','[]','永日貪程客，長年弔古詩。',48,'全唐诗/poet.song.137000.json','["永日貪程客，長年弔古詩。", "悲秋荒故宅，負石慘空祠。", "峻壁鴉翻倦，高畬麥秀遲。", "窮山熊繹國，偪仄建邦時。"]'),
('65f03ab7-eff5-4b47-8149-e0fa9e640317','歸州竹枝歌二首  其一','范成大','宋','宋诗','song-poetry','','[]','東鄰男兒得湘纍，西舍女兒生漢妃。',32,'全唐诗/poet.song.137000.json','["東鄰男兒得湘纍，西舍女兒生漢妃。", "城郭如村莫相笑，人家伐閲似渠稀。"]'),
('31f8cf48-5dd3-465c-b792-f4ccbd7e21b3','歸州竹枝歌二首  其二','范成大','宋','宋诗','song-poetry','','[]','東岸艬船拋石門，西山炊煙連白雲。',32,'全唐诗/poet.song.137000.json','["東岸艬船拋石門，西山炊煙連白雲。", "竹籬茅舍作晚市，青蓋黄旗稱使君。"]'),
('211ef55a-ff36-46be-a74b-c64804ba221b','照君臺','范成大','宋','宋诗','song-poetry','','[]','天生尤物元無種，萬里巴村出青塚。',64,'全唐诗/poet.song.137000.json','["天生尤物元無種，萬里巴村出青塚。", "高臺望思臺已荒，東風溪漲流水香。", "嬋娟鍾美空萬古，翻使鄉山多醜女。", "灸眉作瘢亦不須，人人有癭如瓠壺。"]'),
('011f7796-615f-444d-9ce3-93c4f2adde9c','人鮓甕','范成大','宋','宋诗','song-poetry','','[]','懷沙祠下鐵色磯，中流束湍張禍機。',64,'全唐诗/poet.song.137000.json','["懷沙祠下鐵色磯，中流束湍張禍機。", "與齎俱入彼可弔，乘流而下吾亦危。", "江河難犯一至此，天地好生安取斯。", "朝歌勝母古尚諱，我其覆醢航秭歸。"]'),
('380a93de-4637-40dc-a131-ac6d236bdf54','巴東峽口','范成大','宋','宋诗','song-poetry','','[]','水宿頻欹側，徒行又險艱。',48,'全唐诗/poet.song.137000.json','["水宿頻欹側，徒行又險艱。", "舟危神女峽，馬瘦鬼門關。", "照夜燒畬隴，緣雲種笮山。", "催成頭雪白，休說鬢絲斑。"]'),
('cf1e6ca9-5dce-4457-8477-e0a4dfe62d04','初入巫峽','范成大','宋','宋诗','song-poetry','','[]','鑽火巴東岸，摐金峽口船。',48,'全唐诗/poet.song.137000.json','["鑽火巴東岸，摐金峽口船。", "束江崖欲合，漱石水多漩。", "卓午三竿日，中間一罅天。", "偉哉神禹跡，疏鑿此山川。"]'),
('c1a99a23-2c8a-4c45-8395-0f6dba797bc1','將至巫山遇雨','范成大','宋','宋诗','song-poetry','','[]','峽行水落惟憂雨，通昔淋浪怨行旅。',64,'全唐诗/poet.song.137000.json','["峽行水落惟憂雨，通昔淋浪怨行旅。", "千山萬山生白煙，陽臺那得雲如許。", "牋詞騰告翠帷僊，丐我一晴翻手間。", "放開十二峰頭色，重賦碧叢高插天。"]'),
('ca9f2eb7-f73f-4633-9756-238d35a206e2','巫山高','范成大','宋','宋诗','song-poetry','','[]','濕雲不收煙雨霏，峽船作灘梢廟磯。',128,'全唐诗/poet.song.137000.json','["濕雲不收煙雨霏，峽船作灘梢廟磯。", "杜鵑無聲猿叫斷，惟有饑鴉迎客飛。", "西真功高佐禹跡，斧鑿鱗皴倚天壁。", "上有瑶簪十二尖，下有黄湍三百尺。", "蔓花虯木風煙昏，蘚珮翠帷香火寒。", "靈斿飄忽定何許，時有行人開廟門。", "楚客詞章元是諷，紛紛餘子空嘲弄。", "玉色頩顔不可干，人間錯說高唐夢。"]'),
('28af6f86-f610-4697-a054-7efe42e1b410','刺濆淖','范成大','宋','宋诗','song-poetry','','[]','峽江饒暗石，水狀日千變。',264,'全唐诗/poet.song.137000.json','["峽江饒暗石，水狀日千變。", "不愁灘瀧來，但畏濆淖見。", "人言盤渦耳，夷險顧有間。", "仍於非時作，未可一理貫。", "安行方熨縠，無事忽翻練。", "突如湯鼎沸，翕作茶磨旋。", "勢迫中成漥，怒霽外始暈。", "已定稍安慰，儵作更驚眩。", "漂漂浮沫起，疑有潛鯨噀。", "勃勃駭浪騰，復恐蟄鼇抃。", "篙師瞪褫魄，灘戶呀雨汗。", "逡巡怯大敵，勇往決鏖戰。", "幸免與齎入，還憂似蓬轉。", "驚呼招竿折，奔救竹笮斷。", "九死船頭爭，萬苦石上牽。", "旁觀兢薄冰，撇過捷飛電。", "前余叱馭來，山險固嘗徧。", "今者擊檝誓，豈復憚波面。", "澎澎三峽長，颭颭一葦亂。", "既微掬指忙，又匪科頭慢。", "天子賜之履，江神敢吾玩。", "但催疊鼓轟，往助雙櫓健。"]'),
('a41aa640-77a7-4a4e-884c-cbb3b3006028','嘲峽石','范成大','宋','宋诗','song-poetry','','["\u592a\u6e56"]','峽山狠無情，其下多醜石。',264,'全唐诗/poet.song.137000.json','["峽山狠無情，其下多醜石。", "頑質賈憎垂，傀狀發笑啞。", "粗類墳壤黄，沉漬鐵矢黑。", "或如溝泥涴，或似凍壁坼。", "堆疑聚廩粟，陊若壞城甓。", "槎牙鏤朽木，狼籍委枯骼。", "礧砢包蠃蚌，淋漓錮鉛錫。", "縱文瓦溝壠，橫疊衣摺襞。", "鱗皴斧鑿餘，坎窞蹴踏力。", "云何清淑氣，孕此詭譎跡。", "我本一丘壑，嗜石舊成癖。", "端溪紫琳腴，洮河綠沉色。", "階冊截肪膩，泗磬鳴球擊。", "嵌空太湖底，偶立韶江側。", "真陽劖千巖，營道剷寸碧。", "倦游所閲多，未易一二籍。", "朅來茲山下，刺眼昔未覿。", "或云峽多材，奇秀鬰以積。", "絕代昭君村，驚世屈原宅。", "東家兩兒女，氣足豪萬國。", "山石何重輕，奚暇更融液。", "我亦味其言，作詩曉行客。"]'),
('e00fb4e2-6db3-4e6f-9fe8-0cd8b2f31c83','勞畬耕','范成大','宋','宋诗','song-poetry','','[]','峽農生甚艱，斫畬大山巔。',264,'全唐诗/poet.song.137000.json','["峽農生甚艱，斫畬大山巔。", "赤埴無土膏，三刀財一田。", "頗具穴居智，占雨先燎原。", "雨來亟下種，不爾生不蕃。", "麥穗黄剪剪，豆苗綠芊芊。", "餠餌了長夏，更遲秋粟繁。", "稅畝不什一，遺秉得饜餐。", "何曾識秔稻，捫腹嘗果然。", "我知吳農事，請爲峽農言。", "吳田黑壤腴，吳米玉粒鮮。", "長腰瓠犀瘦，齊頭珠顆圓。", "紅蓮勝彫胡，香子馥秋蘭。", "或收虞舜餘，或自占城傳。", "早秈與晚䆉，濫吹甑甗間。", "不辭春養禾，但畏秋輸官。", "姦吏大雀鼠，盜胥衆螟蝝。", "掠剩增釜區，取盈折緡錢。", "兩鍾致一斛，未免催租瘢。", "重以私債迫，逃屋無炊煙。", "晶晶雲子飯，生世不下咽。", "食者定游手，種者長流涎。", "不如峽農飽，豆麥終殘年。"]'),
('fed5eea5-a359-4e40-8c1f-2231e0d0666b','巫山縣','范成大','宋','宋诗','song-poetry','','[]','借馬巫山縣，盤舟掉石灘。',48,'全唐诗/poet.song.137000.json','["借馬巫山縣，盤舟掉石灘。", "梅肥朝雨細，茶老暮煙寒。", "門對高唐起，江從灧澦難。", "流堆三尺在，旅夢一枝安。"]'),
('61d6c838-fa76-4a9c-a1a2-a13da6ecc729','自巫山遵陸以避黑石諸灘大雨不可行泊驛中一日吏士自秭歸陸行者亦會','范成大','宋','宋诗','song-poetry','','[]','巫山信是陽雲臺，客行五日雲不開。',128,'全唐诗/poet.song.137000.json','["巫山信是陽雲臺，客行五日雲不開。", "陰晴何常有朝暮，夜雨少休明復來。", "今朝水長不知數，沒盡山根蒼石堆。", "東磯西磯盡如削，大灘小灘俱若雷。", "不知瞿唐復何似，想見萬頃淙一杯。", "祗今水劑已壯矣，聞道陸程尤艱哉。", "摩圍隘口石生角，蹋颯坡前泥似醅。", "眼前安得故園路，江沙江草便青鞋。"]'),
('bf1a0448-c697-4a31-acbd-ddb5ae70ef30','燕子坡','范成大','宋','宋诗','song-poetry','','[]','大山如牆缺，小山如塚纍。',72,'全唐诗/poet.song.137000.json','["大山如牆缺，小山如塚纍。", "衆山直下看，方知此峰危。", "木末見夔峽，一溝盎春泥。", "中有天下險，造化真兒嬉。", "峰頂不滿笑，舟中鬢成絲。", "登高尚超覽，況乃絕俗姿。"]'),
('16b9356c-bfc7-49ca-af8f-aaf022600acd','鬼門關','范成大','宋','宋诗','song-poetry','','[]','天作隴頭石闕，人言要隔塵樊。',28,'全唐诗/poet.song.137000.json','["天作隴頭石闕，人言要隔塵樊。", "百年會須作鬼，無事先穿鬼關。"]'),
('16477997-598a-4f5a-9d71-4c29da8217eb','離巫山好晴午後入瞿唐關憩高齋半日','范成大','宋','宋诗','song-poetry','','[]','一昨題詩訴苦霖，果然連夜卷曾陰。',64,'全唐诗/poet.song.137000.json','["一昨題詩訴苦霖，果然連夜卷曾陰。", "盡收行雨瑶姬賜，不徇世情巫峽心。", "喜鵲滿枝朝日淡，哀猿何處宿雲深。", "水門山徑高齋外，一枕清風屏萬金。"]'),
('60a04912-dc02-4eff-8e2a-f990de8de100','灧澦堆','范成大','宋','宋诗','song-poetry','','[]','灧澦之石誰劖鎸，惡駭天下形眇然。',192,'全唐诗/poet.song.137000.json','["灧澦之石誰劖鎸，惡駭天下形眇然。", "客行五月潦始漲，但見匹馬浮黄湍。", "時時吐沫作濆淖，灂灂有聲如粥煎。", "蜀江西來已無路，鑿山作澮方成川。", "瞿唐之口狹如带，乃欲納此江漫漫。", "奔流下赴故偪仄，汝更爭道當其前。", "舟師欹傾落膽過，石孽水禍吁難全。", "山川丘陵皆地險，惟此險絕餘難肩。", "東坡筆端喙三尺，願與作賦評嘲喧。", "云非此石峽更怒，臼頭忽作傾城妍。", "我從巫山飛一棹，歡喜偶脫蛟龍涎。", "是非信否未暇詰，且上高齋清晝眠。"]'),
('c64f3bf3-864a-4506-98de-f6064b2db0fe','夔州竹枝歌九首  其一','范成大','宋','宋诗','song-poetry','','[]','五月五日嵐氣開，南門競船爭看來。',32,'全唐诗/poet.song.137000.json','["五月五日嵐氣開，南門競船爭看來。", "雲安酒濃麴米賤，家家扶得醉人迴。"]'),
('abec942f-a22d-4638-a8a4-addbd39a856d','夔州竹枝歌九首  其二','范成大','宋','宋诗','song-poetry','','[]','赤甲白鹽碧叢叢，半山人家草木風。',32,'全唐诗/poet.song.137000.json','["赤甲白鹽碧叢叢，半山人家草木風。", "榴花滿山紅似火，荔子天凉未肯紅。"]'),
('3381b4b1-f9b4-42ba-9b09-061c99ed8dea','夔州竹枝歌九首  其三','范成大','宋','宋诗','song-poetry','','[]','新城果園連瀼西，枇杷壓枝杏子肥。',32,'全唐诗/poet.song.137000.json','["新城果園連瀼西，枇杷壓枝杏子肥。", "半青半黄朝出賣，日午買鹽沽酒歸。"]'),
('02cf6633-7fa9-487d-b7c1-0f685147ba33','夔州竹枝歌九首  其四','范成大','宋','宋诗','song-poetry','','[]','癭婦趁墟城裏來，十十五五市南街。',32,'全唐诗/poet.song.137000.json','["癭婦趁墟城裏來，十十五五市南街。", "行人莫笑女粗醜，兒郎自與買銀釵。"]'),
('199c880d-2fe8-4261-b428-08b76d072a4f','夔州竹枝歌九首  其五','范成大','宋','宋诗','song-poetry','','[]','白頭老媼篸紅花，黑頭女娘三髻丫。',32,'全唐诗/poet.song.137000.json','["白頭老媼篸紅花，黑頭女娘三髻丫。", "背上兒眠上山去，採桑已閑當採茶。"]'),
('6c0954b8-671b-4846-9a21-dcc4a470e8a2','夔州竹枝歌九首  其六','范成大','宋','宋诗','song-poetry','','[]','百衲畬山青間紅，粟莖成穗豆成叢。',32,'全唐诗/poet.song.137000.json','["百衲畬山青間紅，粟莖成穗豆成叢。", "東屯平田秔米軟，不到貧人飯甑中。"]'),
('ffa21179-a886-4fbe-8cfa-740ceb45f37a','夔州竹枝歌九首  其七','范成大','宋','宋诗','song-poetry','','[]','白帝廟前無舊城，荒山野草古今情。',32,'全唐诗/poet.song.137000.json','["白帝廟前無舊城，荒山野草古今情。", "只餘峽口一堆石，恰似人心未肯平。"]'),
('9492e67c-8f54-4d09-b6f7-9d8526b69675','夔州竹枝歌九首  其八','范成大','宋','宋诗','song-poetry','','[]','灧澦如襆瞿唐深，魚復陣圖江水心。',32,'全唐诗/poet.song.137000.json','["灧澦如襆瞿唐深，魚復陣圖江水心。", "大昌鹽船出巫峽，十日溯流無信音。"]'),
('d1c251ae-2120-471c-b2b7-096bceee7c1f','夔州竹枝歌九首  其九','范成大','宋','宋诗','song-poetry','','[]','當筵女兒歌竹枝，一聲三疊客忘歸。',32,'全唐诗/poet.song.137000.json','["當筵女兒歌竹枝，一聲三疊客忘歸。", "萬里橋邊有船到，繡羅衣服生光輝。"]'),
('140ca0e8-3693-4710-abc9-e1d0c03c6d7d','雲安縣','范成大','宋','宋诗','song-poetry','','[]','春暮子規少，日斜紅鵠飛。',48,'全唐诗/poet.song.137000.json','["春暮子規少，日斜紅鵠飛。", "兩山多布水，一島幾柴扉。", "蚓吐無窮壤，人行不斷磯。", "巴陽昨夜雨，灘上水先肥。"]'),
('65b8e610-010b-4fbe-91b0-af28e6b3c354','萬州','范成大','宋','宋诗','song-poetry','','[]','晨炊維下巖，晚酌檥南浦。',120,'全唐诗/poet.song.137000.json','["晨炊維下巖，晚酌檥南浦。", "波心照州榜，雲脚響衙鼓。", "前山如屏牆，得得正當戶。", "西江朝宗來，循屏復東去。", "官曹倚巖棲，市井喚船渡。", "瓦屋仄石磴，猿啼閙人語。", "剔核杏餘酸，連枝茶剩苦。", "窮鄉固瘠薄，陋俗亦寒窶。", "營營謀食艱，寂寂懷磚訴。", "昔聞吏隠名，今識吏隠處。"]'),
('10611cca-2ad9-4383-897d-e97f93ccc8bd','橫溪驛感懷','范成大','宋','宋诗','song-poetry','','[]','行徧天涯與地隅，筋骸那比十年初。',64,'全唐诗/poet.song.137000.json','["行徧天涯與地隅，筋骸那比十年初。", "朱顔有酒且留住，白髮無方能埽除。", "未得歸田先作賦，專攻種樹已成書。", "祗今飛到南山下，猶解清晨出荷鋤。"]'),
('4cb04e10-0ab4-4596-a853-c097cf588fd6','午夜登嶓山','范成大','宋','宋诗','song-poetry','','[]','癉暑嚴夜裝，乘凉躡危嶠。',144,'全唐诗/poet.song.137000.json','["癉暑嚴夜裝，乘凉躡危嶠。", "猿依黑林號，鬼閃青炬嘯。", "驚鳥動危葉，吟蟲滿荒草。", "泉聲遠相隨，山色近如杳。", "夢猶風燈前，身已雲木杪。", "浮生固有役，遠道何時了。", "豈惟失寢興，亦自倒昏曉。", "恭惟天心仁，頗議民力槁。", "我懷漢制詔，來慰蜀父老。", "熙如春臺登，沃若時雨膏。", "須知簡書急，勿厭蓐食早。", "但勤筆力淬，時助詩腸攪。"]'),
('14d87875-2b73-46ef-b702-7354f95a7ad6','峽石鋪','范成大','宋','宋诗','song-poetry','','[]','峰頭壁立偉天造，萬雉石城如带繞。',64,'全唐诗/poet.song.137000.json','["峰頭壁立偉天造，萬雉石城如带繞。", "山骨鱗皴火種難，山下流泉却宜稻。", "新秧一稜綠茸茸，茅花先秋雪搖風。", "后皇嘉種不易熟，野草何爲攙歲功。"]'),
('beef687b-7b49-446b-813b-a12f3acab559','蟠龍嶺','范成大','宋','宋诗','song-poetry','','[]','夷陵至𦚧䏰，複嶺苦絲亂。',144,'全唐诗/poet.song.137000.json','["夷陵至𦚧䏰，複嶺苦絲亂。", "初程尚勇往，少日還委頓。", "安得長劍揮，盡剷疊嶂斷。", "雖云北山愚，聊快南溟運。", "此意竟蕭索，勞歌謾淒曼。", "日日望平陸，念念到彼岸。", "人言束馬險，但欠蟠龍峻。", "摧頹强弩末，黽勉焚舟戰。", "譬如已償逋，猶有未折券。", "山根治曉裝，峰頂寄朝飯。", "稍脫蚓瘴染，還探虎窠翫。", "性命乃可憂，筋力何足算。"]'),
('46df54fe-5422-4c91-b8a2-5a55aea7c7f7','蟠龍瀑布自山頂漫汗淋漓分數道而下望之宛從天降當爲城中布水第一','范成大','宋','宋诗','song-poetry','','[]','銀漢來從左界天，天風吹浪落蒼巔。',32,'全唐诗/poet.song.137000.json','["銀漢來從左界天，天風吹浪落蒼巔。", "人間只見秧田潤，喚作蟠龍洞裏泉。"]'),
('bfe3fac6-0868-450b-b138-43ed6bec41c4','峰門嶺遇雨泊梁山','范成大','宋','宋诗','song-poetry','','[]','窮鄉誰與話悲酸，駐馬看雲强自寬。',64,'全唐诗/poet.song.137000.json','["窮鄉誰與話悲酸，駐馬看雲强自寬。", "酒力無端妨宿病，詩情不淺任塵官。", "虎狼地僻炊煙晚，風雨天低夏木寒。", "行盡峰門千萬丈，梁山鼓角報平安。"]'),
('71a35076-900b-443d-9ca2-2a0d23070faf','𨚩䢹驛大雨','范成大','宋','宋诗','song-poetry','','[]','暮雨連朝雨，長亭又短亭。',48,'全唐诗/poet.song.137000.json','["暮雨連朝雨，長亭又短亭。", "今朝騎馬怯，平日繫船聽。", "竹葉垂頭碧，秧苗滿意青。", "農疇方可望，客路敢遑寧。"]'),
('c2805033-20bc-4af8-83f3-457c709a7c88','墊江縣','范成大','宋','宋诗','song-poetry','','[]','青泥沒髁僕頻驚，黄漲平橋馬不行。',64,'全唐诗/poet.song.137000.json','["青泥沒髁僕頻驚，黄漲平橋馬不行。", "舊雨雲招新雨至，高田水入下田鳴。", "百年心事終懷土，一日身謀且望晴。", "休入忠州爭米市，暝鴉同宿墊江城。"]'),
('7c653422-ae5d-4dca-9108-c0d5bb40efb6','巾子山又雨','范成大','宋','宋诗','song-poetry','','[]','百日籃輿困跼跧，三晨泥坂兀躋攀。',64,'全唐诗/poet.song.137000.json','["百日籃輿困跼跧，三晨泥坂兀躋攀。", "晚晴幸自墊江縣，今雨奈何巾子山。", "樹色於人殊漠漠，雲容憐我稍班班。", "如今只憶雪溪句，乘興而來興盡還。"]'),
('ebc01590-f63c-49d2-9f39-c99c829779cd','鄰山縣','范成大','宋','宋诗','song-poetry','','[]','山頂噓雲黑似煙，修篁高柳共昏然。',32,'全唐诗/poet.song.137000.json','["山頂噓雲黑似煙，修篁高柳共昏然。", "鳥啼一夜勸歸去，誰道東川無杜鵑。"]'),
('2dead486-a485-43a9-bbf4-3cad93e76ac1','沒冰鋪晚晴月出曉復大雨上漏下濕不堪其憂','范成大','宋','宋诗','song-poetry','','[]','晚色熹微煖似薰，兒童歡喜走相聞。',64,'全唐诗/poet.song.137000.json','["晚色熹微煖似薰，兒童歡喜走相聞。", "無端星月照濕土，依舊山川生雨雲。", "旅枕夢寒涔屋漏，征衫潮潤冷爐熏。", "快晴信是行人願，又恐田家曝背耘。"]'),
('1fba1631-5204-4c67-91ae-aa6f0fd8430f','金山嶺','范成大','宋','宋诗','song-poetry','','[]','阪峻身頻偃，崖深首屢回。',48,'全唐诗/poet.song.137000.json','["阪峻身頻偃，崖深首屢回。", "雲浮平地出，路拂半天來。", "但閲關山過，都忘歲月催。", "湘南初上馬，猶插早春梅。"]'),
('8f94a284-75ef-4966-97bc-7be46bee3deb','明日至鄰水又雨','范成大','宋','宋诗','song-poetry','','[]','昨日方無雨，今朝又不晴。',48,'全唐诗/poet.song.137000.json','["昨日方無雨，今朝又不晴。", "滿山皆屐齒，隨處有泉聲。", "頗怪陰霖差，應催老病成。", "泥塗千騎士，與我共勞生。"]'),
('99cc2639-2457-4e20-9ac3-b290d83ff863','殘夜至峰頂上','范成大','宋','宋诗','song-poetry','','[]','片月挂高嶺，我行至其巔。',120,'全唐诗/poet.song.137000.json','["片月挂高嶺，我行至其巔。", "舉手欲攬擷，恐驚乘鸞仙。", "菲菲桂香動，肅肅露脚寒。", "北斗已到地，南斗猶闌干。", "但聞浮黎音，來從始青天。", "大星與之俱，曉色明旗旛。", "素煙渺陸海，中有人所寰。", "想見地上友，啟明膏火煎。", "星落玉宇白，日生綺霞丹。", "冰輪未肯去，相看尚團團。"]'),
('02d119a9-d66d-424a-a65d-898203208788','望鄉臺','范成大','宋','宋诗','song-poetry','','[]','千山已盡一峰孤，立馬行人莫疾驅。',32,'全唐诗/poet.song.137000.json','["千山已盡一峰孤，立馬行人莫疾驅。", "從此蜀川平似掌，更無高處望東吳。"]'),
('c6c0d650-4daf-4ae9-a86d-8b43054a4d1a','蚤晴發廣安軍晚宿萍池村莊','范成大','宋','宋诗','song-poetry','','[]','夜雨洗煩蒸，曉風薦清穆。',120,'全唐诗/poet.song.137000.json','["夜雨洗煩蒸，曉風薦清穆。", "雲頭隤鐵山，日脚迸金瀑。", "暑塗一日凉，遠客萬事足。", "羈人正奔波，觀者何陸續。", "翠蓋立嚴粧，青裙行跣足。", "俗陋介南徼，物華入東蜀。", "竹萌苦已青，荔子酸猶綠。", "修蘆密成籬，直柏森似纛。", "泥乾馬蹄鬆，路坦亭堠速。", "暮投何人莊，窗戶暗修竹。"]'),
('a8a06f47-0365-40c1-9106-0f43fda7f366','巴蜀人好食生蒜臭不可近頃在嶠南其人好食檳榔合蠣灰扶留藤一名蔞藤食之輒昏然已而醒快三物合和唾如膿血可厭今來蜀道又爲食蒜者所薰戲題','范成大','宋','宋诗','song-poetry','','[]','旅食諳殊俗，堆盤駭異聞。',48,'全唐诗/poet.song.137000.json','["旅食諳殊俗，堆盤駭異聞。", "南餐灰薦蠣，巴饌菜先葷。", "幸脫蔞藤醉，還遭胡蒜熏。", "絲蓴鄉味好，歸夢水連雲。"]'),
('7084c1b8-a674-403d-8a0e-6ff951f0dbcd','嘉陵江過合州漢初縣下','范成大','宋','宋诗','song-poetry','','[]','井徑東川縣，山河古合州。',48,'全唐诗/poet.song.137000.json','["井徑東川縣，山河古合州。", "木根拏斷岸，急雨沸中流。", "關下嘉陵水，沙頭杜老舟。", "江花應好在，無計會江樓。"]'),
('7ef325ef-c799-4b89-8a8a-1a89ce928e10','新晴行郪水上與涪江相近','范成大','宋','宋诗','song-poetry','','[]','塗泥初乾雨不落，日色未出暑光薄。',64,'全唐诗/poet.song.137000.json','["塗泥初乾雨不落，日色未出暑光薄。", "畏途得晴天復凉，真是腰錢更騎鶴。", "渾渾郪水流未平，悄悄涪江如鏡清。", "過盡江沙穿麥壠，忽有青蜩扶葉鳴。"]'),
('804ef3f5-aec7-4205-88cd-88af30a91af6','小溪縣','范成大','宋','宋诗','song-poetry','','[]','刈麥千平壠，橫槎一小溪。',48,'全唐诗/poet.song.137000.json','["刈麥千平壠，橫槎一小溪。", "梓花紅綻碎，粟穗綠垂低。", "村婦猶多跣，山猿遂少啼。", "東川雖已過，錦里尚雲西。"]'),
('96e74af1-03b8-410b-8ccd-957f0ede4260','茸山道中感懷','范成大','宋','宋诗','song-poetry','','[]','侍臣筆橐舊西班，大將麾幢又百蠻。',64,'全唐诗/poet.song.137000.json','["侍臣筆橐舊西班，大將麾幢又百蠻。", "挂席南箕宿昔事，閃旗東井何時還。", "日增衰病復一日，山隔舊遊知幾山。", "倦拂盤陀蒼石坐，歸心聊與石俱頑。"]'),
('598d24ca-d4f4-475b-98b9-8fb25202c387','曉發飛鳥晨霞滿天少頃大雨吳諺云朝霞不出門暮霞行千里驗之信然戲紀其事','范成大','宋','宋诗','song-poetry','','[]','朝霞不出門，暮霞行千里。',192,'全唐诗/poet.song.137000.json','["朝霞不出門，暮霞行千里。", "今晨日未出，曉氣散如綺。", "心疑雨再作，眼轉雲四起。", "我豈知天道，吳農諺云爾。", "古來占滂沲，說者類恢詭。", "飛雲走羣羊，停雲浴三豨。", "月當天畢宿，風自少女起。", "爛石燒成香，汗礎潤如洗。", "逐婦鳩能拙，穴居狸有智。", "蜉蝣强知時，蜥蜴與聞計。", "垤鳴東山鸛，堂審南柯蟻。", "或加陰石鞭，或議陽門閉。", "或云逢庚變，或自換甲始。", "刑鵝與象龍，聚訟非一理。", "不如老農諺，響應捷如鬼。", "哦詩敢夸博，聊用醒午睡。"]'),
('4235ec21-6c55-4b4a-8aea-cd3f60309bb2','遂寧府始見平川喜成短歌','范成大','宋','宋诗','song-poetry','','[]','峽之西，遂之東。',168,'全唐诗/poet.song.137000.json','["峽之西，遂之東。", "更無平地二千里，惟有高山三萬重。", "不知誰人鑿混沌，獨此融結何其工。", "我本江吳弄水月，忽來踏徧西南峰。", "不知塵界在何許，但怪星辰浮半空。", "直疑飛入蝶夢境，此豈應有人行蹤。", "今朝平遠見城郭，云是東川軍府雄。", "原田坦若看掌上，沙路浄如行鏡中。", "芋區粟壠潤含雨，楮林竹徑凉生風。", "將士懽呼馬蹄快，康莊直與錦里通。", "半年崎嶇得夷路，一笑未暇憐飄蓬。"]'),
('55ea6bd5-9f85-4c3e-8eb0-994bff028264','九月十九日衙散回留大將及幕屬飲清心堂觀晚菊分韻得譟暮字','范成大','宋','宋诗','song-poetry','','[]','甲光射曾雲，雨脚不敢到。',120,'全唐诗/poet.song.137000.json','["甲光射曾雲，雨脚不敢到。", "西山明古雪，秋日一竿照。", "先偏井絡密，後拒參旗掉。", "分弓滴博平，鳴劍伊吾小。", "君看天山箭，狐兔何足了。", "開邊吾豈敢，自治有餘巧。", "歸來翠帷卷，聊共黄花笑。", "雖無落帽風，亦復接䍦倒。", "餘閒校筆陣，刻燭龍蛇埽。", "毛錐乃更勇，我亦鼓旗譟。"]'),
('322cf98e-97c4-4bfe-8794-76e38f23978b','冬至日銅壺閣落成','范成大','宋','宋诗','song-poetry','','[]','走徧人間行路難，異鄉風物雜悲歡。',64,'全唐诗/poet.song.137000.json','["走徧人間行路難，異鄉風物雜悲歡。", "三年北戶梅邊暖，萬里西樓雪外寒。", "已辦鬢霜供歲籥，仍拚髀肉了征鞍。", "故園雲物知何似，試上東樓直北看。"]'),
('cb460ae4-9b89-455e-8bea-4d089e5ad33b','十二月十八日海雲賞山茶','范成大','宋','宋诗','song-poetry','','[]','追趁新晴管物華，馬蹄鬆快帽檐斜。',64,'全唐诗/poet.song.137000.json','["追趁新晴管物華，馬蹄鬆快帽檐斜。", "天南臘盡風晞雪，冰下春來水潄沙。", "已報主林催市柳，仍從掌故問山茶。", "豐年自是驩聲沸，更著牙前畫鼓撾。"]'),
('43843d4c-dda4-4f1a-8336-f50d3e83c508','雨後東郭排岸司申梅開方及三分戲書小絕令一面開燕','范成大','宋','宋诗','song-poetry','','[]','雨入南枝玉蕊皴，合江雲冷凍芳塵。',32,'全唐诗/poet.song.137000.json','["雨入南枝玉蕊皴，合江雲冷凍芳塵。", "司花好事相邀勒，不著笙歌不肯春。"]'),
('56a10f88-6c41-4368-885b-a4f5331dc4ad','鞭春微雨','范成大','宋','宋诗','song-poetry','','[]','旛勝絲絲雨，笙歌步步塵。',48,'全唐诗/poet.song.137000.json','["旛勝絲絲雨，笙歌步步塵。", "一年新樂事，萬里未歸人。", "雲薄竟慳雪，酒濃先受春。", "送寒東作近，慚愧耦耕身。"]'),
('8ef93d4a-796c-4d72-96bf-594ff44a956f','綠萼梅','范成大','宋','宋诗','song-poetry','','[]','朝罷東皇放玉鸞，霜羅薄袖綠裙單。',32,'全唐诗/poet.song.137000.json','["朝罷東皇放玉鸞，霜羅薄袖綠裙單。", "貪看修竹忘歸路，不管人間日暮寒。"]'),
('ab81923f-a3c8-4ab7-b56a-dd33394437c1','玉茗花','范成大','宋','宋诗','song-poetry','','[]','折得瑶華付與誰，人間鉛粉弄粧遲。',32,'全唐诗/poet.song.137000.json','["折得瑶華付與誰，人間鉛粉弄粧遲。", "直須遠寄驂鸞客，鬢脚飄飄可一枝。"]'),
('50321a76-f4d0-478b-8472-f166e009d6b5','張正字母夫人朱氏輓詞','范成大','宋','宋诗','song-poetry','','[]','蘋藻儀邦媛，詩書了歲華。',48,'全唐诗/poet.song.137000.json','["蘋藻儀邦媛，詩書了歲華。", "籯金寧遺子，羣玉竟傳家。", "厚施心無斁，浮生自有涯。", "空餘報恩子，三載亦苴麻。"]'),
('0493d0ba-d566-4b13-ad69-bcda19771951','十二月二十四日西樓觀雪','范成大','宋','宋诗','song-poetry','','[]','一夜珠簾不下鈎，徹明隨雪上西樓。',64,'全唐诗/poet.song.137000.json','["一夜珠簾不下鈎，徹明隨雪上西樓。", "瑶池萬頃崑崙近，玉壘千峰滴博收。", "已報春迴南畝潤，從教寒勒北枝愁。", "四筵都爲豐年醉，錄事何須校酒籌。"]'),
('b281c836-87cd-40fe-96e5-6f5cf1c891b0','丙申元日安福寺禮塔','范成大','宋','宋诗','song-poetry','','[]','嶺梅蜀柳笑人忙，歲歲椒盤各異方。',64,'全唐诗/poet.song.137000.json','["嶺梅蜀柳笑人忙，歲歲椒盤各異方。", "耳畔逢人無魯語，鬢邊隨我是吳霜。", "新年後飲屠蘇酒，故事先然窣堵香。", "石筍新街好行樂，與民同處且逢場。"]'),
('512a8123-2de5-4bf0-87c1-afa3314ab65d','初三日出東郊碑樓院','范成大','宋','宋诗','song-poetry','','[]','遠柳新晴暝紫煙，小江吹凍舞清漣。',32,'全唐诗/poet.song.137000.json','["遠柳新晴暝紫煙，小江吹凍舞清漣。", "紅塵一鬨人歸後，跕跕饑鳶蹙紙錢。"]'),
('173b50e4-e3ce-459d-9fb8-d74602216f50','郊外閲驍騎剪柳','范成大','宋','宋诗','song-poetry','','[]','千騎同瞻白羽揮，驚塵一鬨響金鞿。',32,'全唐诗/poet.song.137000.json','["千騎同瞻白羽揮，驚塵一鬨響金鞿。", "不知掣電彎弓過，但覺柳梢隨箭飛。"]'),
('479eac5e-acff-46cc-ae84-6c11d0d3d3bc','初四日東郊觀麥苗','范成大','宋','宋诗','song-poetry','','[]','去歲秋霖麥下遲，臘殘一雪潤無泥。',32,'全唐诗/poet.song.137000.json','["去歲秋霖麥下遲，臘殘一雪潤無泥。", "相將飽喫滹沱飯，來聽林間快活啼。"]'),
('8167b57c-4996-4ec9-9110-2e9597fca749','櫻桃花','范成大','宋','宋诗','song-poetry','','[]','借煖衝寒不用媒，勻朱勻粉最先來。',32,'全唐诗/poet.song.137000.json','["借煖衝寒不用媒，勻朱勻粉最先來。", "玉梅一見憐癡小，教向傍邊自在開。"]'),
('cef3c983-9b5b-476a-8d4b-957ee29dfcb4','再出東郊','范成大','宋','宋诗','song-poetry','','[]','晚景增年慣，官身作客諳。',48,'全唐诗/poet.song.137000.json','["晚景增年慣，官身作客諳。", "大都緣偶熟，豈是性能堪。", "昔者開三徑，他時老一龕。", "越溪親種竹，芸綠想毿毿。"]'),
('bee4557a-a16a-4cbe-ac7e-f4a9dc770d71','三月二日北門馬上','范成大','宋','宋诗','song-poetry','','[]','新街如拭過鳴騶，芍藥酴醿競滿頭。',32,'全唐诗/poet.song.137000.json','["新街如拭過鳴騶，芍藥酴醿競滿頭。", "十里珠簾都捲上，少城風物似揚州。"]'),
('fd69ed7b-a3a7-422f-8d2b-fc6248adb811','上巳前一日學射山萬歲池故事','范成大','宋','宋诗','song-poetry','','[]','北郊征路記前回，三尺驚塵馬踏開。',64,'全唐诗/poet.song.137000.json','["北郊征路記前回，三尺驚塵馬踏開。", "新漲忽明多病眼，好風如把及時杯。", "青黄麥壠平平去，疎密榿林整整來。", "游騎不知都幾許，長堤十里轉輕雷。"]'),
('3c5b84e7-c9e2-4058-a85e-2de5d196a017','上巳日萬歲池上呈程詠之提刑','范成大','宋','宋诗','song-poetry','','[]','濃春酒煖絳煙霏，漲水天平雪浪遲。',64,'全唐诗/poet.song.137000.json','["濃春酒煖絳煙霏，漲水天平雪浪遲。", "綠岸翻鷗如北渚，紅塵躍馬似西池。", "麥苗剪剪嘗新麫，梅子雙雙带折枝。", "試比長安水邊景，衹無饑客爲題詩。"]'),
('dfe2d60e-a178-4792-bedc-0c8ec9a3f9fb','新作錦亭程詠之提刑賦詩次其韻二首  其一','范成大','宋','宋诗','song-poetry','','[]','飛鴻銜子謾紛紛，萬里西遊始識真。',64,'全唐诗/poet.song.137000.json','["飛鴻銜子謾紛紛，萬里西遊始識真。", "不管吳霜微點鬢，來看蜀錦爛爭春。", "倚闌定有司花女，秉燭仍留主夜神。", "異縣賞心誰與共，故人新作坐中賓。"]'),
('dff26be7-bca3-4317-a550-ce20f458596e','新作錦亭程詠之提刑賦詩次其韻二首  其二','范成大','宋','宋诗','song-poetry','','[]','小築聊鋤草棘荒，遊人錯比召南棠。',64,'全唐诗/poet.song.137000.json','["小築聊鋤草棘荒，遊人錯比召南棠。", "花邊霧鬢風鬟滿，酒畔雲衣月扇香。", "燦爛吟牋煩索句，淋漓醉墨自成行。", "報章遲鈍吾衰矣，終日冥搜謾七襄。"]'),
('ed6b9f3a-f136-47f9-910d-5cd5d3fceb3c','錦亭然燭觀海棠','范成大','宋','宋诗','song-poetry','','[]','銀燭光中萬綺霞，醉紅堆上缺蟾斜。',32,'全唐诗/poet.song.137000.json','["銀燭光中萬綺霞，醉紅堆上缺蟾斜。", "從今勝絕西園夜，壓盡錦官城裏花。"]'),
('7130f0d3-2967-42bf-b881-0a31b9ec9e96','寶相花','范成大','宋','宋诗','song-poetry','','[]','誰把柔條夾砌栽，壓枝萬朶一時開。',32,'全唐诗/poet.song.137000.json','["誰把柔條夾砌栽，壓枝萬朶一時開。", "爲君也著詩收拾，題作西樓錦被堆。"]'),
('cbd6ab17-85db-435c-9aad-335bf06b9b1d','三月二十三日海雲摸石','范成大','宋','宋诗','song-poetry','','[]','勸耕亭上往來頻，四海萍浮老病身。',64,'全唐诗/poet.song.137000.json','["勸耕亭上往來頻，四海萍浮老病身。", "亂插山茶猶昨夢，重尋池石已殘春。", "驚心歲月東流水，過眼人情一鬨塵。", "頼有貽牟堪飽飯，道逢田畯且眉伸。"]'),
('70f48dbb-777c-48f4-8bad-bb70748b8b1e','四月十日出郊','范成大','宋','宋诗','song-poetry','','[]','約束南風徹曉忙，收雲捲雨一川凉。',64,'全唐诗/poet.song.137000.json','["約束南風徹曉忙，收雲捲雨一川凉。", "漲江混混無聲綠，熟麥騷騷有意黄。", "吏卒遠時閒信馬，田園佳處忽思鄉。", "鄰翁萬里應相念，春晚不歸同插秧。"]'),
('372b9819-d204-4143-a059-9cccdee3e869','納凉','范成大','宋','宋诗','song-poetry','','[]','雨洗新秋夜氣清，悴肌無汗葛衣輕。',32,'全唐诗/poet.song.137000.json','["雨洗新秋夜氣清，悴肌無汗葛衣輕。", "畫檐分月下西壁，絡緯飛來庭樹鳴。"]'),
('05905684-2d0d-4787-8a8b-9f15b1db3957','西樓獨上','范成大','宋','宋诗','song-poetry','','[]','竹日駐微暑，松風生早秋。',48,'全唐诗/poet.song.137000.json','["竹日駐微暑，松風生早秋。", "閒尋來處路，獨倚靜中樓。", "老景驅雙轂，鄉心挽萬牛。", "相隨木上坐，脚底亦雲浮。"]'),
('7feb1b02-b396-4234-a07a-c8f0a3e328bb','曉詣三井觀','范成大','宋','宋诗','song-poetry','','[]','路轉市聲遠，寬閒古城東。',72,'全唐诗/poet.song.137000.json','["路轉市聲遠，寬閒古城東。", "適從紅塵來，忽入蒼煙叢。", "槿心傾穠露，芋葉翻微風。", "秋陽澹籬落，殘暑不必攻。", "野老熟睡起，日高首如蓬。", "官身騎官馬，君應笑龍鍾。"]'),
('ee53cde7-d490-493c-8a8b-06f9dfb7264f','曉起','范成大','宋','宋诗','song-poetry','','[]','黠鼠緣鈴索，饑鴉啄井欄。',48,'全唐诗/poet.song.137000.json','["黠鼠緣鈴索，饑鴉啄井欄。", "不眠秋漏近，多病曉屏寒。", "咄咄渠何怪，休休我自闌。", "牙門朝日上，簫鼓報平安。"]'),
('a4823c33-9568-4704-b44d-5a897d2c7331','舫齋晚憩','范成大','宋','宋诗','song-poetry','','[]','心作萬緣起，境生千劫忙。',48,'全唐诗/poet.song.137000.json','["心作萬緣起，境生千劫忙。", "誰同油幕靜，獨對篆煙長。", "有盡天魔力，無窮海印光。", "雨餘弦月上，塵界本清凉。"]'),
('8aefb91b-3fd4-4407-b973-183d8d5ae78e','秋雨快晴靜勝堂席上','范成大','宋','宋诗','song-poetry','','[]','一笑憧憧鴈鶩行，簿書堆裏賦秋陽。',64,'全唐诗/poet.song.137000.json','["一笑憧憧鴈鶩行，簿書堆裏賦秋陽。", "心如墜絮沾泥懶，身似飛泉激石忙。", "雨後蹲鴟先稻熟，霜前浮蟻鬭棖香。", "天涯節物遮愁眼，且復隨鄉便入鄉。"]'),
('bccfd70f-093c-45b8-a0e4-81cdcac9035e','新凉夜坐','范成大','宋','宋诗','song-poetry','','[]','吏退焚香百慮空，靜聞蟲響度簾櫳。',64,'全唐诗/poet.song.137000.json','["吏退焚香百慮空，靜聞蟲響度簾櫳。", "江頭一尺稻花雨，窗外三更蕉葉風。", "日日老添明鏡裏，家家凉入短檠中。", "簡編燈火平生事，雪白眵昏奈此翁。"]'),
('2a0352ca-ccc5-494a-948b-d8cd068ee985','秋老四境雨已沛然晚坐籌邊樓方議祈晴樓下忽有東界農民數十人訴山田却要雨須長吏致禱感之作詩','范成大','宋','宋诗','song-poetry','','[]','歲晚羈懷有所思，秋來病骨最先知。',64,'全唐诗/poet.song.137000.json','["歲晚羈懷有所思，秋來病骨最先知。", "鏡中公案已甘老，紙上課程休諱癡。", "西堰頗聞江漲急，東山猶說雨來遲。", "錦城樂事知多少，憂旱憂霖蹙盡眉。"]'),
('98fbe84e-19a4-41dd-b2cb-b704f317d11c','西樓夜坐','范成大','宋','宋诗','song-poetry','','[]','抗塵懷抱若爲寬，繞屋蛙聲亦在官。',64,'全唐诗/poet.song.137000.json','["抗塵懷抱若爲寬，繞屋蛙聲亦在官。", "巖桂無香秋遂晚，江鱸有約歲將寒。", "文書散亂嘲癡絕，燈火淒清語夜闌。", "病倦百骸非復我，但思禪板與蒲團。"]'),
('0fc9cbaf-eece-4f8c-a143-ac92f3b2e5b7','立秋月夜','范成大','宋','宋诗','song-poetry','','[]','已放新凉入簟紋，更驅餘溽避爐薰。',64,'全唐诗/poet.song.137000.json','["已放新凉入簟紋，更驅餘溽避爐薰。", "穿雲竹月時時見，咽露莎蛩院院聞。", "稍喜雪山無斥堠，但虞煙驛有移文。", "行藏且付蘧蘧夢，明發還親鴈鶩羣。"]'),
('247afadf-d798-4624-8ffe-e7c70cd08825','前堂觀月','范成大','宋','宋诗','song-poetry','','[]','箕踞繩牀政自豪，遠遊何暇續離騷。',64,'全唐诗/poet.song.137000.json','["箕踞繩牀政自豪，遠遊何暇續離騷。", "蕭森萬竹秋逾瘦，突兀雙楠夜更高。", "東郭風喧三鼓市，西城石洶二江濤。", "色塵聲界如如現，本自無禪不用逃。"]'),
('630426bc-8263-4e28-aa62-357a7f407b0f','有懷石湖舊隠','范成大','宋','宋诗','song-poetry','','[]','浩蕩沙鷗久倦飛，摧頹櫪馬不勝鞿。',64,'全唐诗/poet.song.137000.json','["浩蕩沙鷗久倦飛，摧頹櫪馬不勝鞿。", "官中風月常虛度，夢裏關山或暫歸。", "橘社十年霜欲飽，鱸江一雨水應肥。", "冷雲著地塘蒲晚，誰爲披蓑煖釣磯。"]'),
('64b651ff-7f9a-4c41-9e42-92f238b15a7d','太平瑞聖花','范成大','宋','宋诗','song-poetry','','[]','雪外捫參嶺，煙中濯錦洲。',48,'全唐诗/poet.song.137000.json','["雪外捫參嶺，煙中濯錦洲。", "密攢文杏蕊，高結綵雲毬。", "百世嘉名重，三登瑞氣浮。", "挽春同住夏，看到火西流。"]'),
('668aba57-2990-4214-881f-b149cdc64f1f','無題','范成大','宋','宋诗','song-poetry','','[]','聞道明朝送舊官，無情更鼓夜將闌。',32,'全唐诗/poet.song.137000.json','["聞道明朝送舊官，無情更鼓夜將闌。", "此生見面知何日，忍淚須臾子細看。"]'),
('eb1907aa-2a79-4410-99d7-b5779e2a4adb','晁子西寄詩謝酒自言其家數有逝者詞意悲甚次韻解之且以建茶同往','范成大','宋','宋诗','song-poetry','','[]','我讀晁子詩，十語九慨傷。',144,'全唐诗/poet.song.137000.json','["我讀晁子詩，十語九慨傷。", "長川日夜逝，鬢髮空蒼浪。", "君家出世學，無生亦無亡。", "鄉謂法幢立，何乃槁木僵。", "起滅不滿笑，古來共楸行。", "豈其捏目華，解翳海印光。", "我酒愧薄薄，未能煖愁腸。", "申以春風芽，一瀹萬慮忘。", "慧刀儻未割，會且掀禪牀。", "錦里有逢迎，謹避舍蓋堂。", "居然足音跫，好在故意長。", "啁耳念一洗，遲君鳳鳴岡。"]'),
('2c7c0852-eec9-4b80-904e-00d298f276d7','早衰不寐','范成大','宋','宋诗','song-poetry','','[]','官事拘攣似力田，作勞歸晚意茫然。',64,'全唐诗/poet.song.137000.json','["官事拘攣似力田，作勞歸晚意茫然。", "按摩合體俱非我，展轉通宵似遠年。", "一叟披衣惟兀坐，羣兒得枕便佳眠。", "人生元是華胥客，休向迷塗更著鞭。"]'),
('49498700-8a47-4559-ac50-c2876289d0cb','晚步宣華舊苑','范成大','宋','宋诗','song-poetry','','[]','喬木如山廢苑西，古溝疎水靜鳴池。',64,'全唐诗/poet.song.137000.json','["喬木如山廢苑西，古溝疎水靜鳴池。", "吏兵窸窣番更後，樓閣崔嵬欲暝時。", "有露冷螢猶照草，無風驚雀自遷枝。", "歸來更了程書債，目眚昏花燭穗垂。"]'),
('9866ba5d-49d9-4dd7-a7e3-dc35cc76d745','西樓秋晚','范成大','宋','宋诗','song-poetry','','[]','樓前處處長秋苔，俛仰璿杓又欲回。',64,'全唐诗/poet.song.137000.json','["樓前處處長秋苔，俛仰璿杓又欲回。", "殘暑已隨梁燕去，小春應爲海棠來。", "客愁天遠詩無託，吏案山橫睡有媒。", "晴日滿窗鳬鶩散，巴童來按鴨爐灰。"]'),
('1a536026-7425-49c9-abbb-30a53a0bd4ef','明日分弓亭按閲再用西樓韻','范成大','宋','宋诗','song-poetry','','[]','眼看白露點蒼苔，歲月飛流首屢回。',64,'全唐诗/poet.song.137000.json','["眼看白露點蒼苔，歲月飛流首屢回。", "老去讀書隨忘却，醉中得句若飛來。", "聞雞午夜猶能舞，射雉西郊不用媒。", "自笑支離聊復爾，丹心元未十分灰。"]'),
('ebbb3ab7-3e28-4e7a-9ba7-2c21e82e0bf9','丁酉重九藥市呈坐客','范成大','宋','宋诗','song-poetry','','[]','莫向登臨怨落暉，自緣羈宦阻歸期。',64,'全唐诗/poet.song.137000.json','["莫向登臨怨落暉，自緣羈宦阻歸期。", "年來厭把三邊酒，此去休哦萬里詩。", "烏帽不辭欹短髮，黄花終是欠東籬。", "若無合坐揮毫健，誰解西風楚客悲。"]'),
('d1c440f5-5425-44e9-af6d-f014855d05fb','會慶節大慈寺茶酒','范成大','宋','宋诗','song-poetry','','[]','霜暉催曉五雲鮮，萬國歡呼共一天。',64,'全唐诗/poet.song.137000.json','["霜暉催曉五雲鮮，萬國歡呼共一天。", "澹澹煖紅旗轉日，浮浮寒碧瓦收煙。", "銜杯樂聖千秋節，擊鼓迎冬大有年。", "忽憶捧觴供玉座，不知身在雪山邊。"]'),
('12c33fd5-794d-493e-b5be-64cc479f0754','冬至日天慶觀朝拜雲日晴麗遥想郊禋慶成作驩喜口號','范成大','宋','宋诗','song-poetry','','[]','淅淅霜風不滿旗，紫煙黄氣捧朝曦。',64,'全唐诗/poet.song.137000.json','["淅淅霜風不滿旗，紫煙黄氣捧朝曦。", "五更貫索埋光後，萬里鈎陳放仗時。", "留滯周南無舊事，布宣漢德有新詩。", "豐年四海皆溫飽，願把歡心壽玉巵。"]'),
('44bcb676-cc8a-42cf-8e3e-fc4f32f6270c','十一月十日海雲賞山茶','范成大','宋','宋诗','song-poetry','','[]','門巷歡呼十里村，臘前風物已知春。',64,'全唐诗/poet.song.137000.json','["門巷歡呼十里村，臘前風物已知春。", "兩年池上經行處，萬里天邊未去人。", "客鬢花身俱歲晚，粧光酒色且時新。", "海雲橋下溪如鏡，休把冠巾照路塵。"]'),
('f775ce02-fd59-4294-9bfb-0512b8de22e4','海雲回按驍騎於城北原時有吐番出沒大渡河上','范成大','宋','宋诗','song-poetry','','[]','古道風沙捲夕霏，小江煙浪皺春漪。',64,'全唐诗/poet.song.137000.json','["古道風沙捲夕霏，小江煙浪皺春漪。", "天於麥壠猶慳雪，人向梅梢大欠詩。", "頓轡青驪飛脫兔，離弦白羽嘯寒鴟。", "牙門列校俱剽銳，檄與河邊禿髮知。"]'),
('5d4de920-0412-4423-a1dc-94fe9651cbd8','合江亭隔江望瑶林莊梅盛開過江訪之馬上哦此','范成大','宋','宋诗','song-poetry','','[]','何處春能早，疎籬限激湍。',48,'全唐诗/poet.song.137000.json','["何處春能早，疎籬限激湍。", "竹間煙雪迥，馬上晚香寒。", "喚渡聊相覓，巡檐得細看。", "極知微雨意，未許日烘殘。"]'),
('1ad54fde-77e1-4218-97b4-e335d52a497f','新作官梅莊移植大梅數十本繞之','范成大','宋','宋诗','song-poetry','','["\u897f\u6e56"]','臘前催喚主林神，玉樹飛來不動塵。',64,'全唐诗/poet.song.137000.json','["臘前催喚主林神，玉樹飛來不動塵。", "契闊西湖慚處士，飄零東閣似詩人。", "一天午夢空花碎，滿地春愁月影新。", "掃浄宣華藜藋逕，他年誰記石湖濱。"]'),
('6940f51d-a376-45ac-ac20-817c65d38c82','丁酉正月二日東郊故事','范成大','宋','宋诗','song-poetry','','[]','椒盤宿酒未全醒，擾擾金鞍逐畫軿。',64,'全唐诗/poet.song.137000.json','["椒盤宿酒未全醒，擾擾金鞍逐畫軿。", "麥雨一犁隨處綠，柳煙千縷幾時青。", "客愁舊歲連新歲，歸路長亭間短亭。", "萬里松楸雙淚墮，風前安得諱飄零。"]'),
('65735e39-bda7-4ecc-a7c1-44aa5898ab8e','二月二十七日病後始能扶頭','范成大','宋','宋诗','song-poetry','','[]','複幕重簾苦見遮，暮占栖雀曉占鴉。',64,'全唐诗/poet.song.137000.json','["複幕重簾苦見遮，暮占栖雀曉占鴉。", "殘燈煮藥看成老，細雨鳴鳩過盡花。", "心爲蚤衰元自化，髮從無病已先華。", "更蒙厲鬼相提唱，此去山林屬當家。"]'),
('027cb59b-8e3f-4d28-b658-ef7b7c545280','病中聞西園新花已茂及竹逕皆成而海棠亦未過','范成大','宋','宋诗','song-poetry','','[]','梅塢桃蹊斫竹初，三旬高卧信音疎。',64,'全唐诗/poet.song.137000.json','["梅塢桃蹊斫竹初，三旬高卧信音疎。", "春雖與病無交涉，雨莫將花便破除。", "祗合蘧蘧隨夢去，何須咄咄向空書。", "頗聞蜀錦猶相待，去歲今朝已雪如。"]'),
('51851e50-d8a0-4dc0-926a-9591444fd33b','枕上','范成大','宋','宋诗','song-poetry','','[]','一枕經春似宿酲，三衾投曉尚淒清。',64,'全唐诗/poet.song.137000.json','["一枕經春似宿酲，三衾投曉尚淒清。", "殘更未盡鴉先起，虛幌無聲鼠自驚。", "久病厭聞銅鼎沸，不眠惟望紙窗明。", "摧頹豈是功名具，燒藥爐邊過此生。"]'),
('590d481f-9c8d-4521-8895-5fe76012a8f5','初履地','范成大','宋','宋诗','song-poetry','','[]','扶頭今日强冠篸，餘燼收從百戰酣。',64,'全唐诗/poet.song.137000.json','["扶頭今日强冠篸，餘燼收從百戰酣。", "長脛閣軀如瘦鶴，衝風奪氣似枯柟。", "客來慵抆懶殘涕，老去定同彌勒龕。", "何處更能容結習，任教花雨落毿毿。"]'),
('8ad2619b-d14e-4420-9a79-351738efcdfd','密室憊坐','范成大','宋','宋诗','song-poetry','','[]','如許頭顱莫振矜，但尋曲几與枯藤。',64,'全唐诗/poet.song.137000.json','["如許頭顱莫振矜，但尋曲几與枯藤。", "餘生不直一彈指，此病寧論三折肱。", "何處丹房癡候火，誰家籌室强傳燈。", "本來識字耕夫耳，今乃仍添百不能。"]'),
('4b96dba4-507f-4b6a-865e-00ccc41daf72','春晚初出西樓','范成大','宋','宋诗','song-poetry','','[]','試倚枯藤似籋雲，堂階微步小逡巡。',32,'全唐诗/poet.song.137000.json','["試倚枯藤似籋雲，堂階微步小逡巡。", "忽逢巖桂新抽葉，屈指黄紬睡一春。"]'),
('d4fa10f3-535c-48db-8851-7cf3951ad152','春晚卧病故事都廢聞西門種柳已成而燕宮海棠亦爛熳矣','范成大','宋','宋诗','song-poetry','','[]','軒窗深窈似禪房，竟日虛明裊斷香。',64,'全唐诗/poet.song.137000.json','["軒窗深窈似禪房，竟日虛明裊斷香。", "詩債無邊春已老，睡魔有約晝初長。", "市橋煙雨應官柳，墟苑池臺自海棠。", "游騎行歌莫相笑，遨頭六結已龜藏。"]'),
('677d511a-d9b4-4f47-9f9b-553335348fe0','病起初見賓僚時上疏丐祠未報','范成大','宋','宋诗','song-poetry','','[]','浪將冠服衣猿狙，因病偷閑稍自如。',64,'全唐诗/poet.song.137000.json','["浪將冠服衣猿狙，因病偷閑稍自如。", "時有好懷誇得句，略無情語怕回書。", "邊城晏閉稀傳箭，村巷春遊未荷鋤。", "迨此良辰公事少，天恩儻許賦歸歟。"]'),
('36409d76-7a29-4a7a-8ff8-ef2920d730f8','陸務觀云春初多雨近方晴碧雞坊海棠全未及去年  其一','范成大','宋','宋诗','song-poetry','','[]','遲日溫風護海棠，十分顔色醉春粧。',32,'全唐诗/poet.song.137000.json','["遲日溫風護海棠，十分顔色醉春粧。", "天公已許晴教好，說與鳴鳩一任忙。"]'),
('e038b218-5e04-4f00-9ef3-02d1377f753b','陸務觀云春初多雨近方晴碧雞坊海棠全未及去年  其二','范成大','宋','宋诗','song-poetry','','[]','報事碧雞坊裏來，今年花少似前回。',32,'全唐诗/poet.song.137000.json','["報事碧雞坊裏來，今年花少似前回。", "笙簧冷落遨頭病，不著梁州打不開。"]'),
('9c46e056-0f42-4565-b4d6-4c5de8e04324','清明日試新火作牡丹會','范成大','宋','宋诗','song-poetry','','[]','再鑽巴火尚浮家，去國年多客路賒。',64,'全唐诗/poet.song.137000.json','["再鑽巴火尚浮家，去國年多客路賒。", "那得青煙穿御柳，且將銀燭照京花。", "香鬟半醉斜枝重，病眼全昏瘴霧遮。", "錦地繡天春不散，任教檐雨捲泥沙。"]'),
('2b091429-1fff-4af8-bca5-9899d75f1822','三月十九日夜極冷','范成大','宋','宋诗','song-poetry','','[]','誰勒餘寒不放回，春深猶煖地爐灰。',64,'全唐诗/poet.song.137000.json','["誰勒餘寒不放回，春深猶煖地爐灰。", "鄉心忽向燈前動，夜雨先從竹裏來。", "鶗鴂已如鶑百囀，酴醿那復雪千堆。", "調糜煮藥東風老，慚愧茶甌與酒杯。"]'),
('02e55fa8-78b2-483c-8d53-4d8910f9e442','垂絲海棠','范成大','宋','宋诗','song-poetry','','[]','春工葉葉與絲絲，怕日嫌風不自持。',32,'全唐诗/poet.song.137000.json','["春工葉葉與絲絲，怕日嫌風不自持。", "曉鏡爲誰粧未辦，沁痕猶有淚臙脂。"]'),
('6594962b-2ca9-49c3-9bbc-dc8e2ab017b1','浣花戲題爭標者','范成大','宋','宋诗','song-poetry','','[]','凌波一劇便捐生，得失何曾較重輕。',32,'全唐诗/poet.song.137000.json','["凌波一劇便捐生，得失何曾較重輕。", "蝸角虛名人尚愛，錦標安得笑渠爭。"]'),
('43b8091e-a136-4fb0-b677-ff46b226fde7','鹿鳴宴','范成大','宋','宋诗','song-poetry','','[]','岷峨鍾秀蜀多珍，坐上儒先更逸羣。',64,'全唐诗/poet.song.137000.json','["岷峨鍾秀蜀多珍，坐上儒先更逸羣。", "墨沼不憂經覆瓿，琴臺重有賦凌雲。", "文章小技聊干祿，道學初心擬致君。", "富貴功名今發軔，願看稽古策高勳。"]'),
('a6448879-975a-4693-86a2-a2beef2e2445','陸務觀作春愁曲悲甚作詩反之','范成大','宋','宋诗','song-poetry','','[]','東風本是繁華主，天地元無著愁處。',64,'全唐诗/poet.song.137000.json','["東風本是繁華主，天地元無著愁處。", "詩人多事惹閒情，閒門自造愁如許。", "病翁老矣癡復頑，風前一笑春無邊。", "糟牀夜鳴如落泉，一杯正與人相關。"]'),
('c76593fd-3715-45d9-8696-313021bc5bfa','種竹了題愛山亭','范成大','宋','宋诗','song-poetry','','[]','灑掃宣華舍此君，煙中月下綠生塵。',32,'全唐诗/poet.song.137000.json','["灑掃宣華舍此君，煙中月下綠生塵。", "他年葉葉清風滿，莫忘今年借宅人。"]'),
('88c82d3e-05d6-4152-a9bc-34ed00bc784d','題錦亭','范成大','宋','宋诗','song-poetry','','[]','手開花徑錦成窠，浩蕩春風載酒過。',32,'全唐诗/poet.song.137000.json','["手開花徑錦成窠，浩蕩春風載酒過。", "來歲遊人應解笑，甘棠終少海棠多。"]'),
('097491f1-a6be-4a65-8f30-e956e8b31c5f','初發太城留別田父','范成大','宋','宋诗','song-poetry','','[]','秋苗五月未入土，行人欲行心更苦。',64,'全唐诗/poet.song.137000.json','["秋苗五月未入土，行人欲行心更苦。", "路逢田翁有好語，競說宿來三尺雨。", "行人雖去亦伸眉，翁皆好住莫相思。", "流渠湯湯聲滿野，今年醉飽雞豚社。"]'),
('aad28b9a-12b6-4dbe-8530-764fbca8c465','入崇寧界','范成大','宋','宋诗','song-poetry','','[]','桑間三宿尚回頭，何況三年濯錦遊。',32,'全唐诗/poet.song.137000.json','["桑間三宿尚回頭，何況三年濯錦遊。", "草草郫筒中酒處，不知身已在彭州。"]'),
('f441c871-4e23-4a9d-8237-f6e10a16a65f','懷古亭','范成大','宋','宋诗','song-poetry','','[]','朝來寫得故人書，雙鯉難尋鴈亦無。',32,'全唐诗/poet.song.137000.json','["朝來寫得故人書，雙鯉難尋鴈亦無。", "付與離堆江水去，解從郫縣到成都。"]'),
('5b2d169d-d007-402f-bcd7-382f753ab0f8','離堆行','范成大','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','殘山狠石雙虎卧，斧迹鱗皴中鑿破。',128,'全唐诗/poet.song.137000.json','["殘山狠石雙虎卧，斧迹鱗皴中鑿破。", "潭淵油油無敢唾，下有猛龍跧鐵鎖。", "自從分流注石門，西州秔稻如黄雲。", "刲羊五萬大作社，春秋伐鼓蒼煙根。", "我昔官稱勸農使，年年來激西江水。", "成都火米不論錢，絲管相隨看蠶市。", "款門得得酹清尊，椒漿桂酒刪羶葷。", "妄欲一語神豈聞，更願愛羊如愛人。"]'),
('295f9822-d58d-4ead-8282-ba91a924445d','崇德廟','范成大','宋','宋诗','song-poetry','','[]','雪山南風融雪汁，化作岷江江水來。',128,'全唐诗/poet.song.137000.json','["雪山南風融雪汁，化作岷江江水來。", "不知新漲高幾畫，但覺樓前奔萬雷。", "天教此水入中國，兩山辟易分道開。", "我家長川到海處，却在發源傳酒杯。", "人生幾屐辦此役，遠遊如許神應咍。", "東歸短棹昨已具，明日發船撾鼓催。", "灘平放溜日千里，已夢鱠鱸如雪堆。", "丹楓繫纜一回首，玉壘浮雲安在哉。"]'),
('83ef7ba3-7d06-44cb-8976-1bdddfe65be8','戲題索橋','范成大','宋','宋诗','song-poetry','','[]','織簟勻鋪面，排繩强架空。',48,'全唐诗/poet.song.137000.json','["織簟勻鋪面，排繩强架空。", "染人高曬帛，獵戶遠張罿。", "薄薄難承雨，翻翻不受風。", "何時將蜀客，東下看垂虹。"]'),
('8b16409f-5c25-45dc-8d9c-d5702625113f','青城山會慶建福宮宮舊名丈人觀，予爲請於朝，賜今名。入山前數日，敕書至自行在，予就設醮以祝聖人壽云','范成大','宋','宋诗','song-poetry','','[]','墨詔東來洶驛傳，璇題金榜照山川。',64,'全唐诗/poet.song.137000.json','["墨詔東來洶驛傳，璇題金榜照山川。", "祥開聖代千秋節，響動仙都九室天。", "觸石湧雲埋紫邏，流金飛火燭蒼巔。", "祗應老宅龐眉客，長記新宮錫號年。"]'),
('c3960aa2-1bad-49d7-bc8f-3bb26e823fc7','再題青城山','范成大','宋','宋诗','song-poetry','','[]','萬里清遊不暇慵，雙旌換得一枝筇。',64,'全唐诗/poet.song.137000.json','["萬里清遊不暇慵，雙旌換得一枝筇。", "來從井絡直西路，上到江源第一峰。", "海內閒身輸我佚，山中佳氣爲人濃。", "題詩試刻巖前石，付與他年蘚暈重。"]'),
('2e05b678-3cf8-48bd-8788-e74c235512a9','玉華樓夜醮','范成大','宋','宋诗','song-poetry','','[]','丈人峰前山四周，中有五城十二樓。',184,'全唐诗/poet.song.137000.json','["丈人峰前山四周，中有五城十二樓。", "玉華仙宮居上頭，紫雲澒洞千柱浮。", "剛風八面寒颼飀，靈君宴坐三千秋。", "蹻符飛行戲元洲，下睨濁世悲蜉蝣。", "桂旗偃蹇澹少休，知我萬里遥相投。", "暗蜩奏樂鏘鳴球，浮黎空歌清夜遒。", "參旗如虹欻下流，化爲神燈燭巖幽。", "火鈴洞赤凌空遊，誰歟蔽虧黯然收。", "禱之復然爲我留，半生縛塵鷹在鞲。", "豈有骨相肩浮丘。", "山英發光洗羈愁，行迷未遠夫何尤。", "笙簫上雲神欲遊，揖我從之驂素虬。"]'),
('04b4f01b-1565-4be1-9c77-81f7d1517607','上清宮','范成大','宋','宋诗','song-poetry','','[]','歷井捫參興未闌，丹梯通處更躋攀。',64,'全唐诗/poet.song.137000.json','["歷井捫參興未闌，丹梯通處更躋攀。", "冥濛蜀道一雲氣，破碎岷山千髻鬟。", "但覺星辰垂地上，不知風雨滿人間。", "蝸牛兩角猶如夢，更說紛紛觸與蠻。"]'),
('fa989691-d4b3-4784-8cd8-a28eb3138098','最高峰望雪山','范成大','宋','宋诗','song-poetry','','[]','大面峰頭六月寒，神燈收罷曉雲班。',32,'全唐诗/poet.song.137000.json','["大面峰頭六月寒，神燈收罷曉雲班。", "浮空忽湧三銀闕，云是西天雪嶺山。"]'),
('07162346-9185-42b4-9f58-aa39fbb27bab','范氏莊園','范成大','宋','宋诗','song-poetry','','[]','夕陽塵土漲郊墟，六六峰頭夢覺餘。',32,'全唐诗/poet.song.137000.json','["夕陽塵土漲郊墟，六六峰頭夢覺餘。", "竹色喚人來下馬，亂蟬深處有圖書。"]'),
('0fb5fcba-b1b0-403a-8997-98e5b7d271fc','青城縣何子方使君同年園池','范成大','宋','宋诗','song-poetry','','[]','榿塍芋壠意中行，浩蕩薰風不計程。',64,'全唐诗/poet.song.137000.json','["榿塍芋壠意中行，浩蕩薰風不計程。", "雨脚背人歸玉壘，江聲隨馬入青城。", "五橋今日新知路，千佛當年舊綴名。", "水竹光中同一笑，丐君荷露濯塵纓。"]'),
('ffcd9c40-275e-497b-9644-e5c728cb10be','何同年書院','范成大','宋','宋诗','song-poetry','','[]','竹色侵晚帙，泉聲潄嵌根。',24,'全唐诗/poet.song.137000.json','["竹色侵晚帙，泉聲潄嵌根。", "試通丹竈路，應到老人村。"]'),
('50075d22-e21e-4957-a79f-7d6c1d342198','江源縣張季長正字家善頌堂','范成大','宋','宋诗','song-poetry','','[]','我窮江源來，名勝頗追逐。',156,'全唐诗/poet.song.137000.json','["我窮江源來，名勝頗追逐。", "薰風秀沃野，在處得奇矚。", "頌堂有佳士，文字照縑竹。", "圖書抱世守，古錦韜玉軸。", "黄金不滿籯，故園有喬木。", "逡巡酒如澠，霍霍具水陸。", "田頭新穀升，一飯香滿屋。", "回思閔雨時，敢望遽炊玉。", "摩挲壁間題，明府遂州牧。", "山高江水長，百世照尸祝。", "我來坐琴壇，靦汗媿前躅。", "空餘煙霞痼，未許是公獨。", "請歌青城遊，或附耆舊錄。"]'),
('7b65f71f-06f4-4a1f-8fe1-bda022bf2de9','蜀州西湖','范成大','宋','宋诗','song-poetry','','["\u897f\u6e56"]','閒隨渠水來，偶到湖光裏。',96,'全唐诗/poet.song.137000.json','["閒隨渠水來，偶到湖光裏。", "仍呼水月舟，徑度雲錦地。", "誰云不解飲，我已荷香醉。", "湖陰玉嬋娟，夐立紅粧外。", "何須東閣梅，悠然自詩思。", "驚風入午暑，水竹有秋意。", "采菱不盈掬，興與蓴鱸會。", "遥知新津宿，魂夢亦清麗。"]'),
('5336f9da-6244-44f8-b562-4322ddd5d207','新津道中','范成大','宋','宋诗','song-poetry','','[]','雨後郊原浄，村村各好音。',48,'全唐诗/poet.song.137000.json','["雨後郊原浄，村村各好音。", "宿雲浮竹色，清溜走榿陰。", "曲沼擎青蓋，新畦藝綠針。", "江天空闊處，不受暑光侵。"]'),
('293a8443-7beb-4e33-948c-acc5565b14b2','次韻陸務觀編修新津遇雨不得登修覺山徑過眉州三絕  其一','范成大','宋','宋诗','song-poetry','','[]','送客多情難語離，僕夫無情車載脂。',32,'全唐诗/poet.song.137000.json','["送客多情難語離，僕夫無情車載脂。", "平生飄泊知何限，少似新津風雨時。"]'),
('91431098-3bf6-4590-96d7-3acee9402058','次韻陸務觀編修新津遇雨不得登修覺山徑過眉州三絕  其二','范成大','宋','宋诗','song-poetry','','[]','離合紛紛怕遠遊，遠遊仍怕賦登樓。',32,'全唐诗/poet.song.137000.json','["離合紛紛怕遠遊，遠遊仍怕賦登樓。", "何須一望三千里，望盡西州轉更愁。"]'),
('2e4c31d4-2c60-435c-b5be-b3658f3529de','次韻陸務觀編修新津遇雨不得登修覺山徑過眉州三絕  其三','范成大','宋','宋诗','song-poetry','','[]','雨後蟇頤山色開，玻瓈江清已可杯。',32,'全唐诗/poet.song.137000.json','["雨後蟇頤山色開，玻瓈江清已可杯。", "綠荷紅芰香四合，又入芙蓉城裏來。"]'),
('77b55801-944e-46d9-9128-fe2928d3af75','中巖','范成大','宋','宋诗','song-poetry','','[]','赤巖倚竛竮，翠邏森戌削。',144,'全唐诗/poet.song.137000.json','["赤巖倚竛竮，翠邏森戌削。", "岑蔚嵐氣重，稀間暑光薄。", "聊尋大士處，往扣洞門鑰。", "雙撐紫玉關，中矗翠雲幄。", "應供華藏海，歸坐寶樓閣。", "無法可示人，但見雨花落。", "不知龍湫勝，何似魚潭樂。", "夜深山四來，人靜天一握。", "驚看松桂白，月影到林壑。", "門前六月江，世界塵漠漠。", "寶瓶有甘露，一滴洗煩濁。", "捫天援斗杓，請爲諸君酌。"]'),
('c000145e-f35a-49b7-94e3-a515c4e8e33f','慈姥巖與送客酌別風雨大至凉甚諸賢用中巖韻各賦餞行詩紛然擘牋清飲終日雖無絲竹管絃而情味有餘','范成大','宋','宋诗','song-poetry','','[]','山靈知我厭塵土，喚起蟄雷鏖午暑。',64,'全唐诗/poet.song.137000.json','["山靈知我厭塵土，喚起蟄雷鏖午暑。", "松風無力雨絲長，散作毿毿雪塵舞。", "巖前懸溜珠簾傾，安得吹來添玉觥。", "詩成酒盡腸亦斷，休喚佳人唱渭城。"]'),
('28edaf1a-d0e2-4f30-972a-387e296986c0','次韻陸務觀慈姥巖酌別二絕  其一','范成大','宋','宋诗','song-poetry','','[]','送我彌旬未忍回，可憐蕭索把離杯。',32,'全唐诗/poet.song.137000.json','["送我彌旬未忍回，可憐蕭索把離杯。", "不辭更宿中巖下，投老餘年豈再來。"]'),
('19fefbfa-f7cc-4e57-8efa-32ab112c945f','次韻陸務觀慈姥巖酌別二絕  其二','范成大','宋','宋诗','song-poetry','','[]','明朝真是送人行，從此關山隔故情。',32,'全唐诗/poet.song.137000.json','["明朝真是送人行，從此關山隔故情。", "道義不磨雙鯉在，蜀江流水貫吳城。"]'),
('bc85dffc-5a24-4535-8701-f1729695c012','次韻代答劉文潛司業二絕  其一','范成大','宋','宋诗','song-poetry','','[]','平羌江上首空回，慈姥巖前定把杯。',32,'全唐诗/poet.song.137000.json','["平羌江上首空回，慈姥巖前定把杯。", "縱使石腸都忘却，也應風雨送愁來。"]'),
('a68793da-5703-4325-80a8-de0b7349d504','次韻代答劉文潛司業二絕  其二','范成大','宋','宋诗','song-poetry','','[]','回廊月下短歌行，惟有知音解有情。',32,'全唐诗/poet.song.137000.json','["回廊月下短歌行，惟有知音解有情。", "一曲紅窗聲裏怨，如今分作兩愁城。"]'),
('811b3fc9-b3fc-4334-b600-f92e887b345b','玻瓈江一首戲效陸務觀作','范成大','宋','宋诗','song-poetry','','[]','玻瓈江頭春淥深，別時沄沄流到今。',64,'全唐诗/poet.song.137000.json','["玻瓈江頭春淥深，別時沄沄流到今。", "祇言日遠易排遣，不道相思翻苦心。", "烏頭可白我可去，菖花易青君易尋。", "人生若未免離別，不如碌碌無知音。"]'),
('e5cb1e01-c90e-4bea-9260-042c4b586466','余與陸務觀自聖政所分袂每別輒五年離合又常以六月似有數者中巖送別至揮淚失聲留此爲贈','范成大','宋','宋诗','song-poetry','','[]','宦途流轉幾沉浮，雞黍何年共一丘。',64,'全唐诗/poet.song.137000.json','["宦途流轉幾沉浮，雞黍何年共一丘。", "動輒五年遲遠信，常於三伏話羈愁。", "月生後夜天應老，淚落中巖水不流。", "一語相開仍自解，除書聞已趣刀頭。"]'),
('9917ac75-6a6c-47a6-89cb-8669f5e4851b','萬景樓','范成大','宋','宋诗','song-poetry','','[]','左披九頂雲，右送大峨月。',124,'全唐诗/poet.song.137000.json','["左披九頂雲，右送大峨月。", "殘山剩水不知數，一一當樓供勝絕。", "玻瓈濯錦遥相通，指麾大渡來朝宗。", "川靈胥命各東去，我亦順流呼短篷。", "詩無傑語慚風物，頼有丹青傳小筆。", "仍添詩客倚欄看，令與山川相映發。", "龍彎歸路繞烏尤，棟雲簾雨邀人留。", "若爲喚得涪翁起，題作西南第一樓。"]'),
('c6c8ccde-908c-4ffc-865f-91c0dbf79e10','凌雲九頂','范成大','宋','宋诗','song-poetry','','[]','聊爲東坡載酒遊，萬龕迎我到峰頭。',64,'全唐诗/poet.song.137000.json','["聊爲東坡載酒遊，萬龕迎我到峰頭。", "江搖九頂風雷過，雲抹三峨日夜浮。", "古佛臨流都坐斷，行人識路亦歸休。", "酣酣午枕眠方丈，一笑閒身始自由。"]'),
('5954f1d4-31e4-41c1-93f6-b55b98de23b4','戲題方響洞','范成大','宋','宋诗','song-poetry','','[]','隔凡冰澗不可越，衆真微步壺中月。',32,'全唐诗/poet.song.137000.json','["隔凡冰澗不可越，衆真微步壺中月。", "徙倚含風玉珮聲，何須聽作蕤賓鐵。"]'),
('840f1507-0641-4845-8c37-19fcb1715e8f','問月堂酌別','范成大','宋','宋诗','song-poetry','','[]','半明燈火話悲酸，此會情知後會難。',64,'全唐诗/poet.song.137000.json','["半明燈火話悲酸，此會情知後會難。", "四海宦遊多聚散，一生情事足悲歡。", "鬢絲今夜不多黑，酒量徹明無數寬。", "醉夢登舟都不記，但聞風雨滿江寒。"]'),
('b8523de3-de70-493b-85df-67c2229d15b7','別後寄題漢嘉月榭','范成大','宋','宋诗','song-poetry','','[]','隠吏詩情卜築幽，同年惜別勸淹留。',64,'全唐诗/poet.song.137000.json','["隠吏詩情卜築幽，同年惜別勸淹留。", "試傾萬景湖亭酒，來看半輪江月秋。", "川路雖長猶共此，夜船空載且歸休。", "碧巖勝處頻回首，好事誰能更小樓。"]'),
('19f1f734-b8c4-4f5c-9f26-ef5728dbc350','過燕渡望大峨有白氣如層樓拔起叢雲中','范成大','宋','宋诗','song-poetry','','[]','圍野千山暑氣昏，大峨煙靄亦繽紛。',32,'全唐诗/poet.song.137000.json','["圍野千山暑氣昏，大峨煙靄亦繽紛。", "玉峰忽起三千丈，應是兜羅世界雲。"]'),
('93a5aaca-478e-4b5d-8b9c-c14a7e25b16b','蘇稽鎮客舍','范成大','宋','宋诗','song-poetry','','[]','送客都回我獨前，何人開此竹間軒。',32,'全唐诗/poet.song.137000.json','["送客都回我獨前，何人開此竹間軒。", "灘聲悲壯夜蟬咽，併入小窗供不眠。"]'),
('71c1aea6-6a16-4d53-ad61-0819f5be0f3e','峨眉縣','范成大','宋','宋诗','song-poetry','','[]','窮鄉未省識旌旄，雞犬歡呼巷陌騷。',64,'全唐诗/poet.song.137000.json','["窮鄉未省識旌旄，雞犬歡呼巷陌騷。", "村媼聚觀行績布，野翁迎拜跽然蒿。", "泉清土沃稻芒蚤，縣古林深槐癭高。", "珍重里儒來獻頌，盛言千載此丘遭。"]'),
('765f3198-beb5-4569-9a57-9049f2fafd6d','初入大峨','范成大','宋','宋诗','song-poetry','','[]','煙霞沉痼不須醫，此去真同汗漫期。',64,'全唐诗/poet.song.137000.json','["煙霞沉痼不須醫，此去真同汗漫期。", "曾款上清臨大面，仍從太白問峨眉。", "山中緣法如今熟，世上功名自古癡。", "賸作畫圖歸挂壁，他年猶欲卧遊之。"]'),
('9d68a25d-b808-4c81-8a6a-b742a2668531','華巖寺','范成大','宋','宋诗','song-poetry','','[]','衆峰攢壁立，中有路一綫。',96,'全唐诗/poet.song.137000.json','["衆峰攢壁立，中有路一綫。", "攀援白雲梯，食頃已天半。", "我本紫芝曲，誤落青芻棧。", "向來脫新羈，恍已還舊觀。", "花煙辭少城，暑雪對大面。", "來從太白西，更走三峨徧。", "風生兩腋輕，泉吼四山眩。", "今晨第一程，莫歎輿僕倦。"]'),
('6f917ee6-1f02-4d4c-a3ff-6141cdeed212','中峰','范成大','宋','宋诗','song-poetry','','[]','凌高蹋危峰，斗下頫幽谷。',96,'全唐诗/poet.song.137000.json','["凌高蹋危峰，斗下頫幽谷。", "仙英馥椒蘭，嘉蔭矗旄纛。", "空翠元不雨，洩雲自膏沐。", "暑綌森有稜，瘁肌凄欲粟。", "白崖如負依，金界奠蒼麓。", "衆峰拱二八，娟妙繞重屋。", "真人與尊者，幽居接松竹。", "呼之儻肯應，留我試餐玉。"]'),
('c3b3c081-a00b-4999-802e-86e9135dc81d','雙溪','范成大','宋','宋诗','song-poetry','','[]','冷風騷騷木葉低，洞淵阻深生怪奇。',64,'全唐诗/poet.song.137000.json','["冷風騷騷木葉低，洞淵阻深生怪奇。", "碧琳雙澗黑無底，中有玉龍相對飛。", "雷轟雪捲入林樾，化爲一龍潭底沒。", "摩尼鬭罷四山空，時有寶光巖下發。"]'),
('ab5e95b2-0105-43ce-a053-ce15acb71cd1','寶現溪','范成大','宋','宋诗','song-poetry','','[]','粲粲罨畫沙，鱗鱗麴塵水。',72,'全唐诗/poet.song.137000.json','["粲粲罨畫沙，鱗鱗麴塵水。", "朝陽相發揮，光景艷孔翠。", "寧聞雙溪號，但見縠紋細。", "神魚不謀食，終日印潭底。", "躍珠本具眼，聊共阿師戲。", "收藏更傳寶，一笑落第二。"]'),
('64f05688-acad-49f7-99dc-8067bd0b3ae1','點心山','范成大','宋','宋诗','song-poetry','','[]','入山窘宿雨，上山賀朝霽。',48,'全唐诗/poet.song.137000.json','["入山窘宿雨，上山賀朝霽。", "跬步便歷險，轉盼已呀氣。", "豈惟膝點心，固已頭搶地。", "遊人貪勝踐，姑吟蜀道易。"]'),
('55a4dfaa-5afc-45e8-aab9-0b4884cf85cd','大扶{扌舁}','范成大','宋','宋诗','song-poetry','','[]','身如魚躍上長竿，路似鏡中相對看。',32,'全唐诗/poet.song.137000.json','["身如魚躍上長竿，路似鏡中相對看。", "珍重山丁扶我過，人間踽踽獨行難。"]'),
('0a8acf7d-9b64-4263-9e4a-27b3e60da56a','小扶{扌舁}','范成大','宋','宋诗','song-poetry','','[]','食時方了大扶{扌舁}，前逢仄徑仍崎嶇。',67,'全唐诗/poet.song.137000.json','["食時方了大扶{扌舁}，前逢仄徑仍崎嶇。", "懸崖破棧不可玩，輿丁挾我如騰狙。", "平生行路險艱足，如今雪鬢應難綠。", "却憐苔髮鎮長青，千古毿毿挂高木。"]'),
('36cba9c1-d0c6-42f0-8add-6672a0fd35a0','胡孫梯','范成大','宋','宋诗','song-poetry','','[]','木磴鱗鱗滑带泥，微生欹側寄枯藜。',32,'全唐诗/poet.song.137000.json','["木磴鱗鱗滑带泥，微生欹側寄枯藜。", "胡孫愁處我猶過，箇裏如今幸有梯。"]'),
('64157e12-6595-4c0e-a479-adc2b57bf4a7','雷洞平','范成大','宋','宋诗','song-poetry','','[]','行人魄動風森森，兩崖奔黑愁太陰。',64,'全唐诗/poet.song.137000.json','["行人魄動風森森，兩崖奔黑愁太陰。", "不知七十二洞處，側足下窺雲海深。", "聞有神龍依佛住，棖觸須臾召雷雨。", "兩川稻熟須好晴，我亦閒遊神勿驚。"]'),
('0cbcc7d9-9c13-4296-b06d-a94dbe59542b','八十四盤','范成大','宋','宋诗','song-poetry','','[]','冥鴻無伴鶴孤飛，回首塵籠一笑嬉。',64,'全唐诗/poet.song.137000.json','["冥鴻無伴鶴孤飛，回首塵籠一笑嬉。", "八十四盤新拄杖，萬三千乘舊牙旗。", "石梯碧滑雲生後，木葉紅斑雪霽時。", "說與同行莫惆悵，人間捷徑轉嶔巇。"]'),
('1efc078a-ae4f-46fd-94ca-df5936a802b3','娑羅平','范成大','宋','宋诗','song-poetry','','[]','仙聖飛行此是家，路逢真境但驚呀。',64,'全唐诗/poet.song.137000.json','["仙聖飛行此是家，路逢真境但驚呀。", "神農嘗外盡靈藥，天女散餘多異花。", "嵐雨逼衣寒似鐵，冰泉炊米硬於沙。", "峰頭事事殊塵世，缺甃跳梁笑井蛙。"]'),
('d15725a7-2c96-4572-bcd1-c82c0e0c3e19','思佛亭曉望','范成大','宋','宋诗','song-poetry','','[]','栗烈剛風刮病眸，登臨何啻緩千憂。',64,'全唐诗/poet.song.137000.json','["栗烈剛風刮病眸，登臨何啻緩千憂。", "界天暑雪青城外，湧地晴雲瓦屋頭。", "浩蕩他年誇北客，蒼茫何處認西州。", "千巖萬壑須尋徧，身是江湖不繫舟。"]'),
('c4efa722-f573-4449-a9db-5949da82465e','光相寺','范成大','宋','宋诗','song-poetry','','[]','峰頂四時如大冬，芳花芳草春自融。',64,'全唐诗/poet.song.137000.json','["峰頂四時如大冬，芳花芳草春自融。", "苔痕新晞六月雪，木勢舊偃千年風。", "雲物爲人布世界，日輪同我行虛空。", "浮生元自有超脫，地上可憐悲攓蓬。"]'),
('e0e8c7f0-8895-4139-b4ac-4fdbc45cd38c','七寶巖','范成大','宋','宋诗','song-poetry','','[]','天如碧玉甌，下覆白玉盤。',96,'全唐诗/poet.song.137000.json','["天如碧玉甌，下覆白玉盤。", "晶光眩相射，我獨居兩間。", "正視不勝瞬，却立聊少安。", "但覺風浩浩，骨毛森似寒。", "神仙杳無處，寧論有塵寰。", "身輕一槁葉，兩腋如飛翰。", "同行挽我衣，何往何當還。", "少留作詩去，奇哉此憑闌。"]'),
('ff6eb569-d6ce-4372-a9e3-e08909338019','淳熙四年六月二十七日登大峨之巔一名勝峰山佛書以爲普賢大士所居連日光相大現賦詩紀實屬印老刻之以爲山中一重公案','范成大','宋','宋诗','song-poetry','','[]','勝峰高哉摩紫青，白鹿導我登化城。',320,'全唐诗/poet.song.137000.json','["勝峰高哉摩紫青，白鹿導我登化城。", "住山大士喜客至，兜羅布界繽相迎。", "圓景明暉倚雲立，艴如七寶莊嚴成。", "一光未定一光發，中有墨像隨心生。", "白毫從地插空碧，散燭象緯天龍驚。", "夜神受記亦修供，照世洞然千百燈。", "明朝銀界混一白，咫尺眩轉寒凌兢。", "天容野色鯈開閉，慘澹變化愁仙靈。", "人言六通欲大現，洗山急雨如盆傾。", "重輪疊采印巖腹，非煙非霧非丹青。", "我與化人中共住，鏡光覿面交相呈。", "前山忽湧大圓相，日圍月暈浮青冥。", "林泉草木盡含裹，是則名爲普光明。", "言詞海藏不勝讚，北峰復有金橋橫。", "衆慈久立佛事竟，一塵不起山竛竮。", "向來無法可宣說，爲問有耳如何聽。", "我本三生同行願，隨緣一念猶相應。", "此行且復印心地，衣有寶珠奚外營。", "題詩說偈作公案，亦使來者知吾曾。", "神通佛法須判斷，一任熱椀春雷鳴。"]'),
('579b275d-bd29-412b-9243-73c39c62912a','請佛閣晚望雪山數十峰如爛晃耀暑光中','范成大','宋','宋诗','song-poetry','','[]','累塊蒼然是九州，大千起滅更悠悠。',64,'全唐诗/poet.song.137000.json','["累塊蒼然是九州，大千起滅更悠悠。", "雪光正照天西角，日影長浮雨上頭。", "峰頂何曾知六月，塵間想已別三秋。", "佛毫似欲留人住，橫野金橋晚未收。"]'),
('5452f065-7f04-4603-8b31-57a96df6c175','浄光軒','范成大','宋','宋诗','song-poetry','','[]','翳華銷盡八窗明，雨竹風泉演妙聲。',32,'全唐诗/poet.song.137000.json','["翳華銷盡八窗明，雨竹風泉演妙聲。", "身世只今高幾許，北峰渾共倚闌平。"]'),
('0b1d8646-3267-4fa5-bb2f-2317fd41a527','虎溪','范成大','宋','宋诗','song-poetry','','[]','水本無心作浪波，經行偶與石相磨。',32,'全唐诗/poet.song.137000.json','["水本無心作浪波，經行偶與石相磨。", "不須更問橋安否，喚取於菟載我過。"]'),
('dd18f64d-d987-4570-a6df-47ba87830878','白雲峽','范成大','宋','宋诗','song-poetry','','[]','雙溪疑從銀漢下，我欲窮源問仙舍。',64,'全唐诗/poet.song.137000.json','["雙溪疑從銀漢下，我欲窮源問仙舍。", "飛瀾濺沫潄籃輿，却望兩崖天一罅。", "疎疎暑雨滑危梯，策策山風掖高駕。", "幽尋險絕太奇生，莫笑退之號太華。"]'),
('f4c9405b-4058-491a-8730-b160ccb2c747','孫真人菴','范成大','宋','宋诗','song-poetry','','[]','何處仙翁舊隠居，青蓮巉絕似蓬壺。',64,'全唐诗/poet.song.137000.json','["何處仙翁舊隠居，青蓮巉絕似蓬壺。", "雲深未到淘朱洞，雨小先尋煉藥爐。", "磵下草香疑可餌，林間虎伏試教呼。", "閒身儘辦供薪水，定肯分山一半無。"]'),
('01e02383-7cc6-4d1a-a6bb-bcdf8cc1a496','龍門峽','范成大','宋','宋诗','song-poetry','','[]','插天千丈兩碧城，中有玉塹穿巖扃。',64,'全唐诗/poet.song.137000.json','["插天千丈兩碧城，中有玉塹穿巖扃。", "瀑流懸布不知數，亂落嵌根飛白雨。", "瑶琨爲室雲爲關，龍君所居朱夏寒。", "不辭擊棹更深入，萬一龍驚雷破山。"]'),
('1eca0d8a-43a4-4903-a1b7-1e4c6f1d6828','既離成都故人送者遠至漢嘉分袂其尤遠而相及於峨眉之上者六人范季申郭中行楊商卿嗣勳李良仲譚德稱口占此詩留別','范成大','宋','宋诗','song-poetry','','[]','我本住林屋，風吹來錦城。',192,'全唐诗/poet.song.137000.json','["我本住林屋，風吹來錦城。", "錦城亦何樂，所樂多友生。", "相從不知久，相送不計程。", "橫絕峨眉巔，欲去有餘情。", "吾宗蓋難弟，李郭人中英。", "二楊懿文德，譚子資粹清。", "相視心莫逆，劇談四筵傾。", "明朝各回首，雲水相與平。", "我今投紱去，行且扶犁耕。", "淒凉別知賦，慷慨結客行。", "後會豈不好，路長恐寒盟。", "諸賢乃不凡，骨相有功名。", "大厦罩羣木，明廷朝萬靈。", "王畿坦如砥，結綬當同登。", "道傍石湖水，誰能叩柴荆。", "夢中儻相見，秉燭聽殘更。"]'),
('32918979-df17-4392-8ae5-c1c3dbb06df5','聞威州諸羌退聽邊事已寧少城籌邊樓闌檻修葺亦畢工作詩寄權制帥高子長','范成大','宋','宋诗','song-poetry','','[]','籌邊樓上美髯翁，赤白囊飛笑語中。',64,'全唐诗/poet.song.137000.json','["籌邊樓上美髯翁，赤白囊飛笑語中。", "勃律天西元采玉，蓬婆雪外昨分弓。", "踏筵舞罷平闌月，橫槊詩成滿袖風。", "諸校各能歌破陣，何須琴裏聽平戎。"]'),
('77d06bbd-a04b-433b-9c30-469451cbe560','犍爲江樓','范成大','宋','宋诗','song-poetry','','[]','河邊堵立看歸篷，三老開頭暮欲東。',64,'全唐诗/poet.song.137000.json','["河邊堵立看歸篷，三老開頭暮欲東。", "漲水稠灘連峽內，淺山浮石似湘中。", "無人驛路榛榛草，有客江樓浩浩風。", "種落塵消少公事，賸裁新語寄詩筒。"]'),
('13212cca-aeac-4158-ab08-96cf6ca469e0','宣化道中','范成大','宋','宋诗','song-poetry','','[]','瘦草蕭疎已似秋，盤陀山骨束江流。',32,'全唐诗/poet.song.137000.json','["瘦草蕭疎已似秋，盤陀山骨束江流。", "兩崖若不頑如鐵，爭得狂瀾拍岸休。"]'),
('b080f07a-204c-45c7-bf2e-c49f466ed02f','將至敘州','范成大','宋','宋诗','song-poetry','','[]','亂山滿平野，漲水豪大川。',48,'全唐诗/poet.song.137000.json','["亂山滿平野，漲水豪大川。", "仄徑無轍跡，疎林有炊煙。", "山農旦燒畬，蠻賈暑荷氈。", "窮鄉足荒怪，打鼓催我船。"]'),
('e0a20683-0257-4f27-9999-e21d8e545769','七夕至敘州登鎖江亭山谷謫居時屢登此亭有詩四篇敬用其韻','范成大','宋','宋诗','song-poetry','','[]','水口故城丘壠平，新亭乃有緪鐵橫。',64,'全唐诗/poet.song.137000.json','["水口故城丘壠平，新亭乃有緪鐵橫。", "歸艎擊汰若飛渡，一雨徹明秋漲生。", "東樓鎖江兩重客，筆墨當代俱詩鳴。", "我來但醉春碧酒，星橋脈脈向三更。"]'),
('acb0ae55-07ce-4351-bc07-d8a7af40c9c4','江安道中','范成大','宋','宋诗','song-poetry','','[]','穠綠連村荔子丹，瘴雲將雨暗前灣。',64,'全唐诗/poet.song.137000.json','["穠綠連村荔子丹，瘴雲將雨暗前灣。", "張旗且喜三灘駛，叱馭曾驚九折艱。", "瀘水舟閒迷古渡，馬湖碑缺伴荒山。", "威名功業吾何有，無事飄飄犯百蠻。"]'),
('b832b8fd-231a-4e39-abf9-017dc8b8275b','瀘州南定樓','范成大','宋','宋诗','song-poetry','','[]','歸艎東下興悠哉，小住危闌把一杯。',32,'全唐诗/poet.song.137000.json','["歸艎東下興悠哉，小住危闌把一杯。", "樓下沄沄內江水，明朝同入大江來。"]'),
('00b61373-b8ac-421e-85da-b21f98fbcc53','題譚德稱扇','范成大','宋','宋诗','song-poetry','','[]','蠻風吹雨瘴江肥，短草荒山鳥不飛。',32,'全唐诗/poet.song.137000.json','["蠻風吹雨瘴江肥，短草荒山鳥不飛。", "盡是瀘南腸斷句，如今分與故人歸。"]'),
('358704f8-38a7-4a92-9895-219344dcf011','題楊商卿扇','范成大','宋','宋诗','song-poetry','','[]','君歸我去兩銷魂，愁滿千山鎖瘴雲。',32,'全唐诗/poet.song.137000.json','["君歸我去兩銷魂，愁滿千山鎖瘴雲。", "後夜短檠風雨暗，誰能相伴細論文。"]'),
('d3e2cbf7-10d6-4b9f-b56a-327e475d737b','題楊子容扇','范成大','宋','宋诗','song-poetry','','[]','雙竹軒窗聽讀書，垂天雲翼要摶扶。',32,'全唐诗/poet.song.137000.json','["雙竹軒窗聽讀書，垂天雲翼要摶扶。", "與君只作三年別，射策東來過石湖。"]'),
('09e27e63-9561-4ccc-9ced-4c9229b2a006','譚德稱楊商卿父子送余自成都合江亭相從至瀘南合江縣始分袂水行踰千里作詩以別','范成大','宋','宋诗','song-poetry','','[]','合江亭前送我來，合江縣裏別我去。',64,'全唐诗/poet.song.137000.json','["合江亭前送我來，合江縣裏別我去。", "江流好合人好乖，明日東西南北路。", "千里追隨不忍歸，一杯重把知何處。", "臨岐心曲兩茫然，但祝頻書無別語。"]'),
('f21075f6-7256-46ae-b643-bb646e57eb8d','發合江數里寄楊商卿諸公','范成大','宋','宋诗','song-poetry','','[]','臨分滿意說離愁，草草無言祇淚流。',32,'全唐诗/poet.song.137000.json','["臨分滿意說離愁，草草無言祇淚流。", "船尾竹林遮縣市，故人猶自立沙頭。"]'),
('cc869380-ef44-4975-b92d-c17866faf043','過江津縣睡熟不暇梢船','范成大','宋','宋诗','song-poetry','','[]','西風扶櫓似乘槎，水闊灘沉浪不花。',32,'全唐诗/poet.song.137000.json','["西風扶櫓似乘槎，水闊灘沉浪不花。", "夢裏竹間喧急雪，覺來船底滾鳴沙。"]'),
('51d678d8-0bfc-4b7e-95cb-f375a756c165','恭州夜泊','范成大','宋','宋诗','song-poetry','','[]','萆山磽确强田疇，村落熙然粟豆秋。',64,'全唐诗/poet.song.137000.json','["萆山磽确强田疇，村落熙然粟豆秋。", "翠竹江村非錦里，青溪夜月已渝州。", "小樓高下依盤石，弱纜西東戰急流。", "入峽初程風物異，布裙跣婦總垂瘤。"]'),
('29e4e12e-6079-4e45-92b6-647f0cdb64d9','大熱泊樂溫有懷商卿德稱','范成大','宋','宋诗','song-poetry','','[]','暑候秋逾濁，江流晚更渾。',48,'全唐诗/poet.song.137000.json','["暑候秋逾濁，江流晚更渾。", "瘴風如火焮，嵐月似煙昏。", "城郭廩君國，山林妃子園。", "故人新判袂，得句與誰論。"]'),
('170e0c19-eae1-40f1-8ee1-5ba4af349925','涪州江險不可泊入黔江檥舟','范成大','宋','宋诗','song-poetry','','[]','黄沙翻浪攻排亭，濆淖百尺呀成坑。',88,'全唐诗/poet.song.137000.json','["黄沙翻浪攻排亭，濆淖百尺呀成坑。", "坳漥眩轉久乃平，一渦熨帖千渦生。", "篙師絕叫敺川靈，鳴饒飛渡如奔霆。", "水從岷來如濁涇，夜榜黔江聊濯纓。", "玻瓈徹底鏡面清，忽思短棹中流橫，釣絲隨風浮月明。"]'),
('415b3d9c-56cf-41aa-af7d-3c3d9461f1fd','妃子園','范成大','宋','宋诗','song-poetry','','[]','露葉風枝驛騎傳，華清天上一嫣然。',32,'全唐诗/poet.song.137000.json','["露葉風枝驛騎傳，華清天上一嫣然。", "當時若識陳家紫，何處蠻村更有園。"]'),
('45e45e7e-4459-4336-9efe-bf04b84b0e02','豐都觀','范成大','宋','宋诗','song-poetry','','[]','神仙得者王方平，誰其繼之陰長生。',184,'全唐诗/poet.song.137000.json','["神仙得者王方平，誰其繼之陰長生。", "飄然空飛五雲軿，上賓寥陽留玉京。", "石爐丹氣常夜明，寵光萬柏森千齡。", "峽山偪仄岷江縈，洞宮福地古所銘。", "云有北陰神帝庭，太陰黑簿囚鬼靈。", "自從仙都啟巖扃，明霞流電飛陽晶。", "暉景下墮鑠九冰，塞絕苦道升無形。", "至今臺殿棲竛竮，隋圬唐堊留丹青。", "十仙怪奇溪女清，瑶池仙仗紛娉婷，琅璈赴節鏘欲鳴。", "我來秋暑如炊蒸，汗流呀氣扶枯藤。", "摩挲衆蹟不暇評，聊記梗概知吾曾。"]'),
('f652095c-ef7a-487d-901c-60e149e05a2e','萬州西山湖亭秋荷尚盛','范成大','宋','宋诗','song-poetry','','[]','叢薈忽明眼，山腰灧湖光。',48,'全唐诗/poet.song.137000.json','["叢薈忽明眼，山腰灧湖光。", "列岫繞雲錦，深林護風香。", "西山即太華，玉井餘秋芳。", "隔江招岑仙，共擘雙蓮房。"]'),
('894b12bb-6392-4603-a9e3-896eb643700e','下巖','范成大','宋','宋诗','song-poetry','','[]','疇昔中巖一夢殘，下巖風景亦高寒。',64,'全唐诗/poet.song.137000.json','["疇昔中巖一夢殘，下巖風景亦高寒。", "峽中無處堪停棹，雨後今朝始凭闌。", "不用苦求毫相現，祇教長挂水簾看。", "山僧勸我題蒼壁，坡谷前頭未敢刊。"]'),
('fe7e4aac-ffb9-4eb2-a98b-d8bb97e683ab','魚復浦泊舟望月出赤甲山山形斷缺如鼉龍坐而張頤月自缺中騰上山頂','范成大','宋','宋诗','song-poetry','','[]','月出赤甲如金盆，蹲龍呀口吐復吞。',64,'全唐诗/poet.song.137000.json','["月出赤甲如金盆，蹲龍呀口吐復吞。", "長風浩浩挾之出，影落半江沉復翻。", "天高夜靜四山寂，惟有灘聲喧水門。", "高齋詩翁不可作，我亦不眠終夕看。"]'),
('64771e60-c6b3-4402-82de-4736c30997de','夔門即事','范成大','宋','宋诗','song-poetry','','[]','峽行風物不堪論，袢暑驕陽雜瘴氛。',64,'全唐诗/poet.song.137000.json','["峽行風物不堪論，袢暑驕陽雜瘴氛。", "人入恭南多附贅，山從夔子盡侵雲。", "竹枝舊曲元無調，麴米新篘但有聞。", "試覓清泠一杯水，筒泉須自卧龍分。"]'),
('7f9fc650-40f6-4d86-bb05-1f1a52c9cb3d','瞿唐行','范成大','宋','宋诗','song-poetry','','[]','川靈知我歸有程，一夜漲痕千丈生。',128,'全唐诗/poet.song.137000.json','["川靈知我歸有程，一夜漲痕千丈生。", "中流擊楫洶作氣，夾岸簸旗呀失聲。", "不知灧澦在船底，但覺瞿唐如鏡平。", "鑿峽疏川狠石破，號山索飲飛泉驚。", "白鹽赤甲轉頭失，黑石黄嵌拚命輕。", "草齊增肥無泊處，竹枝凝咽空餘情。", "人間險路此奇絕，客裏驚心吾飽更。", "劍閣翻成蜀道易，請歌范子瞿唐行。"]'),
('48d5c6a0-c45a-4840-9c0a-de554bf82e8f','夜泊歸州州有宋玉宅、昭君臺','范成大','宋','宋诗','song-poetry','','[]','舊國風煙古，新凉瘴癘清。',48,'全唐诗/poet.song.137000.json','["舊國風煙古，新凉瘴癘清。", "片雲將客夢，微月照江聲。", "細和悲秋賦，遥憐出塞情。", "荒山飲閥閲，兒女擅嘉名。"]'),
('dba66b85-4fc8-4ecf-b7fc-bc0e1b5a40a1','秭歸郡圃絕句二首  其一','范成大','宋','宋诗','song-poetry','','[]','花竹蕭騷小圃畦，官居翻似隠淪棲。',32,'全唐诗/poet.song.137000.json','["花竹蕭騷小圃畦，官居翻似隠淪棲。", "巴山四合秋陽滿，杜宇黄鸝相對啼。"]'),
('12e44997-082d-4c00-8548-6d5538747ed6','秭歸郡圃絕句二首  其二','范成大','宋','宋诗','song-poetry','','[]','孤城偪仄復偪仄，前山後山青欲來。',32,'全唐诗/poet.song.137000.json','["孤城偪仄復偪仄，前山後山青欲來。", "市聲蕭條衙鼓靜，惟有叱灘喧萬雷。"]'),
('c4bc1367-5406-42b0-aab7-54f9b7015edf','宋玉宅','范成大','宋','宋诗','song-poetry','','[]','悲秋人去語難工，搖落空山草木風。',32,'全唐诗/poet.song.137000.json','["悲秋人去語難工，搖落空山草木風。", "猶有市人傳舊事，酒壚還在宋家東。"]'),
('ba5ca7e3-1c69-4f7c-8801-16326a67c934','後巫山高一首','范成大','宋','宋诗','song-poetry','','[]','凝真宮前十二峰，兩峰娟妙翠插空。',128,'全唐诗/poet.song.137000.json','["凝真宮前十二峰，兩峰娟妙翠插空。", "餘峰競秀尚多有，白壁蒼崖無數重。", "秋江潄石半山腹，倚天削鐵荒行蹤。", "造化鍾奇矗瑶巘，真靈擇勝深珠宮。", "朝雲未罷暮雲起，陰晴竟日長冥濛。", "瑶姬作意送歸客，一夜收潦仍回風。", "仰看館御飛檝過，回首已在虛無中。", "惟餘烏鴉作使者，迎船送船西復東。"]'),
('f82e6e73-3df7-42cf-89c3-4f0e33eba503','黄牛峽','范成大','宋','宋诗','song-poetry','','[]','朝離悲秋宅，午榜疊石磯。',88,'全唐诗/poet.song.137000.json','["朝離悲秋宅，午榜疊石磯。", "小留黄牛廟，細讀石馬詩。", "黄牛隠見蒼山裏，石馬至今猶馘耳。", "當年夢境識仙翁，馬爲迎門神爲起。", "物生不朽繫所逢，歐詞蘇筆蒼苔封。", "山高水長翁之風，石馬亦與翁無窮。"]'),
('979246f2-de86-4835-9bc2-717200e531e6','假十二峰','范成大','宋','宋诗','song-poetry','','[]','巴東三峽數巫陽，山入西陵更鬰蒼。',32,'全唐诗/poet.song.137000.json','["巴東三峽數巫陽，山入西陵更鬰蒼。", "何以假爲非確論，直疑溟涬弟高唐。"]'),
('5f70e977-c2fb-45cd-ad4b-32f3ddca7cae','扇子峽','范成大','宋','宋诗','song-poetry','','[]','茲行看山真飽諳，今晨出峽仍窮探。',128,'全唐诗/poet.song.137000.json','["茲行看山真飽諳，今晨出峽仍窮探。", "南磯北磯白鐵壁，千峰萬峰蒼玉篸。", "橫前直疑江已斷，崛起競與天相攙。", "蜀山欲窮此盤礴，禹力已盡猶鎸劖。", "望舒宮中金背蟾，泥塗脫盡餘老饞。", "下飲岷江不知去，流涎落吻如排髯。", "挈瓶檥棹𣂏清甘，未暇煮茗和薑鹽。", "聊將滌硯濡我筆，恍惚詩律高巉巖。"]'),
('05627c60-0500-4d13-89f5-5ad75ffac979','荆渚中流回望巫山無復一點戲成短歌','范成大','宋','宋诗','song-poetry','','[]','千峰萬峰巴峽裏，不信人間有平地。',64,'全唐诗/poet.song.137000.json','["千峰萬峰巴峽裏，不信人間有平地。", "渚宮回望水連天，却疑平地元無山。", "山川相迎復相送，轉頭變滅都如夢。", "歸程萬里今三千，幾夢即到石湖邊。"]'),
('38c8956c-2cff-43ec-ba7d-6454fe55f4a1','魯家洑入沌','范成大','宋','宋诗','song-poetry','','[]','過盡巴東巫峽長，荆川鼓棹更茫茫。',64,'全唐诗/poet.song.137000.json','["過盡巴東巫峽長，荆川鼓棹更茫茫。", "避風怕入三江口，乘月貪行百里荒。", "夜後逢人盡刀劍，古來踏地皆耕桑。", "可憐行路難如此，一簇寒蘆尚稅場。"]'),
('0ae81538-7353-4ad4-8f86-b6ed39d02133','鄂州南樓','范成大','宋','宋诗','song-poetry','','[]','誰將玉笛弄中秋，黄鶴飛來識舊游。',64,'全唐诗/poet.song.137000.json','["誰將玉笛弄中秋，黄鶴飛來識舊游。", "漢樹有情橫北渚，蜀江無語抱南樓。", "燭天燈火三更市，搖月旌旗萬里舟。", "却笑鱸鄉垂釣手，武昌魚好便淹留。"]'),
('84b3cb52-cbde-4778-b3e1-434932ea0770','題黄州臨皋亭','范成大','宋','宋诗','song-poetry','','[]','夏口風帆赤壁磯，雪堂釃酒竹樓棋。',32,'全唐诗/poet.song.137000.json','["夏口風帆赤壁磯，雪堂釃酒竹樓棋。", "繫舟一日黄州下，只辦登臨不辦詩。"]'),
('937d450b-2326-4577-9d14-167a9362b4b4','江州庾樓夜宴','范成大','宋','宋诗','song-poetry','','[]','岷江潄北渚，廬阜窺南窗。',120,'全唐诗/poet.song.137000.json','["岷江潄北渚，廬阜窺南窗。", "名山復大川，超覽茲樓雙。", "何必元規塵，自足豪他邦。", "使君秫田熟，新凉篘酒缸。", "落景澹碧瓦，長虹吐金釭。", "客從三峽來，噩夢隨奔瀧。", "小留聽琵琶，船旗卷修杠。", "請呼裂帛絃，爲拊洮河腔。", "曲終四憑欄，倦遊心始降。", "明發挂帆去，曉鐘煙外撞。"]'),
('5b001c5e-9c11-42b3-aa5a-d8c706dd70a0','東林寺','范成大','宋','宋诗','song-poetry','','[]','談易繙經宰木春，三生猶自裊煙熏。',64,'全唐诗/poet.song.137000.json','["談易繙經宰木春，三生猶自裊煙熏。", "客塵長隔虎溪水，劫火不侵香谷雲。", "老矣懶供蓮社課，歸哉忺讀草堂文。", "山頭一任天燈現，箇事何曾落見聞。"]'),
('b7ea9510-afe2-4297-94dd-7ac71b16384e','過虎溪對東林蒼巖翠樾下浸大澗宛似靈隠冷泉囑長老法才作亭名曰過溪且爲率山丁薙草定基一朝而畢','范成大','宋','宋诗','song-poetry','','[]','過溪無限翠屏開，大笑從教虎子猜。',32,'全唐诗/poet.song.137000.json','["過溪無限翠屏開，大笑從教虎子猜。", "不獨山中添故事，仍教題作小飛來。"]'),
('9af428b2-3953-41c5-a2e5-536e07689919','病倦不能過谷簾三峽寄題','范成大','宋','宋诗','song-poetry','','[]','白龍青峽紫煙爐，山北山南只半塗。',32,'全唐诗/poet.song.137000.json','["白龍青峽紫煙爐，山北山南只半塗。", "說與同來綠玉杖，他年終補卧遊圖。"]'),
('dedc4b49-5144-45e9-9ccc-0b710150c122','湖口望大孤','范成大','宋','宋诗','song-poetry','','[]','廬阜岡勢斷，江流漭相通。',72,'全唐诗/poet.song.137000.json','["廬阜岡勢斷，江流漭相通。", "大孤如小冠，插入奫淪中。", "我欲蛻濁浪，往馭揚瀾風。", "晃晃銀色界，濙濙水晶宮。", "濯足望八荒，列宿羅心胸。", "客帆詎肯駐，搔首蒼煙叢。"]'),
('2104439b-c398-4df2-a6c8-2d08adebda92','澎浪磯阻風','范成大','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','浦口舟藏尋丈慳，篙師抱膝朝暮閒。',64,'全唐诗/poet.song.137000.json','["浦口舟藏尋丈慳，篙師抱膝朝暮閒。", "逆風來從水府廟，濁浪欲碎小孤山。", "太白猶高缺蟾墮，長江未盡歸鬢斑。", "短歌聊復怨行路，當有聽者凋朱顔。"]'),
('9d44da7c-bb11-4d3e-a01a-a4db755dfa3c','馬當洑阻風居人云非五日或七日風不止謂之重陽信','范成大','宋','宋诗','song-poetry','','[]','拍岸回流逆上磯，枯楊折葦靜相依。',64,'全唐诗/poet.song.137000.json','["拍岸回流逆上磯，枯楊折葦靜相依。", "趁墟漁子晨爭渡，賽廟商人晚醉歸。", "重九信來風未憗，大千行徧昨俱非。", "羈愁萬斛從頭數，带眼今秋又減圍。"]'),
('e0b4ca43-ec4c-4417-b216-8b268a5c1266','放舟風復不順再泊馬當對岸夾中馬當水府即小說所載神助王勃一席清風處也戲題兩絕  其一','范成大','宋','宋诗','song-poetry','','[]','萬里江隨倦客東，馬當山嘴勒孤篷。',32,'全唐诗/poet.song.137000.json','["萬里江隨倦客東，馬當山嘴勒孤篷。", "無才解賦珠簾雨，誰肯相賒一席風。"]'),
('080062ac-9322-40ed-b05e-cc84404514d0','放舟風復不順再泊馬當對岸夾中馬當水府即小說所載神助王勃一席清風處也戲題兩絕  其二','范成大','宋','宋诗','song-poetry','','[]','禁江上口柏山東，三日荒寒繫短篷。',32,'全唐诗/poet.song.137000.json','["禁江上口柏山東，三日荒寒繫短篷。", "却憶宮亭湖裏去，隨人南北解分風。"]'),
('07b395db-824f-404a-8eb6-6fe63ddcc61b','守風嘲舟子','范成大','宋','宋诗','song-poetry','','[]','奪命稠灘百戰餘，守風端坐恰乘除。',32,'全唐诗/poet.song.137000.json','["奪命稠灘百戰餘，守風端坐恰乘除。", "日長飽飯佳眠覺，閒傍蘆花學釣魚。"]'),
('25850bd9-9ac4-4da1-9c38-ecf20c81af81','佛池口大風復泊','范成大','宋','宋诗','song-poetry','','[]','碧葦無思連天生，青山有情終日橫。',64,'全唐诗/poet.song.137000.json','["碧葦無思連天生，青山有情終日橫。", "風聲洶怒木朝拔，川氣流光珠夜明。", "誰能坐守白頭浪，我欲往騎金背鯨。", "俛仰之間撫四海，可憐步步愁江程。"]'),
('10292d3f-19a7-4dcf-b012-1fa34d68b09e','長風沙','范成大','宋','宋诗','song-poetry','','[]','夕陽明遠帆，高浪兀孤嶼。',48,'全唐诗/poet.song.137000.json','["夕陽明遠帆，高浪兀孤嶼。", "綿綿淮山來，閃閃沙鳥去。", "落木兩三家，炊煙南北渡。", "眉伸擊汰行，夢愕阻風處。"]'),
('cfd059db-4ac2-4189-80ef-fc31b01386a8','九月八日泊池口','范成大','宋','宋诗','song-poetry','','[]','斜景下天末，煙霏酣夕紅。',72,'全唐诗/poet.song.137000.json','["斜景下天末，煙霏酣夕紅。", "餘暉染江色，瀲灧琥珀濃。", "我從落日西，忽到大江東。", "回首舊遊處，曛黄錦城中。", "藥市并樂事，歌樓沸晴空。", "故人十二闌，豈復念此翁。"]'),
('587e3fce-d560-43fe-93fe-69780a6dda6f','池州九日用杜牧之齊山韻','范成大','宋','宋诗','song-poetry','','[]','年年佳節歌式微，秋浦片帆還欲飛。',64,'全唐诗/poet.song.137000.json','["年年佳節歌式微，秋浦片帆還欲飛。", "萬里蜀魂思遠道，九歌楚調送將歸。", "杯中山影分秋色，木末江光借夕暉。", "細撚黄花一枝盡，霏霏金屑滿征衣。"]'),
('7be660a7-9350-4d13-a89f-ac2843c13e50','離池陽十里清溪口復阻風','范成大','宋','宋诗','song-poetry','','[]','恰從秋浦挂籧篨，又泊清溪十里餘。',64,'全唐诗/poet.song.137000.json','["恰從秋浦挂籧篨，又泊清溪十里餘。", "愁水愁風吹帽後，作雲作雨授衣初。", "遠尋草市沽新酒，牢閉篷窗理舊書。", "行路阻艱催老病，騷騷落雪滿晨梳。"]'),
('6a1f4bc8-73b6-4d18-a422-4d1fb89a5742','梅根夾','范成大','宋','宋诗','song-poetry','','[]','辛苦凌波棹，平安入夾船。',48,'全唐诗/poet.song.137000.json','["辛苦凌波棹，平安入夾船。", "日明漁浦網，風側瓦窯煙。", "老圃容挑菜，村巫橫索錢。", "且投人處宿，終夜得佳眠。"]'),
('57db7044-d6a5-48a5-b237-5062c319cfcc','宿長蘆寺方丈','范成大','宋','宋诗','song-poetry','','[]','塔廟新浮水，汀洲舊布金。',48,'全唐诗/poet.song.137000.json','["塔廟新浮水，汀洲舊布金。", "聊憑一葦力，與障萬波侵。", "帆影窺門近，鐘聲出院深。", "夜闌雷破夢，欹枕聽潮音。"]'),
('e32b61e2-af29-4862-a9df-bd07ba36c231','將至吳中親舊多來相迓感懷有作','范成大','宋','宋诗','song-poetry','','[]','望見家山意欲飛，古來燕晉一沾衣。',64,'全唐诗/poet.song.137000.json','["望見家山意欲飛，古來燕晉一沾衣。", "回思客路豈非夢，乍聽鄉音真是歸。", "新事略從年少問，故人差覺坐中稀。", "不須更說桑榆晚，霜後鱸魚也自肥。"]'),
('c371ab2c-49ef-415b-aa7b-bba09086fc9d','淳熙五年四月二日直宿玉堂懷舊二絕句  其一','范成大','宋','宋诗','song-poetry','','[]','桂海冰天老歲華，直廬重上玉皇家。',32,'全唐诗/poet.song.137000.json','["桂海冰天老歲華，直廬重上玉皇家。", "當年曾識青青鬢，惟有東牆一架花。"]'),
('0565b137-e550-4827-bf0e-624b16928862','淳熙五年四月二日直宿玉堂懷舊二絕句  其二','范成大','宋','宋诗','song-poetry','','[]','雪山刁斗不停撾，夜把軍書敢顧家。',32,'全唐诗/poet.song.137000.json','["雪山刁斗不停撾，夜把軍書敢顧家。", "珍重玉堂今夜夢，靜聞宮漏隔宮花。"]'),
('da1e6643-8401-4ec0-bb29-98c7cb498ec7','初歸石湖','范成大','宋','宋诗','song-poetry','','[]','曉霧朝暾紺碧烘，橫塘西岸越城東。',64,'全唐诗/poet.song.137000.json','["曉霧朝暾紺碧烘，橫塘西岸越城東。", "行人半出稻花上，宿鷺孤明菱葉中。", "信脚自能知舊路，驚心時復認鄰翁。", "當時手種斜橋柳，無限鳴蜩翠掃空。"]'),
('f0369958-5c76-405f-8932-4a8e67201fbc','寄蜀州楊道人','范成大','宋','宋诗','song-poetry','','[]','老來萬事總蕭然，猶憶西州暑雪邊。',32,'全唐诗/poet.song.137000.json','["老來萬事總蕭然，猶憶西州暑雪邊。", "爲報岷峨山水道，如今真箇得歸田。"]'),
('6efc3d4c-e3e8-4bc8-8948-da8f2e62b763','送同年萬元亨知階州  其一','范成大','宋','宋诗','song-poetry','','[]','老我曾頒萬里春，憐君飛棹也浮秦。',32,'全唐诗/poet.song.137000.json','["老我曾頒萬里春，憐君飛棹也浮秦。", "當年千佛名經裏，又見西遊第二人。"]'),
('abd6f14a-59f6-4da1-abe2-8484cb074f61','送同年萬元亨知階州  其二','范成大','宋','宋诗','song-poetry','','[]','路入南山舊漢畿，油油清渭照牙旗。',32,'全唐诗/poet.song.137000.json','["路入南山舊漢畿，油油清渭照牙旗。", "古來百戰功名地，正是雞鳴起舞時。"]'),
('93c1cec4-0510-4294-8163-6b278dce6d35','送同年萬元亨知階州  其三','范成大','宋','宋诗','song-poetry','','[]','十年關隴困科輸，聖德如天盡掃除。',32,'全唐诗/poet.song.137000.json','["十年關隴困科輸，聖德如天盡掃除。", "臨遣中和二千石，好乘春日下寬書。"]'),
('c93b6c0c-30d8-4b76-b880-83a814af47f9','次韻蜀客西歸者來過石湖并寄成都舊僚','范成大','宋','宋诗','song-poetry','','[]','走徧塵埃倦鳥還，故鄉元在水雲間。',64,'全唐诗/poet.song.137000.json','["走徧塵埃倦鳥還，故鄉元在水雲間。", "黄粱飯裏夢魂醒，青篛笠前身世閒。", "鷗鷺飛來俱玉立，松篁歲晚各蒼顔。", "岷峨交舊如相問，鐵鎖無扃任客攀。"]'),
('b98c33bf-1443-408c-801a-745bfadf29e2','十一月大霧中自胥口渡太湖','范成大','宋','宋诗','song-poetry','','["\u592a\u6e56"]','白霧漫空白浪深，舟如竹葉信浮沉。',32,'全唐诗/poet.song.137000.json','["白霧漫空白浪深，舟如竹葉信浮沉。", "科頭晏起吾何敢，自有山川印此心。"]'),
('beaa7e08-0b9a-455f-89c2-42573a4ff931','靈祐觀','范成大','宋','宋诗','song-poetry','','[]','暘谷西門鎖洞宮，古苔斑駁檜蒙茸。',32,'全唐诗/poet.song.137000.json','["暘谷西門鎖洞宮，古苔斑駁檜蒙茸。", "百廊三殿惟眢井，萬壑千巖有瘦筇。"]'),
('54d2835c-b097-4adf-83a7-748190ab5b71','林屋洞','范成大','宋','宋诗','song-poetry','','[]','擊水摶風浪雪翻，煙銷日出見仙村。',64,'全唐诗/poet.song.137000.json','["擊水摶風浪雪翻，煙銷日出見仙村。", "舊知浮玉北堂路，今到幽墟三洞門。", "石燕翾飛遮炬火，金龍深阻護嵌根。", "寶鐘靈鼓何須叩，庭柱宵晨已默存。"]'),
('4b766b92-7234-406d-b8e5-730a40aac1ca','包山寺','范成大','宋','宋诗','song-poetry','','[]','仙塢遜半坐，精廬遷古幢。',72,'全唐诗/poet.song.137000.json','["仙塢遜半坐，精廬遷古幢。", "槁衲昔開山，至今坐道場。", "熾然說慈忍，禪海薰戒香。", "穉竹暗寒碧，飛松盤老蒼。", "船鼓入宴坐，紅塵隔滄浪。", "藤杖懶歸去，共倚薄團牀。"]'),
('e7452e83-6314-48be-937b-31ce84de67a2','毛公壇福地','范成大','宋','宋诗','song-poetry','','[]','松蘿滴翠白晝陰，七十二峰中最深。',96,'全唐诗/poet.song.137000.json','["松蘿滴翠白晝陰，七十二峰中最深。", "綠毛仙翁已仙去，惟有石壇留竹塢。", "竹陰掃壇石槎牙，漢時風雨生蘚花。", "山中笙鶴尚遺響，湖外人煙驚歲華。", "道人眸子照秋色，邀我分山築丹室。", "驅丁役甲莫兒嬉，渴飲隠泉饑餌朮。"]'),
('b1fc1f40-cd6b-46f0-a110-fca9047aa725','上方寺','范成大','宋','宋诗','song-poetry','','[]','檥棹古銷夏，搘筇新上方。',48,'全唐诗/poet.song.137000.json','["檥棹古銷夏，搘筇新上方。", "珠灣鎖員折，冰鏡沉空光。", "楓纈醉晴日，橘黄明蚤霜。", "閒門松竹徑，隨處有清凉。"]'),
('426d08a9-cc63-4c30-9741-a7e20944ba58','銷夏灣','范成大','宋','宋诗','song-poetry','','[]','蓼磯楓渚故離宮，一曲清漣九里宮。',32,'全唐诗/poet.song.137000.json','["蓼磯楓渚故離宮，一曲清漣九里宮。", "縱有暑光無著處，青山環水水浮空。"]'),
('74c130f8-93ed-4114-93e7-72bb452809f9','橘園','范成大','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','橘中有佳人，招客果下遊。',96,'全唐诗/poet.song.137000.json','["橘中有佳人，招客果下遊。", "胡牀到何許，坐我金碧洲。", "沉沉剪綵山，垂垂萬星毬。", "奇采日中麗，生香風外浮。", "折贈黄團雙，珍逾桃李投。", "拆開甘露囊，快吸冰泉甌。", "熱腦散五濁，豈止沉疴瘳。", "未知商山樂，能如洞庭不。"]'),
('a482d179-7e20-4160-902a-efcd939d4880','華山寺','范成大','宋','宋诗','song-poetry','','[]','五湖西岸孤絕處，旃檀大士來同住。',144,'全唐诗/poet.song.137000.json','["五湖西岸孤絕處，旃檀大士來同住。", "性空真水徧清凉，隨緣出現無方所。", "蒙泉新潔鑑泉明，瀹茗羹藜甘似乳。", "何須苦問蓮開未，桂子菖花了今古。", "三翁綵筆照青霞，從此他山都不數。", "我今閒行作閒客，暫借雲窗解包具。", "魂清骨冷不成眠，徹曉跏趺聽粥鼓。", "脚力有餘西塢盡，明日灣頭更鳴櫓。", "却上東山喚德雲，別峰應在銀濤許。"]'),
('2fe2959d-4689-4f0b-905c-a8124ec32172','縹緲峰','范成大','宋','宋诗','song-poetry','','["\u592a\u6e56"]','滿載清閒一棹孤，長風相送入仙都。',32,'全唐诗/poet.song.137000.json','["滿載清閒一棹孤，長風相送入仙都。", "莫愁懷抱無消豁，縹緲峰頭望太湖。"]'),
('06846634-c322-4980-b005-6d859c863141','鎮下放船過東山二首  其一','范成大','宋','宋诗','song-poetry','','[]','打頭風急鼻雷鼾，醉夢閒心鐵石頑。',32,'全唐诗/poet.song.137000.json','["打頭風急鼻雷鼾，醉夢閒心鐵石頑。", "惟有愛山貪未厭，西山纔了又東山。"]'),
('49debdb0-0dba-44cd-8ce7-5e94b5f619f8','鎮下放船過東山二首  其二','范成大','宋','宋诗','song-poetry','','[]','老禪竿木各逢場，詩客端來共葦航。',32,'全唐诗/poet.song.137000.json','["老禪竿木各逢場，詩客端來共葦航。", "一任顛風聒高浪，滿船歡笑和詩忙。"]'),
('95a28644-f5d4-4f84-84b9-9376c3bea256','翠峰寺','范成大','宋','宋诗','song-poetry','','[]','來從第九天，橘社繫歸船。',48,'全唐诗/poet.song.137000.json','["來從第九天，橘社繫歸船。", "借問翠峰路，誰參雪竇禪。", "應真庭下木，說法井中泉。", "公案新翻出，諸方一任傳。"]'),
('113d679a-cdbd-476a-929b-b06604139aab','社山放船','范成大','宋','宋诗','song-poetry','','[]','社下鐘聲送客船，凌波撾鼓轉滄灣。',64,'全唐诗/poet.song.137000.json','["社下鐘聲送客船，凌波撾鼓轉滄灣。", "橫煙裊處雞豚社，落日濃邊橘柚山。", "八表茫茫孤鳥去，萬生擾擾一舟閒。", "湖心行路平如鏡，陸地風波却險艱。"]'),
('fc96e755-407d-430d-89da-c7c3d75c2065','東山渡湖','范成大','宋','宋诗','song-poetry','','[]','渡船帆飽如張弓，倏忽世界寒浺瀜。',164,'全唐诗/poet.song.137000.json','["渡船帆飽如張弓，倏忽世界寒浺瀜。", "堪輿無垠日夜汎，浩浩元氣蓬蓬風。", "湖光日色不可辨，但見水精火齊合集成虛空。", "波臣川后敬愛客，約束祕怪驅魚龍。", "大千總作大圓鏡，光中飛度迷西東。", "蒼茫一身無四壁，八方上下惟孤篷。", "毛仙出迎笑相問，何乃自苦荒寒中。", "吾生蓋頭乏片瓦，到處漂搖稱寓公。", "猶嫌塵土礙人眼，茲遊勝絕餘難同。", "九衢車馬恍昨夢，付與一笑隨飛鴻。"]'),
('87f4f29b-f2a4-4127-b3c3-dba502e9d1af','與游子明同過石湖','范成大','宋','宋诗','song-poetry','','[]','契闊相逢一笑歡，當年森桂共驂鸞。',64,'全唐诗/poet.song.137000.json','["契闊相逢一笑歡，當年森桂共驂鸞。", "試談舊事醒村酒，仍趁新晴暖客鞍。", "梅粉都皴啼宿雨，柳黄不展噤春寒。", "從今鼎鼎多幽事，仍喜蛙聲不在官。"]'),
('c4568853-f55a-4dec-9e8a-010d1d2eb869','次韻同年楊廷秀使君寄題石湖  其一','范成大','宋','宋诗','song-poetry','','[]','儀凰當瑞九韶成，何事栖鸞滯碧城。',64,'全唐诗/poet.song.137000.json','["儀凰當瑞九韶成，何事栖鸞滯碧城。", "公退蕭然真吏隠，文名藉甚更詩聲。", "句從月脇天心得，筆與冰甌雪椀清。", "書到石湖春亦到，平堤梅影縠紋生。"]'),
('67b8e4a3-fc66-4235-bda8-74f497d934eb','次韻同年楊廷秀使君寄題石湖  其二','范成大','宋','宋诗','song-poetry','','[]','半世輕隨出岫雲，如今歸作卧雲人。',64,'全唐诗/poet.song.137000.json','["半世輕隨出岫雲，如今歸作卧雲人。", "小山有賦招遊子，大塊無私佚老身。", "禪版夢中千嶂曉，鬢絲風裏萬花春。", "新年社甕鵝黄滿，賸醉田頭紫領巾。"]'),
('80165d17-fd26-4df5-8e5b-d2d22bf66af7','自閶門騎馬入越城  其一','范成大','宋','宋诗','song-poetry','','[]','日影穿雲亦未濃，夜來疎雨洗清空。',32,'全唐诗/poet.song.137000.json','["日影穿雲亦未濃，夜來疎雨洗清空。", "村前村後東風滿，略數桃花一萬重。"]'),
('6d0b53a5-95ca-4fce-a7af-f5cadf25d96c','自閶門騎馬入越城  其二','范成大','宋','宋诗','song-poetry','','[]','斷橋隤岸數家村，雨少晴多減漲痕。',32,'全唐诗/poet.song.137000.json','["斷橋隤岸數家村，雨少晴多減漲痕。", "雪白鵝兒綠楊柳，日高猶自掩柴門。"]'),
('9261cc78-a0eb-46ec-bc53-58e451ecdca9','姚夫人輓歌詞','范成大','宋','宋诗','song-poetry','','[]','衿帨虞鰥後，詩書孟母鄰。',48,'全唐诗/poet.song.137000.json','["衿帨虞鰥後，詩書孟母鄰。", "高懷琴意靜，晚福詔恩新。", "自古悲風木，于今詠澗蘋。", "松銘無溢美，百世考堅珉。"]'),
('00a46921-9fc1-4298-9337-300ee1a3f2f2','北山草堂千巖觀新成徐叔智運使吟古風相賀次韻謝之','范成大','宋','宋诗','song-poetry','','[]','北山松竹堪怡顔，千巖觀前多好山。',96,'全唐诗/poet.song.137000.json','["北山松竹堪怡顔，千巖觀前多好山。", "誰云都無卓錐地，亦尚有此茅三間。", "洞門無鑰常不關，小徑百曲蒼龍盤。", "衆芳迷人不知處，片雲與我俱忘還。", "花前一杯重鼎呂，明日戽田并灌圃。", "種苗種豆從此忙，昨夜驚雷送膏雨。"]'),
('90301905-5235-457e-bd1a-78c07994d8f3','贈舉書記歸雲丘  其一','范成大','宋','宋诗','song-poetry','','[]','一枕清風四十霜，孤生無處話淒凉。',32,'全唐诗/poet.song.137000.json','["一枕清風四十霜，孤生無處話淒凉。", "相看只有龐眉客，還在雲丘舊草堂。"]'),
('9d7d0e63-53b0-47e0-a439-dec61ddc9f17','贈舉書記歸雲丘  其二','范成大','宋','宋诗','song-poetry','','[]','四股澗松雷斧碎，十圍巖桂燒痕枯。',32,'全唐诗/poet.song.137000.json','["四股澗松雷斧碎，十圍巖桂燒痕枯。", "不知階下跳珠處，舊竹春來有筍無。"]'),
('0d46a190-b440-495b-98d1-0733beecff4f','贈舉書記歸雲丘  其三','范成大','宋','宋诗','song-poetry','','[]','青山面目想依依，水石風林入夢思。',32,'全唐诗/poet.song.137000.json','["青山面目想依依，水石風林入夢思。", "白髮蒼顔心故在，只如當日看山時。"]'),
('d7b4166a-5b7b-444a-9fba-1ace018a62b8','題查山林氏菴','范成大','宋','宋诗','song-poetry','','["\u8861\u5c71"]','戶庭清深宅翠微，雪如佳壁喚題詩。',64,'全唐诗/poet.song.137000.json','["戶庭清深宅翠微，雪如佳壁喚題詩。", "煙梢矗矗青圍屋，露葉鮮鮮綠滿籬。", "宿雨一春纔汎鴨，新蕪幾日已藏碑。", "山僧見客如枯木，疑是懶殘南嶽師。"]'),
('ef6d9aaf-3c68-4462-a7fe-7345bf9795f7','木瀆道中風雨震雷大作','范成大','宋','宋诗','song-poetry','','[]','惡風奔雲何壯哉，溪水欲立山欲摧。',64,'全唐诗/poet.song.137000.json','["惡風奔雲何壯哉，溪水欲立山欲摧。", "石岸迸裂纜邊樹，胡牀動搖船底雷。", "靈巖塔後雨脚挂，胥口廟前浪花來。", "篷漏衣沾不足惜，酒瓶傾倒愁空罍。"]'),
('13e74834-a190-48cf-902a-f0ee0afd91a8','光福塘上','范成大','宋','宋诗','song-poetry','','[]','指點炊煙隔莽蒼，午餐應可寄前莊。',64,'全唐诗/poet.song.137000.json','["指點炊煙隔莽蒼，午餐應可寄前莊。", "雞聲人語小家樂，木葉草花深巷香。", "春去已空衣尚絮，雨來何晚稻初芒。", "祗今農事村村急，第一先陂貯水塘。"]'),
('37b54944-57a5-4a31-8695-26d189c92d8a','與至先兄遊諸園看牡丹三日行徧  其一','范成大','宋','宋诗','song-poetry','','[]','拄杖無邊處處過，粉圍紅繞奈春何。',32,'全唐诗/poet.song.137000.json','["拄杖無邊處處過，粉圍紅繞奈春何。", "閶門昨日看不足，今日婁門花更多。"]'),
('984e53df-875f-440a-b2a3-d2ee39d0673f','與至先兄遊諸園看牡丹三日行徧  其二','范成大','宋','宋诗','song-poetry','','[]','蜂蝶蕭騷草露漫，小家籬落閉荒寒。',32,'全唐诗/poet.song.137000.json','["蜂蝶蕭騷草露漫，小家籬落閉荒寒。", "欲知國色天香句，須是倚闌燒燭看。"]'),
('2825c4c2-27b4-4b3c-a355-818042cb30a8','次韻同年楊使君回自毘陵同泛石湖舟中見贈  其一','范成大','宋','宋诗','song-poetry','','[]','客舫中流下，人家夾岸看。',48,'全唐诗/poet.song.137000.json','["客舫中流下，人家夾岸看。", "洛花堆錦煖，吳藕鏤冰寒。", "莫厭清歡暫，須知後會難。", "小詩煩本事，任禿綵毫端。"]'),
('ceff5240-869d-4564-b216-624b50e51171','次韻同年楊使君回自毘陵同泛石湖舟中見贈  其二','范成大','宋','宋诗','song-poetry','','[]','曲誤不須顧，客狂當好看。',48,'全唐诗/poet.song.137000.json','["曲誤不須顧，客狂當好看。", "日斜雙槳急，風駛夾衣寒。", "賸說歸田樂，休歌行路難。", "石湖三萬頃，何處覓憂端。"]'),
('3b7604b0-73c0-4f32-87ff-66dcdf61a508','次韻同年楊使君回自毘陵同泛石湖舟中見贈  其三','范成大','宋','宋诗','song-poetry','','[]','北渚乘風渡，西山带霧看。',48,'全唐诗/poet.song.137000.json','["北渚乘風渡，西山带霧看。", "袖單嫌翠薄，杯淺怯金寒。", "宿雨收全易，春酲解却難。", "且留行色住，重肯過蘇端。"]'),
('2f373e05-73d6-45b9-a865-ae67260199ca','頃乾道辛卯歲三月望夜與周子充內翰泛舟石湖松江之間夜艾歸宿農圃距今淳熙己亥九年矣余先得歸田復以是夕泛湖有懷昔遊賦詩紀事','范成大','宋','宋诗','song-poetry','','[]','石湖花月浮春空，憶共仙人同短篷。',128,'全唐诗/poet.song.137000.json','["石湖花月浮春空，憶共仙人同短篷。", "三更半醉吹笛去，櫂入濕銀天鏡中。", "鶴鳴喚歸斗未沒，却步扶疎花底月。", "不知行到碧桃邊，但見天風吹積雪。", "月圓月缺今幾回，依舊滿湖金碧堆。", "仙人還上玉堂宿，合有片時清夢來。", "一笑流光飛電抹，嫦娥相對兩愁絕。", "桂枝應亦老無花，蟾兔不須疑鶴髮。"]'),
('bd88eaed-44f3-4753-885f-dc81bfb18f99','嬾牀午坐','范成大','宋','宋诗','song-poetry','','[]','晴霄垂北窗，卧我翠幄中。',72,'全唐诗/poet.song.137000.json','["晴霄垂北窗，卧我翠幄中。", "不知幾斧鑿，成此太虛空。", "前雲稍過盡，後雲來無窮。", "鳥雀有底忙，激彈過牆東。", "不如雙飛蝶，款款弄微風。", "我亦困思生，拋書眼蒙茸。"]'),
('28dae8a9-bb9a-4596-bda0-ea340e9f48d7','秋前三日大雨','范成大','宋','宋诗','song-poetry','','[]','暑殘堪喜亦堪憎，恰似沙場喋血兵。',32,'全唐诗/poet.song.137000.json','["暑殘堪喜亦堪憎，恰似沙場喋血兵。", "縱有背城餘燼在，能禁幾度瀉檐聲。"]'),
('889968be-3872-40cb-8a6c-ad77c5dcaf87','秋前風雨頓凉','范成大','宋','宋诗','song-poetry','','[]','秋期如約不須催，雨脚風聲兩快哉。',64,'全唐诗/poet.song.137000.json','["秋期如約不須催，雨脚風聲兩快哉。", "但得暑光如寇退，不辭老景似潮來。", "酒杯觸撥詩情動，書卷招邀病眼開。", "明日更凉吾已卜，暮雲渾作亂峰堆。"]'),
('181a959f-9d49-418c-b4b7-fdc618e2199f','立秋後二日泛舟越來溪三絕  其一','范成大','宋','宋诗','song-poetry','','[]','西風初入小溪帆，旋織波紋縐淺藍。',32,'全唐诗/poet.song.137000.json','["西風初入小溪帆，旋織波紋縐淺藍。", "行入閙荷無水面，紅蓮沉醉白蓮酣。"]'),
('822dfe19-10ac-431d-bfcc-b9755c9a1a59','立秋後二日泛舟越來溪三絕  其二','范成大','宋','宋诗','song-poetry','','[]','一川新漲熨秋光，挂起篷窗受晚凉。',32,'全唐诗/poet.song.137000.json','["一川新漲熨秋光，挂起篷窗受晚凉。", "楊柳無窮蟬不斷，好風將夢過橫塘。"]'),
('b5cdf2cb-76e3-4aaa-8589-b82987c62747','立秋後二日泛舟越來溪三絕  其三','范成大','宋','宋诗','song-poetry','','[]','飯後茶前困思生，水寬風穩信篙撐。',32,'全唐诗/poet.song.137000.json','["飯後茶前困思生，水寬風穩信篙撐。", "不知浪打船頭響，聽作凌波解佩聲。"]'),
('4d871fd0-be0a-4ebd-9c24-5840cf716bd9','采菱戶','范成大','宋','宋诗','song-poetry','','[]','采菱辛苦似天刑，刺手朱殷鬼質青。',32,'全唐诗/poet.song.137000.json','["采菱辛苦似天刑，刺手朱殷鬼質青。", "休問揚荷涉江曲，只堪聊誦楚詞聽。"]'),
('61e669a8-5e81-4035-8bc9-1cf57d92581e','曉起聞雨','范成大','宋','宋诗','song-poetry','','[]','老來稍喜睡魔清，兀坐枯株聽五更。',64,'全唐诗/poet.song.137000.json','["老來稍喜睡魔清，兀坐枯株聽五更。", "蕭索輪囷憐燭燼，飛揚跋扈厭蚊聲。", "登高事了從教雨，刈熟人忙却要晴。", "莫道西成便無慮，大須濃日曬香秔。"]'),
('0e68ff34-2ca8-44d0-9859-76cd3469fee9','說虎軒夜坐','范成大','宋','宋诗','song-poetry','','[]','白雲深處卧癡頑，挂起東窗水月寬。',64,'全唐诗/poet.song.137000.json','["白雲深處卧癡頑，挂起東窗水月寬。", "但得好詩生眼底，何須寶剎現毫端。", "一身莫作官身想，萬境都如夢境看。", "蟹舍鄰翁能日醉，呼來分與一蒲團。"]'),
('3696f608-5148-4bc3-871f-d7707a74bf7b','偶書','范成大','宋','宋诗','song-poetry','','[]','太行巫峽費車舟，休向滄溟認一漚。',64,'全唐诗/poet.song.137000.json','["太行巫峽費車舟，休向滄溟認一漚。", "日下冰山難把玩，雨中土偶任漂流。", "元無刻木牽絲技，但合收繩卷索休。", "惟有酒缸并飯甑，却須秔秫十分收。"]'),
('1fa40481-cc9e-4800-b13e-ab08d78e3a43','睡覺','范成大','宋','宋诗','song-poetry','','[]','漏箭聲中斷角哀，界窗猶有月徘徊。',64,'全唐诗/poet.song.137000.json','["漏箭聲中斷角哀，界窗猶有月徘徊。", "心兵休爲一蚊動，句法却從孤鴈來。", "潄罷玉池甘似醴，夢餘金鼓辯如雷。", "夜長展轉添許事，推枕蕭然一笑咍。"]'),
('5262573b-524e-4853-888b-473fe96b8d22','閶門行送胡子遠著作守漢川','范成大','宋','宋诗','song-poetry','','[]','前年送君朝明光，今年送君還故鄉。',96,'全唐诗/poet.song.137000.json','["前年送君朝明光，今年送君還故鄉。", "錦官樓上一樽酒，萬里閶門折楊柳。", "吳波沄沄蜀山蒼，人生行路如許長。", "相逢相送鬢如雪，人生能禁幾離別。", "房湖風月開春臺，石湖水雲歸去來。", "西棹東帆君未了，相逢還向閶門道。"]'),
('1320d4d0-99f4-4a20-97fb-60fc899bb626','嘲蚊四十韻','范成大','宋','宋诗','song-poetry','','[]','暑魃方肆行，羽孽亦厲習。',288,'全唐诗/poet.song.137000.json','["暑魃方肆行，羽孽亦厲習。", "肖翹極么魔，坱圠累闢翕。", "濕生同糞蝎，腐化類宵熠。", "初來閙郭郛，少進亙原隰。", "嚶如蠅聲薨，聚若螽羽揖。", "俄爲殷雷鬨，遂作密霰集。", "口銜鋼針鋒，力洞衲衣襲。", "啾聲先計議，著肉便噓吸。", "立豹猶未定，卓錐已深入。", "血隨姑嘬升，勢甚轆轤汲。", "沉酣尻益高，飽滿腹漸急。", "晶晶紫蟹眼，滴滴紅飯粒。", "拂掠倦體煩，爬搔瘁肌澀。", "捄東不虞西，擒一已竄十。", "新瘢蓓蕾漲，宿暈斑斕浥。", "竟夜眠展轉，連牀歎於悒。", "云何人戚欣，乃係汝張歙。", "驅以葵扇風，熏以艾煙濕。", "檠長鎮藏遮，帳隙亟補葺。", "火攻憚穢臭，手拍嫌腥汁。", "伏翼佐掃除，網蛛助收拾。", "薄暮洶交攻，大明訌未戢。", "牛革厚逾氈，鱟介銛勝鈒。", "遭汝若欲困，嗟人何以給。"]'),
('51ae240d-070f-49f3-8b70-d3b911eeef5c','閶門戲調行客','范成大','宋','宋诗','song-poetry','','[]','日夜飛帆與跨鞍，閶門川陸路漫漫。',64,'全唐诗/poet.song.137000.json','["日夜飛帆與跨鞍，閶門川陸路漫漫。", "人生自苦身餘幾，天色無情歲又寒。", "萬事惟堪六如觀，一杯莫信四并難。", "重陽雖過黄花少，尚有遲開玉雪團。"]'),
('f3a6ac57-c4e3-47e5-b176-11e1cd6c3e07','九月二十八日湖上檢校籬落','范成大','宋','宋诗','song-poetry','','[]','村北村南打稻聲，荒園屐齒亦嬉晴。',64,'全唐诗/poet.song.137000.json','["村北村南打稻聲，荒園屐齒亦嬉晴。", "菊邊更覺朝陽好，松下偏聞晚吹清。", "一歲無非吾樂事，千金不博此閒行。", "周遭踏徧芙蓉岸，足痹腰頑栩栩輕。"]'),
('0a593bed-c40f-457c-bd7d-8520f8c3cd02','晚步吳故城下','范成大','宋','宋诗','song-poetry','','[]','意行殊不計榛菅，風袖飄然勝羽翰。',64,'全唐诗/poet.song.137000.json','["意行殊不計榛菅，風袖飄然勝羽翰。", "拄杖前頭雙雉起，浮圖絕頂一併盤。", "醉紅匝地斜曛暖，熨練涵空漲水寒。", "却向東臯望煙火，缺蟾先映槲林丹。"]'),
('d66a9c8c-4bec-4d47-94ee-233a5b89046d','上沙田舍','范成大','宋','宋诗','song-poetry','','[]','更無雲物起微陰，壠畝人家各好音。',64,'全唐诗/poet.song.137000.json','["更無雲物起微陰，壠畝人家各好音。", "歲晚陽和歸稻把，夜來霜力到楓林。", "兒童笑裏豐年面，烏鳥聲中落日心。", "釀秫炊秔都入手，賸拚腰脚辦登臨。"]'),
('96e2bffa-a5c8-4c38-8274-8f8f3260e8e1','與現壽二長老遊壽泉因話去年林屋之遊題贈  其一','范成大','宋','宋诗','song-poetry','','[]','何年錫杖劚清甘，天遣深源壽此菴。',32,'全唐诗/poet.song.137000.json','["何年錫杖劚清甘，天遣深源壽此菴。", "金靨萬枝浮倒影，爲君題作菊花潭。"]'),
('be01c6cc-d540-4ebb-a3e7-31a566da2f8c','與現壽二長老遊壽泉因話去年林屋之遊題贈  其二','范成大','宋','宋诗','song-poetry','','[]','松風放浪入雲關，二衲相從一士閒。',32,'全唐诗/poet.song.137000.json','["松風放浪入雲關，二衲相從一士閒。", "人與瘦筇俱老健，去年今日在包山。"]'),
('8c5f514d-c765-4291-89dc-982cfe4a2926','渡太湖','范成大','宋','宋诗','song-poetry','','["\u592a\u6e56"]','囊風閣雨半晴陰，慘淡誰知造化心。',64,'全唐诗/poet.song.137000.json','["囊風閣雨半晴陰，慘淡誰知造化心。", "委命浮沉惟一葉，計身輕重亦千金。", "紅塵猶道不勝險，白浪莫嗔如許深。", "晚得薌山堪寄纜，卧聽鼉吼與龍吟。"]'),
('c86b5925-0a8a-4acd-959e-9b31e1538ff6','再渡胥口','范成大','宋','宋诗','song-poetry','','[]','古來此地快蓬心，天繞明湖日照臨。',64,'全唐诗/poet.song.137000.json','["古來此地快蓬心，天繞明湖日照臨。", "一鴈雲平時隠現，兩山波動對浮沉。", "衰髯都共荻花老，醉面不如楓葉深。", "罾戶釣徒來問訊，去年盟在肯重尋。"]'),
('b9586a4a-1dcd-429b-9c9d-c2192947cc12','跨馬過練墟喜晴','范成大','宋','宋诗','song-poetry','','[]','稻穗初乾怕雨時，晚來蒸煖欲霏微。',32,'全唐诗/poet.song.137000.json','["稻穗初乾怕雨時，晚來蒸煖欲霏微。", "西風若肯吹雲盡，不惜飄飄側帽歸。"]'),
('a833f73c-4461-4fb1-865b-dfe402f03f6d','晚歸石湖','范成大','宋','宋诗','song-poetry','','[]','何須駟馬衒鄉關，只作歸農老圃看。',64,'全唐诗/poet.song.137000.json','["何須駟馬衒鄉關，只作歸農老圃看。", "夢裏曾腰綪結佩，年來新著惰遊冠。", "和煙種竹聊醫俗，带月聞蛙不在官。", "久矣此心恬不動，如今併與此身安。"]'),
('380d4cbd-e154-48d7-869d-1170fc78286c','北山堂開爐夜坐','范成大','宋','宋诗','song-poetry','','[]','困眠醒坐一龕多，竹洞無關斷客過。',64,'全唐诗/poet.song.137000.json','["困眠醒坐一龕多，竹洞無關斷客過。", "貪向爐中煨榾柮，懶從掌上看菴摩。", "閒無雜念惟詩在，老不甘心奈鏡何。", "八萬四千安樂法，元無祕密可伽陀。"]'),
('2a010f99-4da2-4fbf-9fe9-ab773f3bb60f','入城','范成大','宋','宋诗','song-poetry','','[]','十里清風一餉間，片帆真欲解人顔。',32,'全唐诗/poet.song.137000.json','["十里清風一餉間，片帆真欲解人顔。", "林家莊近聞鵝鴨，船到閶門儘未關。"]');
